// pages/ConfirmationsPage.tsx
import { useState, useEffect, useRef } from "react";
import { Confirmation, ConfirmationType, SteamAccountInfo } from "../types";
import { accountApi } from "@/services/api";
import { useAccountLogin } from "@/hooks/use-account-login";
import { AuthenticationRequired } from "@/components/AuthenticationRequired";
import { ConfirmationsUnavailable } from "@/components/ConfirmationsUnavailable";
import { Modal } from "@/components/Modal";
import { AlertTriangle, Loader2 } from "lucide-react";

interface ConfirmationsPageProps {
  account: SteamAccountInfo | null;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
}

type SettingType = "trade" | "market" | "system" | "acceptGiftTrade";

const getConfirmationTypeName = (type: number): string => {
  switch (type) {
    case ConfirmationType.Test:
      return "Test Confirmation";
    case ConfirmationType.Trade:
      return "Trade Offer";
    case ConfirmationType.MarketSell:
      return "Market Sell Listing";
    case ConfirmationType.FeatureOptOut:
      return "Feature Opt-Out";
    case ConfirmationType.PhoneNumberChange:
      return "Phone Number Change";
    case ConfirmationType.AccountRecovery:
      return "Account Recovery";
    case ConfirmationType.ApiKeyCreation:
      return "API Key Creation";
    case ConfirmationType.JoinSteamFamily:
      return "Join Steam Family";
    case ConfirmationType.MarketBuy:
      return "Market Buy Confirmation";
    default:
      return "Confirmation";
  }
};

const formatDate = (isoString: string) => {
  const date = new Date(isoString);
  return date.toLocaleString();
};

export function ConfirmationsPage({
  account,
  onUpdateAccount,
}: ConfirmationsPageProps) {
  const [loading, setLoading] = useState<SettingType | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [confirmationsList, setConfirmationsList] = useState<Confirmation[]>(
    [],
  );
  const [loadingList, setLoadingList] = useState(false);
  const [processingIds, setProcessingIds] = useState<Set<string>>(new Set());
  const [timeUntilRefresh, setTimeUntilRefresh] = useState(5);
  const intervalRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const countdownRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentAccountNameRef = useRef<string | null>(null);
  const [modalState, setModalState] = useState<{
    type: "accept" | "decline" | null;
    open: boolean;
  }>({ type: null, open: false });
  const [bulkLoading, setBulkLoading] = useState<{
    accept: boolean;
    decline: boolean;
  }>({ accept: false, decline: false });
  const { loggingIn, handleLogin, loginError } = useAccountLogin({
    account,
    onUpdateAccount,
  });

  const fetchConfirmations = async () => {
    if (!account) return;
    if (account.sharedSecret == "") return;
    if (!account.cookies) return;

    const accountName = account.accountName;
    currentAccountNameRef.current = accountName;

    setLoadingList(true);
    setError(null);
    const result = await accountApi.getConfirmations(accountName);

    if (currentAccountNameRef.current !== accountName) {
      console.log("Account changed during fetch, ignoring results");
      return;
    }

    if (result.data) {
      setConfirmationsList(result.data);
    } else {
      setError(result.error || "Failed to load confirmations");
    }
    setLoadingList(false);
    setTimeUntilRefresh(5);
  };

  // Запуск обратного отсчета
  useEffect(() => {
    if (!account?.cookies) return;

    countdownRef.current = setInterval(() => {
      setTimeUntilRefresh((prev) => {
        if (prev <= 1) {
          return 5;
        }
        return prev - 1;
      });
    }, 1000);

    return () => {
      if (countdownRef.current) {
        clearInterval(countdownRef.current);
        countdownRef.current = null;
      }
    };
  }, [account?.cookies]);

  useEffect(() => {
    if (!account) return;

    setConfirmationsList([]);
    setError(null);
    setProcessingIds(new Set());
    currentAccountNameRef.current = account.accountName;

    if (account.cookies) {
      fetchConfirmations();
    }

    if (account.cookies) {
      intervalRef.current = setInterval(() => {
        fetchConfirmations();
      }, 5000);
    }

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [account]);

  const handleAcceptAll = async () => {
    if (!account) return;
    setBulkLoading((prev) => ({ ...prev, accept: true }));
    const result = await accountApi.acceptAllConfirmations(account.accountName);
    if (result.success) {
      setConfirmationsList([]);
      await fetchConfirmations();
    } else {
      setError(result.error || "Failed to accept all confirmations");
    }
    setBulkLoading((prev) => ({ ...prev, accept: false }));
    setModalState({ type: null, open: false });
  };

  const handleDeclineAll = async () => {
    if (!account) return;
    setBulkLoading((prev) => ({ ...prev, decline: true }));
    const result = await accountApi.declineAllConfirmations(
      account.accountName,
    );
    if (result.success) {
      setConfirmationsList([]);
      await fetchConfirmations();
    } else {
      setError(result.error || "Failed to decline all confirmations");
    }
    setBulkLoading((prev) => ({ ...prev, decline: false }));
    setModalState({ type: null, open: false });
  };

  const openConfirmModal = (type: "accept" | "decline") => {
    setModalState({ type, open: true });
  };

  const renderHeaderButtons = () => (
    <div className="flex gap-3">
      <button
        onClick={() => openConfirmModal("accept")}
        disabled={
          bulkLoading.accept ||
          bulkLoading.decline ||
          confirmationsList.length === 0
        }
        className="px-4 py-2 bg-green-600 hover:bg-green-700 rounded-md text-sm font-medium transition-colors disabled:opacity-50 cursor-pointer flex items-center gap-2"
      >
        {bulkLoading.accept ? (
          <>
            <Loader2 className="w-4 h-4 animate-spin" />
            <span>Processing...</span>
          </>
        ) : (
          "Accept All"
        )}
      </button>
      <button
        onClick={() => openConfirmModal("decline")}
        disabled={
          bulkLoading.accept ||
          bulkLoading.decline ||
          confirmationsList.length === 0
        }
        className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-md text-sm font-medium transition-colors disabled:opacity-50 cursor-pointer flex items-center gap-2"
      >
        {bulkLoading.decline ? (
          <>
            <Loader2 className="w-4 h-4 animate-spin" />
            <span>Processing...</span>
          </>
        ) : (
          "Decline All"
        )}
      </button>
    </div>
  );

  const handleAccept = async (confirmationId: string) => {
    if (!account || processingIds.has(confirmationId)) return;
    if (!account.cookies) {
      setError("Account is not logged in. Please login first.");
      return;
    }

    setProcessingIds((prev) => new Set(prev).add(confirmationId));
    const result = await accountApi.acceptConfirmation(
      account.accountName,
      confirmationId,
    );
    if (result.success) {
      setConfirmationsList((prev) =>
        prev.filter((c) => c.id !== confirmationId),
      );
    } else {
      setError(result.error || "Failed to accept confirmation");
    }
    setProcessingIds((prev) => {
      const newSet = new Set(prev);
      newSet.delete(confirmationId);
      return newSet;
    });
  };

  const handleDecline = async (confirmationId: string) => {
    if (!account || processingIds.has(confirmationId)) return;
    if (!account.cookies) {
      setError("Account is not logged in. Please login first.");
      return;
    }

    setProcessingIds((prev) => new Set(prev).add(confirmationId));
    const result = await accountApi.declineConfirmation(
      account.accountName,
      confirmationId,
    );
    if (result.success) {
      setConfirmationsList((prev) =>
        prev.filter((c) => c.id !== confirmationId),
      );
    } else {
      setError(result.error || "Failed to decline confirmation");
    }
    setProcessingIds((prev) => {
      const newSet = new Set(prev);
      newSet.delete(confirmationId);
      return newSet;
    });
  };

  const toggleSetting = async (setting: SettingType, currentValue: boolean) => {
    if (!account) return;
    setLoading(setting);
    setError(null);
    try {
      const response = await accountApi.confirmationSetting(
        account.accountName,
        setting,
      );
      if (response.success) {
        const updatedConfirmations = {
          ...account.confirmations,
          [setting === "acceptGiftTrade" ? "acceptGiftTrade" : setting]:
            !currentValue,
        };
        const updatedAccount = {
          ...account,
          confirmations: updatedConfirmations,
        };
        if (onUpdateAccount) onUpdateAccount(updatedAccount);
      } else {
        setError(response.error || "Failed to toggle setting");
      }
    } catch (err) {
      console.error("Toggle error:", err);
      setError("Network error. Please try again.");
    } finally {
      setLoading(null);
    }
  };

  const renderToggle = (
    label: string,
    setting: SettingType,
    isActive: boolean,
  ) => {
    const isLoading = loading === setting;
    return (
      <div className="flex justify-between items-center border-b border-gray-700 pb-3">
        <span className="text-gray-300">{label}</span>
        <button
          onClick={() => toggleSetting(setting, isActive)}
          disabled={isLoading}
          className={`
            relative inline-flex h-6 w-11 items-center rounded-full transition-all duration-200 cursor-pointer
            ${isActive ? "bg-green-600 hover:bg-green-500" : "bg-gray-600 hover:bg-gray-500"}
            ${isLoading ? "opacity-50 cursor-wait" : "cursor-pointer"}
          `}
        >
          <span
            className={`
              inline-block h-4 w-4 transform rounded-full bg-white transition-transform duration-200
              ${isActive ? "translate-x-6" : "translate-x-1"}
            `}
          />
        </button>
      </div>
    );
  };

  if (!account) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center text-gray-400">No account selected</div>
      </div>
    );
  }
  if (account.sharedSecret == "") {
    return <ConfirmationsUnavailable />;
  }
  if (!account.cookies && account.status === "offline") {
    return (
      <AuthenticationRequired
        handleLogin={handleLogin}
        loggingIn={loggingIn}
        loginError={loginError}
        text="You need to be logged in to manage confirmations"
      />
    );
  }
  if (account.status === "logining") {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-purple-500 mx-auto mb-4"></div>
          <div className="text-gray-300 text-lg font-medium mb-2">
            Logging in...
          </div>
          <div className="text-gray-400 text-sm">
            Please wait while we establish connection
          </div>
        </div>
      </div>
    );
  }

  // Общий блок заголовка с кнопками
  const headerWithButtons = (
    <div className="flex justify-between items-center mb-6">
      <h1 className="text-2xl font-bold">Confirmations</h1>
      {renderHeaderButtons()}
    </div>
  );

  // Блок настроек автоподтверждений (общий)
  const settingsBlock = (disabled: boolean = false) => (
    <div
      className={`bg-gray-800/40 rounded-lg p-6 ${disabled ? "relative" : ""}`}
    >
      {disabled && (
        <div className="absolute inset-0 bg-gray-900/60 backdrop-blur-sm rounded-lg flex flex-col items-center justify-center gap-3 z-10">
          <p className="text-amber-400 text-sm font-medium">
            To activate auto‑confirmation settings – please resume the session
          </p>
          <button
            onClick={handleLogin}
            className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-md text-sm font-medium transition-colors cursor-pointer"
          >
            Launch account
          </button>
        </div>
      )}
      <div className={disabled ? "opacity-40 pointer-events-none" : ""}>
        <h2 className="text-xl font-semibold mb-4">
          Auto-Confirmation Settings
        </h2>
        <div className="space-y-3">
          {renderToggle(
            "Market Confirmations",
            "market",
            account.confirmations.market,
          )}
          {renderToggle(
            "Trade Confirmations",
            "trade",
            account.confirmations.trade,
          )}
          {renderToggle(
            "Accept Gift Trade",
            "acceptGiftTrade",
            account.confirmations.acceptGiftTrade,
          )}
          {renderToggle(
            "System Confirmations",
            "system",
            account.confirmations.system,
          )}
        </div>
      </div>
    </div>
  );

  // Общий блок поиска (спиннер)
  const searchingBlock = () => (
    <div className="bg-gray-800/40 rounded-lg p-6 mb-6">
      <div className="flex flex-col items-center justify-center py-12">
        <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-purple-500 mx-auto mb-4"></div>
        <div className="text-gray-300 text-lg font-medium mb-2">
          Searching for confirmations...
        </div>
        <div className="text-gray-400 text-sm">
          Waiting for new confirmations to appear
        </div>
        <div className="text-gray-500 text-xs mt-2">
          Refresh in {timeUntilRefresh}s
        </div>
      </div>
    </div>
  );

  // Общий блок списка подтверждений
  const confirmationsListBlock = () => (
    <div className="bg-gray-800/40 rounded-lg p-6 mb-6">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-xl font-semibold">
          Pending Confirmations for {account.accountName}
        </h2>
        <div className="text-gray-500 text-xs">
          Refresh in {timeUntilRefresh}s
        </div>
      </div>
      <div className="space-y-3">
        {confirmationsList.map((conf) => {
          const isProcessing = processingIds.has(conf.id);
          return (
            <div
              key={conf.id}
              className="flex items-start gap-3 p-3 bg-gray-700/30 rounded-lg transition-opacity duration-200"
            >
              {conf.icon && (
                <img
                  src={conf.icon}
                  alt=""
                  className="w-10 h-10 rounded object-cover flex-shrink-0"
                  onError={(e) => (e.currentTarget.style.display = "none")}
                />
              )}
              <div className="flex-1">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-medium">
                    {conf.title || getConfirmationTypeName(conf.type)}
                  </span>
                  <span className="text-xs text-gray-400">
                    {formatDate(conf.time || conf.timestamp)}
                  </span>
                </div>
                {conf.sending && conf.sending !== "null" && (
                  <div className="text-sm text-red-300">➤ {conf.sending}</div>
                )}
                {conf.receiving && conf.receiving !== "null" && (
                  <div className="text-sm text-green-300">
                    ◀ {conf.receiving}
                  </div>
                )}
                {conf.type === ConfirmationType.MarketBuy &&
                  !conf.sending &&
                  !conf.receiving && (
                    <div className="text-sm text-yellow-300">
                      🛡️ Security verification required
                    </div>
                  )}
                <div className="text-xs text-gray-400 mt-1">
                  Type: {getConfirmationTypeName(conf.type)} • ID: {conf.id}
                </div>
              </div>
              <div className="flex gap-2 flex-shrink-0">
                <button
                  onClick={() => handleAccept(conf.id)}
                  disabled={isProcessing}
                  className="px-3 py-1 bg-green-600 hover:bg-green-700 cursor-pointer rounded text-sm transition-colors disabled:opacity-50 flex items-center gap-1 min-w-[70px] justify-center"
                >
                  {isProcessing ? (
                    <>
                      <Loader2 className="w-3 h-3 animate-spin" />
                      <span>...</span>
                    </>
                  ) : (
                    "Accept"
                  )}
                </button>
                <button
                  onClick={() => handleDecline(conf.id)}
                  disabled={isProcessing}
                  className="px-3 py-1 bg-red-600 hover:bg-red-700 rounded cursor-pointer text-sm transition-colors disabled:opacity-50 flex items-center gap-1 min-w-[70px] justify-center"
                >
                  {isProcessing ? (
                    <>
                      <Loader2 className="w-3 h-3 animate-spin" />
                      <span>...</span>
                    </>
                  ) : (
                    "Decline"
                  )}
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );

  // Общий компонент модального окна для массовых действий
  const renderBulkModal = () => (
    <Modal
      isOpen={modalState.open}
      onClose={() => setModalState({ type: null, open: false })}
      title={
        modalState.type === "accept"
          ? "Confirm Accept All"
          : "Confirm Decline All"
      }
      icon={<AlertTriangle className="w-5 h-5 text-red-400" />}
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={() => setModalState({ type: null, open: false })}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-md text-sm font-medium transition-colors cursor-pointer"
          >
            Cancel
          </button>
          <button
            onClick={
              modalState.type === "accept" ? handleAcceptAll : handleDeclineAll
            }
            disabled={bulkLoading.accept || bulkLoading.decline}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-colors cursor-pointer flex items-center gap-2 ${
              modalState.type === "accept"
                ? "bg-green-600 hover:bg-green-700"
                : "bg-red-600 hover:bg-red-700"
            } disabled:opacity-50`}
          >
            {(bulkLoading.accept || bulkLoading.decline) && (
              <Loader2 className="w-4 h-4 animate-spin" />
            )}
            {modalState.type === "accept"
              ? "Yes, accept all"
              : "Yes, decline all"}
          </button>
        </div>
      }
      maxWidth="md"
    >
      <div className="p-4">
        <p className="text-gray-300">
          Are you sure you want to{" "}
          {modalState.type === "accept" ? "accept" : "decline"}{" "}
          <strong>all {confirmationsList.length} pending confirmations</strong>?
        </p>
        <p className="text-red-400 text-sm mt-2">
          This action cannot be undone.
        </p>
      </div>
    </Modal>
  );

  // Отрисовка в зависимости от состояния
  if (
    account.cookies &&
    account.status === "offline" &&
    confirmationsList.length === 0
  ) {
    return (
      <div className="max-w-4xl mx-auto">
        {headerWithButtons}
        {searchingBlock()}
        {settingsBlock(true)}
        {error && (
          <div className="mt-4 p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
            {error}
          </div>
        )}
        {renderBulkModal()}
      </div>
    );
  }

  if (
    account.cookies &&
    account.status !== "offline" &&
    confirmationsList.length === 0 &&
    !error
  ) {
    return (
      <div className="max-w-4xl mx-auto">
        {headerWithButtons}
        {searchingBlock()}
        {settingsBlock(false)}
        {error && (
          <div className="mt-4 p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
            {error}
          </div>
        )}
        {renderBulkModal()}
      </div>
    );
  }

  if (
    account.cookies &&
    account.status !== "offline" &&
    confirmationsList.length > 0
  ) {
    return (
      <div className="max-w-4xl mx-auto">
        {headerWithButtons}
        {confirmationsListBlock()}
        {settingsBlock(false)}
        {error && (
          <div className="mt-4 p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
            {error}
          </div>
        )}
        {renderBulkModal()}
      </div>
    );
  }

  if (
    account.cookies &&
    account.status === "offline" &&
    confirmationsList.length > 0
  ) {
    return (
      <div className="max-w-4xl mx-auto">
        {headerWithButtons}
        {confirmationsListBlock()}
        {settingsBlock(true)}
        {error && (
          <div className="mt-4 p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
            {error}
          </div>
        )}
        {renderBulkModal()}
      </div>
    );
  }

  return null;
}
