// components/AccountList/AccountAvatar.tsx
import { cn } from "@/lib/utils";
import { User } from "lucide-react";

interface AccountAvatarProps {
  avatar?: string;
  username?: string;
  activePage: string;
  isSelected: boolean;
}

export function AccountAvatar({
  avatar,
  username,
  activePage,
  isSelected,
}: AccountAvatarProps) {
  if (avatar) {
    return (
      <img
        src={avatar}
        alt={username}
        className={cn(
          activePage === "profile" &&
            isSelected &&
            "outline-2 outline-emerald-300",
          "h-8 w-8 rounded-full object-cover flex-shrink-0",
        )}
      />
    );
  }

  return (
    <div className="flex h-8 w-8 items-center justify-center rounded-full bg-gray-800 flex-shrink-0">
      <User size={14} className="text-gray-500" />
    </div>
  );
}
