// components/AccountList/StatusIcon.tsx
import { cn } from "../../lib/utils";

interface StatusIconProps {
  isActive: boolean;
  icon: React.ReactNode;
  label: string;
  activeText: string;
  inactiveText: string;
}

export function StatusIcon({
  isActive,
  icon,
  label,
  activeText,
  inactiveText,
}: StatusIconProps) {
  return (
    <div className="relative group">
      <div
        className={cn(
          "h-5 w-5 rounded-full flex items-center justify-center transition-all cursor-help",
          isActive
            ? "bg-emerald-500/20 text-emerald-400"
            : "bg-red-500/20 text-red-400",
        )}
        title={label}
      >
        {icon}
      </div>
      <span className="absolute bottom-full left-1/2 -translate-x-1/2 mb-1 px-1.5 py-0.5 rounded text-[8px] font-medium bg-gray-900 text-white whitespace-nowrap opacity-0  transition-opacity pointer-events-none z-10">
        {isActive ? activeText : inactiveText}
      </span>
    </div>
  );
}
