import {
  CheckCircle,
  XCircle,
  AlertCircle,
  RefreshCcw,
  LockOpen,
  LockKeyholeOpen,
  Lock,
} from "lucide-react";
import { SteamAccountInfo } from "../types";
import { SortHeader } from "./SortHeader";
import { BalanceSortField } from "../types/index.ts";
import { formatTimeAgo } from "@/shared/utils/timeFormatter.ts";

interface BalanceTableProps {
  accounts: SteamAccountInfo[];
  sortField: BalanceSortField;
  sortOrder: "asc" | "desc";
  onSort: (field: BalanceSortField) => void;
}

export function BalanceTable({
  accounts,
  sortField,
  sortOrder,
  onSort,
}: BalanceTableProps) {
  return (
    <table className="w-full">
      <thead className="bg-secondary/50">
        <tr>
          <SortHeader
            label="Login"
            field="login"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Balance"
            field="balance"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Active Listings"
            field="activeListings"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Active Orders"
            field="activeOrders"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Market Status"
            field="marketStatus"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Last Update"
            field="lastUpdated"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
        </tr>
      </thead>
      <tbody>
        {accounts.length > 0 ? (
          accounts.map((account) => (
            <tr
              key={account.accountName}
              className="border-t border-border hover:bg-secondary/20 transition-colors"
            >
              <td className="p-3 text-sm font-medium">{account.accountName}</td>
              <td className="p-3 text-sm text-emerald-400 font-mono">
                <div className="flex space-x-2 group cursor-pointer">
                  <p>{account.balance?.formattedBalance || "0"}</p>
                  <p className="invisible group-hover:visible duration-100">
                    ($
                    {typeof account.balance?.usdbalance === "number"
                      ? account.balance.usdbalance.toFixed(2)
                      : "0.00"}
                    )
                  </p>
                </div>
              </td>
              <td className="p-3 text-sm text-yellow-400">
                {account.activeListings || 0}
              </td>
              <td className="p-3 text-sm text-yellow-400">
                {account.activeOrders || 0}
              </td>
              <td className="p-3">
                {(() => {
                  const willOpen = account.market.willOpen;
                  const date = willOpen ? new Date(willOpen as Date) : null;

                  const bans = account.bans.kt;
                  const open = account.market.open;
                  const can = account.market.canOpenByPurchase;
                  if (bans)
                    return (
                      <span className="inline-flex items-center gap-1 text-xs text-red-400 font-semibold">
                        <Lock size={12} /> Blocked
                      </span>
                    );
                  if (date)
                    return (
                      <span className="inline-flex items-center gap-1 text-xs text-emerald-400">
                        <LockOpen size={12} />{" "}
                        {date.getTime() < new Date().getTime()
                          ? date.toLocaleDateString() +
                            " " +
                            date.toLocaleTimeString()
                          : "123"}
                      </span>
                    );
                  if (can)
                    return (
                      <span className="inline-flex items-center gap-1 text-xs text-yellow-400 font-semibold">
                        <LockOpen size={12} />
                        Сan be opened
                      </span>
                    );
                  if (open)
                    return (
                      <span className="inline-flex items-center gap-1 text-xs text-emerald-400">
                        <LockKeyholeOpen size={12} /> Available
                      </span>
                    );
                  return (
                    <span className="inline-flex items-center gap-1 text-xs text-orange-400">
                      <RefreshCcw size={12} /> Need Update
                    </span>
                  );
                })()}
              </td>
              <td className="p-3 text-sm text-yellow-400">
                {account.balance?.lastUpdated
                  ? formatTimeAgo(account.balance.lastUpdated)
                  : "N/A"}
              </td>
            </tr>
          ))
        ) : (
          <tr>
            <td colSpan={5} className="p-8 text-center text-muted-foreground">
              <AlertCircle className="h-8 w-8 mx-auto mb-2 opacity-30" />
              <p className="text-sm">No accounts with wallet found</p>
            </td>
          </tr>
        )}
      </tbody>
    </table>
  );
}
