// components/Market/MarketHeader.tsx
import { SteamAccountInfo } from "@/types";
import { RefreshCw, Tag, PlusCircle } from "lucide-react";

interface MarketHeaderProps {
  account: SteamAccountInfo;
  onRefresh: () => void;
  onCreateOrder?: () => void; // Добавлено
  isLoading: boolean;
}

export function MarketHeader({
  account,
  onRefresh,
  onCreateOrder,
  isLoading,
}: MarketHeaderProps) {
  console.log(account);
  return (
    <div className="flex justify-between items-center mb-6">
      <h1 className="text-2xl font-bold">Steam Market</h1>
      <div className="flex gap-4">
        {onCreateOrder && (
          <button
            onClick={onCreateOrder}
            className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
          >
            <PlusCircle size={16} />
            Create Order
          </button>
        )}
        <button
          onClick={onRefresh}
          disabled={isLoading}
          className="p-2 rounded-md hover:bg-gray-700 transition-colors disabled:opacity-50"
          title="Refresh"
        >
          <RefreshCw size={18} className={isLoading ? "animate-spin" : ""} />
        </button>
      </div>
    </div>
  );
}
