// components/inventory/GameSelector.tsx
import { useState } from "react";
import { ChevronDown } from "lucide-react";
import { GameOption, POPULAR_GAMES } from "@/constants/games.constants";

interface GameSelectorProps {
  selectedGame: GameOption | null;
  onSelectGame: (game: GameOption) => void;
}

export function GameSelector({
  selectedGame,
  onSelectGame,
}: GameSelectorProps) {
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);

  return (
    <div className="bg-gray-800/40 rounded-lg p-4 mb-6">
      <label className="block text-sm font-medium text-gray-300 mb-2">
        Select Game
      </label>
      <div className="relative">
        <button
          onClick={() => setIsDropdownOpen(!isDropdownOpen)}
          className="w-full flex items-center justify-between px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white hover:bg-gray-700 transition-colors cursor-pointer"
        >
          <span>{selectedGame ? selectedGame.name : "Choose a game..."}</span>
          <ChevronDown
            size={18}
            className={`transition-transform ${isDropdownOpen ? "rotate-180" : ""}`}
          />
        </button>

        {isDropdownOpen && (
          <div className="absolute top-full left-0 right-0 mt-1 bg-gray-800 border border-gray-700 rounded-lg shadow-lg z-10 max-h-60 overflow-y-auto">
            {POPULAR_GAMES.map((game) => (
              <button
                key={game.appId}
                onClick={() => {
                  onSelectGame(game);
                  setIsDropdownOpen(false);
                }}
                className={`w-full text-left px-4 py-2 hover:bg-gray-700 transition-colors cursor-pointer ${
                  selectedGame?.appId === game.appId ? "bg-indigo-600/30" : ""
                }`}
              >
                <div className="text-sm text-white">{game.name}</div>
                <div className="text-xs text-gray-400">ID: {game.appId}</div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
