export function parseMarketHashNameFromUrl(
  url: string,
): { appId: string; marketHashName: string } | null {
  try {
    const patterns = [
      /steamcommunity\.com\/market\/listings\/(\d+)\/([^?]+)/,
      /steamcommunity\.com\/market\/listings\/(\d+)\/(.+?)(?:\?|$)/,
    ];

    for (const pattern of patterns) {
      const match = url.match(pattern);
      if (match) {
        let marketHashName = decodeURIComponent(match[2]);
        marketHashName = marketHashName.replace(/\+/g, " ");
        return {
          appId: match[1],
          marketHashName: marketHashName,
        };
      }
    }

    return null;
  } catch (error) {
    console.error("Error parsing URL:", error);
    return null;
  }
}
