import { useState, useMemo } from "react";
import { Search } from "lucide-react";
import { cn } from "../lib/utils";
import { Wallet, Users, Shield, Package } from "lucide-react";
import { MainPageProps, ActiveCard } from "../types/index";
import { useMainPageStats, useMainPageSort } from "../hooks/index";

import {
  DashboardCards,
  BalanceTable,
  AccountsTable,
  BansTable,
} from "../components/index";

export function MainPage({ accounts }: MainPageProps) {
  const [activeCard, setActiveCard] = useState<ActiveCard>("balance");
  const [searchQuery, setSearchQuery] = useState("");

  const {
    accountsWithWallet,
    balances,
    totalBalanceUSD,
    accountStats,
    banStats,
    inventoryStats,
    loadingInventory,
    refreshInventory,
  } = useMainPageStats(accounts);

  const filteredAccounts = useMemo(() => {
    if (!searchQuery) return accounts;
    return accounts.filter((account) =>
      account.accountName.toLowerCase().includes(searchQuery.toLowerCase()),
    );
  }, [accounts, searchQuery]);

  const filteredAccountsWithWallet = useMemo(() => {
    if (!searchQuery) return accountsWithWallet;
    return accountsWithWallet.filter((account) =>
      account.accountName.toLowerCase().includes(searchQuery.toLowerCase()),
    );
  }, [accountsWithWallet, searchQuery]);

  const {
    balanceSortField,
    balanceSortOrder,
    accountsSortField,
    accountsSortOrder,
    bansSortField,
    bansSortOrder,
    handleBalanceSort,
    handleAccountsSort,
    handleBansSort,
    handleInventorySort,
    sortedBalanceAccounts,
    sortedAccountsList,
    sortedBansAccounts,
  } = useMainPageSort(filteredAccounts);

  const getActiveIcon = () => {
    switch (activeCard) {
      case "balance":
        return <Wallet className="h-4 w-4 text-indigo-400" />;
      case "accounts":
        return <Users className="h-4 w-4 text-indigo-400" />;
      case "bans":
        return <Shield className="h-4 w-4 text-red-400" />;
      case "inventory":
        return <Package className="h-4 w-4 text-emerald-400" />;
    }
  };

  const getActiveTitle = () => {
    switch (activeCard) {
      case "balance":
        return "Account Balances";
      case "accounts":
        return "Account Details";
      case "bans":
        return "Banned Accounts";
      case "inventory":
        return "Inventory Details";
    }
  };

  const renderTable = () => {
    switch (activeCard) {
      case "balance":
        return (
          <BalanceTable
            accounts={sortedBalanceAccounts}
            sortField={balanceSortField}
            sortOrder={balanceSortOrder}
            onSort={handleBalanceSort}
          />
        );
      case "accounts":
        return (
          <AccountsTable
            accounts={sortedAccountsList}
            sortField={accountsSortField}
            sortOrder={accountsSortOrder}
            onSort={handleAccountsSort}
          />
        );
      case "bans":
        return (
          <BansTable
            accounts={sortedBansAccounts}
            sortField={bansSortField}
            sortOrder={bansSortOrder}
            onSort={handleBansSort}
          />
        );
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl text-white font-bold tracking-tight bg-gradient-to-r from-indigo-400 to-emerald-400 bg-clip-text text-transparent">
          Dashboard Overview
        </h1>
        <p className="text-sm text-muted-foreground mt-0.5">
          Account Management Statistics
        </p>
      </div>

      <DashboardCards
        activeCard={activeCard}
        onCardClick={setActiveCard}
        totalBalanceUSD={totalBalanceUSD}
        balances={balances}
        accountStats={accountStats}
        banStats={banStats}
        totalInventoryItems={inventoryStats.totalItems}
        totalInventoryValue={inventoryStats.totalValue}
        cheapItemsCount={inventoryStats.cheapItemsCount}
        topGames={inventoryStats.topGames}
        onRefreshInventory={refreshInventory}
        loadingInventory={loadingInventory}
      />

      <div className="rounded-lg border border-border bg-card">
        <div className="p-4 border-b border-border">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <input
              type="text"
              placeholder="Search by login..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-4 py-2 rounded-md border border-border bg-background text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>
        </div>

        <div className="flex items-center gap-2 px-4 py-3 border-b border-border bg-secondary/20">
          <div
            className={cn(
              "rounded-md p-1.5",
              activeCard === activeCard && "bg-indigo-500/10",
            )}
          >
            {getActiveIcon()}
          </div>
          <h2 className="text-base font-semibold">{getActiveTitle()}</h2>
        </div>

        <div className="overflow-x-auto">{renderTable()}</div>
      </div>
    </div>
  );
}
