// utils/rarity.ts
export const getRarityColor = (rarityName: string): string => {
  const rarityMap: Record<string, string> = {
    "Consumer Grade": "text-gray-400",
    "Industrial Grade": "text-blue-400",
    "Mil-Spec Grade": "text-blue-300",
    Restricted: "text-purple-400",
    Classified: "text-pink-400",
    Covert: "text-red-400",
    "Base Grade": "text-gray-400",
    "Exceedingly Rare": "text-yellow-400",
    Contraband: "text-orange-400",
  };
  return rarityMap[rarityName] || "text-gray-300";
};

export const getRarityBgColor = (rarityName: string): string => {
  const rarityMap: Record<string, string> = {
    "Consumer Grade": "bg-gray-500/20",
    "Industrial Grade": "bg-blue-500/20",
    "Mil-Spec Grade": "bg-blue-500/20",
    Restricted: "bg-purple-500/20",
    Classified: "bg-pink-500/20",
    Covert: "bg-red-500/20",
    "Base Grade": "bg-gray-500/20",
    "Exceedingly Rare": "bg-yellow-500/20",
    Contraband: "bg-orange-500/20",
  };
  return rarityMap[rarityName] || "bg-gray-500/20";
};

export const getItemRarityFromTags = (item: any): string => {
  const rarityTag = item.tags?.find((tag: any) => tag.category === "Rarity");
  return rarityTag?.name || item.type || "Common";
};
