// pages/InventoryPage.tsx
import { useState, useCallback } from "react";
import { Package, RefreshCw } from "lucide-react";
import { SelectedItemWithPrice, SteamAccountInfo } from "../types";
import { accountApi } from "../services/api";
import { GameOption } from "@/constants/games.constants";
import { useInventory } from "../hooks/use-inventory";
import { GameSelector } from "../components/Inventory/GameSelector";
import { SellModal } from "@/components/Inventory/SellModal";
import { PriceDetailsModal } from "@/components/Inventory/PriceDetailsModal";
import { TradeModal } from "@/components/Inventory/TradeModal";
import { InventoryGrid } from "@/components/Inventory/InventoryGrid";
import { useAccountLogin } from "@/hooks/use-account-login";
import { AuthenticationRequired } from "@/components/AuthenticationRequired";

interface InventoryPageProps {
  account: SteamAccountInfo;
  accounts: SteamAccountInfo[];
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
}

export function InventoryPage({
  account,
  accounts,
  onUpdateAccount,
}: InventoryPageProps) {
  const [selectedGame, setSelectedGame] = useState<GameOption | null>(null);
  const [actionModalOpen, setActionModalOpen] = useState(false);
  const [currentAction, setCurrentAction] = useState<"sell" | "trade" | null>(
    null,
  );
  const [processingAction, setProcessingAction] = useState(false);
  const [notification, setNotification] = useState<{
    type: "success" | "error";
    message: string;
  } | null>(null);
  const [detailedResult, setDetailedResult] = useState<{
    ok: string[];
    error: string[];
  } | null>(null);
  const [tradeUrl, setTradeUrl] = useState("");
  const [tradeSending, setTradeSending] = useState(false);
  const [priceModalOpen, setPriceModalOpen] = useState(false);
  const [priceModalType, setPriceModalType] = useState<
    "instant" | "market" | null
  >(null);
  const [selectedItemForPrice, setSelectedItemForPrice] =
    useState<SelectedItemWithPrice | null>(null);
  const [searchQuery, setSearchQuery] = useState("");

  const {
    inventory,
    loading,
    error,
    selectedItems,
    itemPrices,
    loadingItems,
    handleItemSelect,
    handleSelectAll,
    startLoadingPrices,
    updateItemPrice,
    setPriceMinusOneCent,
    clearPrices,
    fetchInventory,
    setError,
    setSelectedItems,
  } = useInventory(account, selectedGame);
  const { loggingIn, handleLogin, loginError } = useAccountLogin({
    account,
    onUpdateAccount,
  });
  const openActionModal = async (action: "sell" | "trade") => {
    if (selectedItems.size === 0) {
      setError("Please select at least one item");
      return;
    }

    setCurrentAction(action);
    setActionModalOpen(true);
    setDetailedResult(null);

    // Для обоих действий загружаем цены, чтобы отображать стоимость
    const selectedItemsList = inventory.filter((item) =>
      selectedItems.has(item.assetid),
    );
    await startLoadingPrices(selectedItemsList);

    if (action === "trade") {
      setTradeUrl("");
      setTradeSending(false);
    }
  };

  const handleCreateListings = async () => {
    if (!account) return;

    setProcessingAction(true);
    setNotification(null);
    setDetailedResult(null);

    const itemsToSell = Array.from(itemPrices.values())
      .filter((item) => item.customPrice && parseFloat(item.customPrice) > 0)
      .map((item) => {
        let price: string;
        if ((parseFloat(item.customPrice) * 100).toFixed(0) === "3") {
          price = "1";
        } else {
          price = (parseFloat(item.customPrice) * 100).toFixed(0);
        }
        return {
          appId: item.appid.toString(),
          contextId: item.contextid,
          assetId: item.assetid,
          price,
        };
      });

    if (itemsToSell.length === 0) {
      setError("Please set valid prices for at least one item");
      setProcessingAction(false);
      return;
    }

    try {
      const result = await accountApi.createMarketListing(
        account.accountName,
        itemsToSell,
      );
      if (result.data) {
        const { ok, error: errorList } = result.data;
        setDetailedResult({ ok: ok || [], error: errorList || [] });
        const successCount = ok?.length || 0;
        const errorCount = errorList?.length || 0;

        if (successCount > 0 && errorCount === 0) {
          setNotification({
            type: "success",
            message: `Successfully listed ${successCount} item(s) for sale!`,
          });
          setTimeout(() => {
            setActionModalOpen(false);
            clearPrices();
            setNotification(null);
            setDetailedResult(null);
            fetchInventory();
          }, 3000);
        } else if (successCount > 0 && errorCount > 0) {
          setNotification({
            type: "success",
            message: `Listed ${successCount} item(s), ${errorCount} failed.`,
          });
        } else {
          setNotification({
            type: "error",
            message: result.error || "Failed to create listings",
          });
        }
      } else {
        setNotification({
          type: "error",
          message: result.error || "Failed to create listings",
        });
      }
    } catch (err) {
      setNotification({
        type: "error",
        message: "Network error. Please try again.",
      });
    } finally {
      setProcessingAction(false);
    }
  };

  const handleSendTrade = async (url: string) => {
    if (!account) return;

    const selectedItemsList = inventory.filter((item) =>
      selectedItems.has(item.assetid),
    );
    if (selectedItemsList.length === 0) {
      setError("No items selected for trade");
      return;
    }

    setTradeSending(true);
    setNotification(null);

    try {
      const result = await accountApi.sendTrade(
        account.accountName,
        url,
        selectedItemsList,
      );
      if (result.success) {
        setNotification({
          type: "success",
          message: `Successfully sent trade offer for ${selectedItemsList.length} item(s)!`,
        });
        setTimeout(() => {
          setActionModalOpen(false);
          setSelectedItems(new Set());
          setNotification(null);
          setTradeUrl("");
          fetchInventory();
        }, 3000);
      } else {
        setNotification({
          type: "error",
          message: result.error || "Failed to send trade offer",
        });
      }
    } catch (err) {
      setNotification({
        type: "error",
        message: "Network error. Please try again.",
      });
    } finally {
      setTradeSending(false);
    }
  };

  const openPriceModal = (
    item: SelectedItemWithPrice,
    type: "instant" | "market",
  ) => {
    setSelectedItemForPrice(item);
    setPriceModalType(type);
    setPriceModalOpen(true);
  };

  const closeModal = () => {
    setActionModalOpen(false);
    setNotification(null);
    setDetailedResult(null);
    setTradeUrl("");
    clearPrices();
  };
  const totalPrice = Array.from(itemPrices.values()).reduce((sum, item) => {
    const price = item.customPrice ? parseFloat(item.customPrice) : 0;
    return sum + price;
  }, 0);
  const formatPrice = (price: number, prefix: string = "", suffix?: string) => {
    return `${prefix && prefix}${price.toFixed(2)}${suffix}`;
  };

  const selectedItemsList = Array.from(itemPrices.values());
  const totalLoadingItems = loadingItems.size;
  const loadedCount = selectedItemsList.length;

  if (!account) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center text-gray-400">No account selected</div>
      </div>
    );
  }

  if (!account.cookies) {
    return (
      <AuthenticationRequired
        text={"You need to be logged in to view your inventory."}
        handleLogin={handleLogin}
        loggingIn={loggingIn}
        loginError={loginError}
      />
    );
  }

  return (
    <div className="max-w-6xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Steam Inventory</h1>

        <button
          onClick={fetchInventory}
          disabled={loading || !selectedGame}
          className="p-2 rounded-md hover:bg-gray-700 transition-colors disabled:opacity-50"
          title="Refresh"
        >
          <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
        </button>
      </div>

      <GameSelector
        selectedGame={selectedGame}
        onSelectGame={setSelectedGame}
      />

      {selectedGame ? (
        <InventoryGrid
          account={account}
          inventory={inventory}
          loading={loading}
          error={error}
          searchQuery={searchQuery}
          onSearchChange={setSearchQuery}
          selectedItems={selectedItems}
          onItemSelect={handleItemSelect}
          handleSelectAll={handleSelectAll}
          onSellClick={() => openActionModal("sell")}
          onTradeClick={() => openActionModal("trade")}
          selectedCount={selectedItems.size}
        />
      ) : (
        <div className="bg-gray-800/40 rounded-lg p-12 text-center">
          <Package size={48} className="mx-auto mb-4 opacity-50" />
          <p className="text-gray-400">Select a game to view your inventory</p>
        </div>
      )}

      <SellModal
        isOpen={actionModalOpen && currentAction === "sell"}
        onClose={closeModal}
        selectedItems={selectedItemsList}
        loadingItems={loadingItems}
        processingAction={processingAction}
        notification={notification}
        detailedResult={detailedResult}
        error={error}
        totalLoadingItems={totalLoadingItems}
        loadedCount={loadedCount}
        onPriceChange={updateItemPrice}
        onPriceMinusOneCent={setPriceMinusOneCent}
        onOpenPriceModal={openPriceModal}
        onCreateListings={handleCreateListings}
        formatPrice={(price, prefix, suffix) =>
          formatPrice(price, prefix, suffix)
        }
      />

      {account.identity_secret && account.sharedSecret && (
        <TradeModal
          currency={account.balance?.formattedBalance.replace(/\d/g, "") || ""}
          accounts={accounts}
          isOpen={actionModalOpen && currentAction === "trade"}
          onClose={closeModal}
          selectedCount={selectedItems.size}
          totalPrice={totalPrice}
          onSendTrade={handleSendTrade}
          notification={notification}
          error={error}
          sending={tradeSending}
        />
      )}

      <PriceDetailsModal
        isOpen={priceModalOpen}
        onClose={() => {
          setPriceModalOpen(false);
          setSelectedItemForPrice(null);
          setPriceModalType(null);
        }}
        item={selectedItemForPrice}
        modalType={priceModalType}
        formatPrice={formatPrice}
      />
    </div>
  );
}
