// components/Tags/TagsModal.tsx
import { useState, useEffect } from "react";
import { createPortal } from "react-dom";
import {
  X,
  Plus,
  Loader2,
  Tag,
  AlertCircle,
  Trash2,
  Pencil,
} from "lucide-react";
import { accountApi } from "@/services/api";
import { Tag as TagType, SteamAccountInfo } from "@/types";
import { TagChip } from "./TagChip";

interface TagsModalProps {
  isOpen: boolean;
  onClose: () => void;
  account: SteamAccountInfo;
  onTagsUpdated: () => void;
}

const PRESET_COLORS = [
  "#EF4444",
  "#F97316",
  "#F59E0B",
  "#EAB308",
  "#84CC16",
  "#22C55E",
  "#10B981",
  "#14B8A6",
  "#06B6D4",
  "#0EA5E9",
  "#3B82F6",
  "#6366F1",
  "#8B5CF6",
  "#A855F7",
  "#D946EF",
  "#EC4899",
  "#F43F5E",
  "#78716C",
  "#6B7280",
  "#334155",
];

export function TagsModal({
  isOpen,
  onClose,
  account,
  onTagsUpdated,
}: TagsModalProps) {
  const [allTags, setAllTags] = useState<TagType[]>([]);
  const [accountTagIds, setAccountTagIds] = useState<Set<number>>(new Set());
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [creating, setCreating] = useState(false);
  const [newTagName, setNewTagName] = useState("");
  const [newTagColor, setNewTagColor] = useState(PRESET_COLORS[0]);
  const [editingTag, setEditingTag] = useState<TagType | null>(null); // добавить
  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [tagsRes, accountTagsRes] = await Promise.all([
        accountApi.getAllTags(),
        accountApi.getAccountTags(account.accountName),
      ]);
      if (!tagsRes.success) throw new Error(tagsRes.error);
      if (!accountTagsRes.success) throw new Error(accountTagsRes.error);
      setAllTags(tagsRes.data || []);
      setAccountTagIds(
        new Set((accountTagsRes.data || []).map((t: TagType) => t.id)),
      );
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };
  const handleEditSaved = (updatedTag: TagType) => {
    setAllTags((prev) =>
      prev.map((t) => (t.id === updatedTag.id ? updatedTag : t)),
    );

    window.location.reload();
  };
  useEffect(() => {
    if (isOpen) loadData();
  }, [isOpen, account.accountName]);

  const handleToggleTag = async (
    tagId: number,
    isCurrentlyAttached: boolean,
  ) => {
    try {
      if (isCurrentlyAttached) {
        const res = await accountApi.removeTagFromAccount(
          account.accountName,
          tagId,
        );
        if (!res.success) throw new Error(res.error);
        setAccountTagIds((prev) => {
          const newSet = new Set(prev);
          newSet.delete(tagId);
          return newSet;
        });
      } else {
        const res = await accountApi.addTagToAccount(
          account.accountName,
          tagId,
        );
        if (!res.success) throw new Error(res.error);
        setAccountTagIds((prev) => new Set(prev).add(tagId));
      }
      onTagsUpdated();
    } catch (err: any) {
      console.error(err);
      alert(err.message);
    }
  };

  const handleDeleteTag = async (tagId: number, tagName: string) => {
    if (
      !confirm(
        `Are you sure you want to delete tag "${tagName}"? It will be removed from all accounts.`,
      )
    ) {
      return;
    }
    try {
      const res = await accountApi.deleteTag(tagId);
      if (!res.success) throw new Error(res.error);
    } catch (err: any) {
      // Даже если ошибка, всё равно убираем тег из UI (он уже удалён или не существует)
      console.error("Delete tag error (ignored):", err);
    } finally {
      // Убираем тег из состояния в любом случае
      setAllTags((prev) => prev.filter((t) => t.id !== tagId));
      if (accountTagIds.has(tagId)) {
        setAccountTagIds((prev) => {
          const newSet = new Set(prev);
          newSet.delete(tagId);
          return newSet;
        });
        window.location.reload();
      }
    }
  };

  const handleCreateTag = async () => {
    if (!newTagName.trim()) return;
    setCreating(true);
    try {
      const createRes = await accountApi.createTag(
        newTagName.trim(),
        newTagColor,
      );
      if (!createRes.success) throw new Error(createRes.error);
      const newTag = createRes.data!;
      setAllTags((prev) => [...prev, newTag]);
      const attachRes = await accountApi.addTagToAccount(
        account.accountName,
        newTag.id,
      );
      if (!attachRes.success) throw new Error(attachRes.error);
      setAccountTagIds((prev) => new Set(prev).add(newTag.id));
      setNewTagName("");
      setNewTagColor(
        PRESET_COLORS[Math.floor(Math.random() * PRESET_COLORS.length)],
      );
      onTagsUpdated();
    } catch (err: any) {
      console.error(err);
      alert(err.message);
    } finally {
      setCreating(false);
    }
  };

  const getRandomColor = () =>
    setNewTagColor(
      PRESET_COLORS[Math.floor(Math.random() * PRESET_COLORS.length)],
    );

  if (!isOpen) return null;

  return createPortal(
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
      onClick={onClose}
    >
      <div
        className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[85vh] flex flex-col overflow-hidden border border-gray-700"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex justify-between items-center p-5 border-b border-gray-700">
          <div>
            <h2 className="text-xl font-semibold text-white flex items-center gap-2">
              <Tag className="w-5 h-5 text-purple-400" />
              Manage tags for {account.accountName}
            </h2>
            <p className="text-xs text-gray-400 mt-1">
              Attach or detach tags, create new tags, or delete existing tags
            </p>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-white transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-5 space-y-6">
          {loading ? (
            <div className="flex justify-center py-12">
              <Loader2 className="animate-spin text-purple-400" size={32} />
            </div>
          ) : error ? (
            <div className="flex items-center gap-2 text-red-400 justify-center py-8">
              <AlertCircle size={20} />
              <span>{error}</span>
            </div>
          ) : (
            <>
              {/* Existing tags list */}
              <div>
                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
                  <Tag className="w-4 h-4 text-purple-400" />
                  All tags
                </h3>
                <div className="space-y-2 max-h-64 overflow-y-auto pr-2">
                  {allTags.length === 0 && (
                    <p className="text-sm text-gray-500 text-center py-4">
                      No tags created yet.
                    </p>
                  )}
                  {allTags.map((tag) => (
                    <div
                      key={tag.id}
                      className="flex items-center justify-between gap-3 p-2 rounded-lg hover:bg-gray-800"
                    >
                      <label className="flex items-center gap-3 flex-1 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={accountTagIds.has(tag.id)}
                          onChange={() =>
                            handleToggleTag(tag.id, accountTagIds.has(tag.id))
                          }
                          className="w-4 h-4 rounded border-gray-600 text-purple-500 focus:ring-purple-500 bg-gray-700 cursor-pointer"
                        />
                        <TagChip tag={tag} small />
                      </label>
                      <div className="flex gap-1">
                        <button
                          onClick={() => setEditingTag(tag)}
                          className="text-gray-500 hover:text-blue-400 transition-colors p-1"
                          title="Edit tag"
                        >
                          <Pencil size={14} />
                        </button>
                        <button
                          onClick={() => handleDeleteTag(tag.id, tag.name)}
                          className="text-gray-500 hover:text-red-400 transition-colors p-1"
                          title="Delete tag"
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Create new tag */}
              <div className="border-t border-gray-700 pt-4">
                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
                  <Plus className="w-4 h-4 text-purple-400" />
                  <p className="text-sm font-medium text-gray-300">
                    Create new tag
                  </p>
                </h3>
                <div className="flex flex-wrap gap-3 items-end">
                  <div className="flex-1 min-w-[150px]">
                    <input
                      type="text"
                      value={newTagName}
                      onChange={(e) => setNewTagName(e.target.value)}
                      placeholder="Tag name"
                      className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-500 focus:outline-none focus:ring-2 focus:ring-purple-500"
                      disabled={creating}
                    />
                  </div>
                  <div className="flex gap-2 items-center">
                    <div className="relative">
                      <input
                        type="color"
                        value={newTagColor}
                        onChange={(e) => setNewTagColor(e.target.value)}
                        className="w-9 h-9 rounded-lg cursor-pointer bg-gray-800 border border-gray-700"
                        disabled={creating}
                      />
                    </div>
                    <button
                      onClick={getRandomColor}
                      className="px-3 py-1.5 text-xs bg-gray-700 rounded-lg hover:bg-gray-600 transition-colors  text-white"
                      disabled={creating}
                    >
                      Random
                    </button>
                    <button
                      onClick={handleCreateTag}
                      disabled={creating || !newTagName.trim()}
                      className="inline-flex items-center gap-1.5 px-4 py-1.5 bg-purple-600 hover:bg-purple-700 rounded-lg text-sm font-medium text-white transition-colors "
                    >
                      {creating ? (
                        <Loader2 size={14} className="animate-spin" />
                      ) : (
                        <Plus size={14} />
                      )}
                      Create
                    </button>
                  </div>
                </div>
              </div>
            </>
          )}
        </div>

        {/* Footer */}
        <div className="p-5 border-t border-gray-700 flex justify-end">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm text-white transition-colors"
          >
            Close
          </button>
        </div>
      </div>
      {editingTag && (
        <EditTagModal
          tag={editingTag}
          isOpen={!!editingTag}
          onClose={() => setEditingTag(null)}
          onSaved={handleEditSaved}
        />
      )}
    </div>,
    document.body,
  );
}

// EditTagModal (локальный компонент)
function EditTagModal({
  tag,
  isOpen,
  onClose,
  onSaved,
}: {
  tag: TagType;
  isOpen: boolean;
  onClose: () => void;
  onSaved: (updatedTag: TagType) => void;
}) {
  const [name, setName] = useState(tag.name);
  const [color, setColor] = useState(tag.color);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen) {
      setName(tag.name);
      setColor(tag.color);
    }
  }, [isOpen, tag]);

  const handleSave = async () => {
    if (!name.trim()) return;
    setLoading(true);
    try {
      const res = await accountApi.updateTag(tag.id, {
        name: name.trim(),
        color,
      });
      if (!res.success) throw new Error(res.error);
      onSaved(res.data!);
      onClose();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  return createPortal(
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
      onClick={onClose}
    >
      <div
        className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-md border border-gray-700"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex justify-between items-center p-4 border-b border-gray-700">
          <h3 className="text-lg font-semibold text-white">Edit tag</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-white">
            <X size={18} />
          </button>
        </div>
        <div className="p-4 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">
              Name
            </label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:ring-2 focus:ring-purple-500"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-1">
              Color
            </label>
            <div className="flex gap-2 items-center">
              <input
                type="color"
                value={color}
                onChange={(e) => setColor(e.target.value)}
                className="w-10 h-10 rounded cursor-pointer bg-gray-800 border border-gray-700"
              />
              <button
                onClick={() =>
                  setColor(
                    PRESET_COLORS[
                      Math.floor(Math.random() * PRESET_COLORS.length)
                    ],
                  )
                }
                className="px-3 py-1.5 text-xs bg-gray-700 rounded-lg hover:bg-gray-600 text-white"
              >
                Random
              </button>
            </div>
          </div>
        </div>
        <div className="flex justify-end gap-3 p-4 border-t border-gray-700">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-gray-700 text-gray-100 hover:bg-gray-600 rounded-lg text-sm"
          >
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={loading}
            className="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-gray-100 rounded-lg text-sm flex items-center gap-2"
          >
            {loading && <Loader2 size={14} className="animate-spin" />}
            Save
          </button>
        </div>
      </div>
    </div>,
    document.body,
  );
}
