// components/inventory/SellItemRow.tsx
import { getItemRarityFromTags, getRarityBgColor } from "@/shared/utils/rarity";
import { SelectedItemWithPrice } from "@/types";
import { DollarSign, Loader2, TrendingUp, TrendingDown } from "lucide-react";

interface SellItemRowProps {
  item: SelectedItemWithPrice;
  isLoading: boolean;
  isPending: boolean;
  isSuccess: boolean;
  isError: boolean;
  onPriceChange: (assetId: string, price: string) => void;
  onPriceMinusOneCent: (assetId: string, currentPrice: number) => void;
  onOpenPriceModal: (
    item: SelectedItemWithPrice,
    type: "instant" | "market",
  ) => void;
  formatPrice: (price: number, prefix?: string, suffix?: string) => string;
}

export function SellItemRow({
  item,
  isLoading,
  isPending,
  isSuccess,
  isError,
  onPriceChange,
  onPriceMinusOneCent,
  onOpenPriceModal,
  formatPrice,
}: SellItemRowProps) {
  const rarity = getItemRarityFromTags(item);
  const rarityBg = getRarityBgColor(rarity);

  return (
    <div
      className={`p-3 rounded-lg border ${
        isSuccess
          ? "border-emerald-500 bg-emerald-500/10"
          : isError
            ? "border-red-500 bg-red-500/10"
            : isPending
              ? "border-yellow-500 bg-yellow-500/10"
              : `border-gray-700 ${rarityBg}`
      }`}
    >
      <div className="flex items-center gap-3">
        {/* Item Image */}
        <div className="w-12 h-12 flex-shrink-0">
          <img
            src={`https://community.cloudflare.steamstatic.com/economy/image/${item.icon_url}`}
            alt={item.market_hash_name}
            className="w-full h-full object-contain"
            onError={(e) => {
              e.currentTarget.src =
                "https://steamcommunity.com/images/icon_loading.gif";
            }}
          />
        </div>

        {/* Item Info */}
        <div className="flex-1 min-w-0">
          <div
            className="font-medium text-white truncate"
            title={item.market_hash_name}
          >
            {item.market_hash_name}
            {isSuccess && (
              <span className="ml-2 text-xs text-emerald-400">✓ Listed</span>
            )}
            {isError && (
              <span className="ml-2 text-xs text-red-400">✗ Failed</span>
            )}
            {isPending && (
              <span className="ml-2 text-xs text-yellow-400">
                ⟳ Processing...
              </span>
            )}
          </div>
          <div className="flex gap-2 mt-1">
            {isLoading ? (
              <div className="flex items-center gap-1">
                <Loader2 size={12} className="animate-spin text-gray-400" />
                <span className="text-xs text-gray-400">Loading prices...</span>
              </div>
            ) : item.priceLoaded ? (
              <div className="flex gap-2">
                <button
                  onClick={() => onOpenPriceModal(item, "instant")}
                  className="text-xs text-green-400 hover:text-green-300 cursor-pointer transition-colors flex items-center gap-1"
                >
                  <TrendingUp size={10} />
                  Instant:{" "}
                  {formatPrice(
                    item.instantSellPrice,
                    item.fullOrderSpread?.price_suffix === ""
                      ? item.fullOrderSpread?.price_prefix
                      : "",
                    item.fullOrderSpread?.price_suffix,
                  )}
                </button>
                <button
                  onClick={() => onOpenPriceModal(item, "market")}
                  className="text-xs text-red-400 hover:text-red-300 cursor-pointer transition-colors flex items-center gap-1"
                >
                  <TrendingDown size={10} />
                  Market:{" "}
                  {formatPrice(
                    item.marketPrice,
                    item.fullOrderSpread?.price_suffix === ""
                      ? item.fullOrderSpread?.price_prefix
                      : "",
                    item.fullOrderSpread?.price_suffix,
                  )}
                </button>
              </div>
            ) : (
              <span className="text-xs text-red-400">
                Failed to load prices
              </span>
            )}
          </div>
        </div>

        {/* Price Input */}
        <div className="flex items-center gap-2">
          <div className="relative w-28">
            {item.fullOrderSpread?.price_prefix === "$" &&
            !item.fullOrderSpread?.price_suffix ? (
              <DollarSign className="absolute left-2 top-1/2 transform -translate-y-1/2 w-3 h-3 text-gray-400" />
            ) : (
              <p className="absolute left-2.5 top-2/5 transform -translate-y-1/2 w-4 h-4 text-gray-400">
                {item.fullOrderSpread?.price_suffix === ""
                  ? item.fullOrderSpread?.price_prefix[0]
                  : item.fullOrderSpread?.price_suffix[0]}
              </p>
            )}
            <input
              value={item.customPrice}
              onChange={(e) => onPriceChange(item.assetid, e.target.value)}
              disabled={
                isLoading || !item.priceLoaded || isSuccess || isPending
              }
              className="w-full pl-7 pr-2 py-1.5 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-emerald-500 disabled:opacity-50"
            />
          </div>
          {item.priceLoaded && !isSuccess && !isPending && (
            <button
              onClick={() =>
                onPriceMinusOneCent(item.assetid, item.instantSellPrice)
              }
              className="px-2 py-1.5 bg-gray-700 hover:bg-gray-600 rounded-lg text-xs transition-colors cursor-pointer"
              title="Set price 0.01 lower than instant sell"
            >
              -0.01
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
