import { useState, useMemo } from "react";
import { SteamAccountInfo } from "../types";
import { statusPriority } from "../constants/mainPage.constants";
import {
  BalanceSortField,
  AccountsSortField,
  BansSortField,
  InventorySortField,
} from "../types/index.ts";

export const useMainPageSort = (filteredAccounts: SteamAccountInfo[]) => {
  const [balanceSortField, setBalanceSortField] =
    useState<BalanceSortField>("login");
  const [balanceSortOrder, setBalanceSortOrder] = useState<"asc" | "desc">(
    "asc",
  );
  const [accountsSortField, setAccountsSortField] =
    useState<AccountsSortField>("login");
  const [accountsSortOrder, setAccountsSortOrder] = useState<"asc" | "desc">(
    "asc",
  );
  const [bansSortField, setBansSortField] = useState<BansSortField>("login");
  const [bansSortOrder, setBansSortOrder] = useState<"asc" | "desc">("asc");
  const [inventorySortField, setInventorySortField] =
    useState<InventorySortField>("login");
  const [inventorySortOrder, setInventorySortOrder] = useState<"asc" | "desc">(
    "asc",
  );

  const handleBalanceSort = (field: BalanceSortField) => {
    if (balanceSortField === field) {
      setBalanceSortOrder(balanceSortOrder === "asc" ? "desc" : "asc");
    } else {
      setBalanceSortField(field);
      setBalanceSortOrder("asc");
    }
  };

  const handleAccountsSort = (field: AccountsSortField) => {
    if (accountsSortField === field) {
      setAccountsSortOrder(accountsSortOrder === "asc" ? "desc" : "asc");
    } else {
      setAccountsSortField(field);
      setAccountsSortOrder("asc");
    }
  };

  const handleBansSort = (field: BansSortField) => {
    if (bansSortField === field) {
      setBansSortOrder(bansSortOrder === "asc" ? "desc" : "asc");
    } else {
      setBansSortField(field);
      setBansSortOrder("asc");
    }
  };

  const handleInventorySort = (field: InventorySortField) => {
    if (inventorySortField === field) {
      setInventorySortOrder(inventorySortOrder === "asc" ? "desc" : "asc");
    } else {
      setInventorySortField(field);
      setInventorySortOrder("asc");
    }
  };
  const getMarketPriority = (acc: any) => {
    if (acc.market.open) return 1; // открыт сейчас
    if (acc.market.willOpen && !acc.market.canOpenByPurchase) return 2; // откроется позже
    if (acc.market.canOpenByPurchase && !acc.market.willOpen) return 3; // можно открыть покупкой
    return 4; // заблокирован полностью
  };

  const sortedBalanceAccounts = useMemo(() => {
    const accountsWithWallet = filteredAccounts.filter(
      (account) => account.hasWallet && account.balance !== null,
    );
    const sorted = [...accountsWithWallet];
    sorted.sort((a, b) => {
      let comparison = 0;
      switch (balanceSortField) {
        case "login":
          comparison = a.accountName.localeCompare(b.accountName);
          break;
        case "balance":
          comparison =
            (a.balance?.usdbalance || 0) - (b.balance?.usdbalance || 0);
          break;
        case "activeListings":
          comparison = (a.activeListings || 0) - (b.activeListings || 0);
          break;
        case "activeOrders":
          comparison = (a.activeOrders || 0) - (b.activeOrders || 0);
          break;
        case "marketStatus":
          comparison = getMarketPriority(a) - getMarketPriority(b);
          break;
        case "lastUpdated":
          comparison =
            (a.balance?.lastUpdated
              ? new Date(a.balance.lastUpdated).getTime()
              : 0) -
            (b.balance?.lastUpdated
              ? new Date(b.balance.lastUpdated).getTime()
              : 0);
          break;
      }
      return balanceSortOrder === "asc" ? comparison : -comparison;
    });
    return sorted;
  }, [filteredAccounts, balanceSortField, balanceSortOrder]);

  const sortedAccountsList = useMemo(() => {
    const sorted = [...filteredAccounts];
    sorted.sort((a, b) => {
      let comparison = 0;
      switch (accountsSortField) {
        case "login":
          comparison = a.accountName.localeCompare(b.accountName);
          break;
        case "status":
          comparison =
            (statusPriority[a.status] || 99) - (statusPriority[b.status] || 99);
          break;
        case "proxy":
          comparison = (a.ipAddress || "").localeCompare(b.ipAddress || "");
          break;
        case "limit":
          comparison = (a.limited ? 1 : 0) - (b.limited ? 1 : 0);
          break;
      }
      return accountsSortOrder === "asc" ? comparison : -comparison;
    });
    return sorted;
  }, [filteredAccounts, accountsSortField, accountsSortOrder]);

  const accountsWithBans = filteredAccounts.filter(
    (a) => a.bans.vac || a.bans.game || a.bans.community || a.bans.kt,
  );

  const sortedBansAccounts = useMemo(() => {
    const sorted = [...accountsWithBans];
    sorted.sort((a, b) => {
      let comparison = 0;
      switch (bansSortField) {
        case "login":
          comparison = a.accountName.localeCompare(b.accountName);
          break;
        case "vac":
          comparison = (a.bans.vac ? 1 : 0) - (b.bans.vac ? 1 : 0);
          break;
        case "game":
          comparison = (a.bans.game ? 1 : 0) - (b.bans.game ? 1 : 0);
          break;
        case "community":
          comparison = (a.bans.community ? 1 : 0) - (b.bans.community ? 1 : 0);
          break;
        case "total":
          comparison =
            (a.bans.vac ? 1 : 0) +
            (a.bans.game ? 1 : 0) +
            (a.bans.community ? 1 : 0) -
            ((b.bans.vac ? 1 : 0) +
              (b.bans.game ? 1 : 0) +
              (b.bans.community ? 1 : 0));
          break;
      }
      return bansSortOrder === "asc" ? comparison : -comparison;
    });
    return sorted;
  }, [accountsWithBans, bansSortField, bansSortOrder]);

  return {
    balanceSortField,
    balanceSortOrder,
    accountsSortField,
    accountsSortOrder,
    bansSortField,
    bansSortOrder,
    inventorySortField,
    inventorySortOrder,
    handleBalanceSort,
    handleAccountsSort,
    handleBansSort,
    handleInventorySort,
    sortedBalanceAccounts,
    sortedAccountsList,
    sortedBansAccounts,
    accountsWithBans,
  };
};
