// components/Market/CancelOrderModal.tsx
import { AlertTriangle } from "lucide-react";
import { Modal } from "../Modal";
import { MarketOrder } from "../../types";

interface CancelOrderModalProps {
  isOpen: boolean;
  order: MarketOrder | null;
  onClose: () => void;
  onConfirm: () => void;
  isProcessing: boolean;
}

const formatPrice = (price: string | null) => {
  if (!price) return "N/A";
  return price;
};

export function CancelOrderModal({
  isOpen,
  order,
  onClose,
  onConfirm,
  isProcessing,
}: CancelOrderModalProps) {
  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Cancel Buy Order"
      icon={<AlertTriangle className="w-5 h-5 text-red-400" />}
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors"
          >
            No, Keep
          </button>
          <button
            onClick={onConfirm}
            disabled={isProcessing}
            className="px-4 py-2 bg-red-600 hover:bg-red-700 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {isProcessing ? "Cancelling..." : "Yes, Cancel"}
          </button>
        </div>
      }
      maxWidth="md"
    >
      <div className="p-4">
        <div className="flex items-center gap-4 mb-4">
          {order?.image && (
            <img
              src={order.image}
              alt={order.title}
              className="w-16 h-16 rounded object-cover"
              onError={(e) => (e.currentTarget.style.display = "none")}
            />
          )}
          <div>
            <h3 className="font-semibold text-white">{order?.title}</h3>
            <p className="text-sm text-gray-400">{order?.game}</p>
          </div>
        </div>

        <div className="bg-gray-800/60 rounded-lg p-4 mb-4">
          <div className="flex justify-between mb-2">
            <span className="text-gray-400">Price per unit:</span>
            <span className="text-emerald-400 font-medium">
              {formatPrice(order?.price_per_unit || null)}
            </span>
          </div>
          <div className="flex justify-between mb-2">
            <span className="text-gray-400">Quantity:</span>
            <span className="text-gray-300">{order?.quantity || "N/A"}</span>
          </div>
          <div className="flex justify-between">
            <span className="text-gray-400">Total value:</span>
            <span className="text-emerald-400 font-medium">
              {formatPrice(order?.total_value || null)}
            </span>
          </div>
        </div>

        <p className="text-center text-gray-300">
          Are you sure you want to cancel this buy order?
        </p>
        <p className="text-center text-sm text-gray-400 mt-2">
          This action cannot be undone.
        </p>
      </div>
    </Modal>
  );
}
