// pages/ActivityPage.tsx
import { useState, useEffect, useCallback } from "react";
import {
  Play,
  Database,
  ShoppingCart,
  Gift,
  Award,
  Image,
  Ticket,
  Package,
  Send,
  DollarSign,
  ShoppingBag,
} from "lucide-react";
import { SteamAccountInfo, AllAccountsData } from "../types";
import { FarmingManagerModal } from "@/components/Activity/FarmingModalManager";
import { PurchaseItemModal } from "@/components/Activity/PurchaseItemModal";
import { AddFreeGamesModal } from "@/components/Activity/AddFreeGamesModal";
import { CreateBadgeModal } from "@/components/Activity/CreateBadgeModal";
import { PurchaseBackgroundModal } from "@/components/Activity/PurchaseBackgroundModal";
import { ActivateVouchersModal } from "@/components/Activity/ActivateVouchersModal";
import { CollectItemsFromBotsModal } from "@/components/Activity/CollectItemsFromBotsModal";
import { SendTradeToBotsModal } from "@/components/Activity/SendTradeToBotsModal";
import { accountApi } from "@/services/api";
import { MassSellItemsModal } from "@/components/Activity/MassSellItemsModal";
import { BuyCs2ItemModal } from "@/components/Activity/BuyCs2ItemModal";

interface ActivityPageProps {
  accounts: SteamAccountInfo[];
}

export function ActivityPage({ accounts }: ActivityPageProps) {
  const [farmingData, setFarmingData] = useState<AllAccountsData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loadingFarming, setLoadingFarming] = useState(false);
  // Modal states
  const [isFarmingManagerOpen, setIsFarmingManagerOpen] = useState(false);
  const [isPurchaseModalOpen, setIsPurchaseModalOpen] = useState(false);
  const [isFreeGamesModalOpen, setIsFreeGamesModalOpen] = useState(false);
  const [isBadgeModalOpen, setIsBadgeModalOpen] = useState(false);
  const [isBackgroundModalOpen, setIsBackgroundModalOpen] = useState(false);
  const [isVouchersModalOpen, setIsVouchersModalOpen] = useState(false);
  const [isSendTradeModalOpen, setIsSendTradeModalOpen] = useState(false);
  const [isCollectItemsModalOpen, setIsCollectItemsModalOpen] = useState(false);
  const [isMassSellModalOpen, setIsMassSellModalOpen] = useState(false);
  const [isBuyCs2ModalOpen, setIsBuyCs2ModalOpen] = useState(false);
  const isFarmingActive = farmingData?.isFarming ?? false;
  const activeCount = farmingData?.farming.length ?? 0;
  const queueCount = farmingData?.queue.length ?? 0;

  const fetchFarmingData = useCallback(async () => {
    setLoadingFarming(true);
    try {
      const result = await accountApi.getMassPlayGameInfo();
      if (result.data) {
        setFarmingData(result.data);
        setError(null);
      } else {
        setError(result.error || "Не удалось загрузить статус фарма");
      }
    } catch (err) {
      setError("Ошибка загрузки данных фарма");
    } finally {
      setLoadingFarming(false);
    }
  }, []);

  useEffect(() => {
    fetchFarmingData();
    const interval = setInterval(() => {
      fetchFarmingData();
    }, 10000);
    return () => clearInterval(interval);
  }, [fetchFarmingData]);

  return (
    <div className="max-w-6xl mx-auto">
      <h1 className="text-2xl font-bold mb-6">Steam Activity Management</h1>

      {/* Farming Activity Section */}
      <div className="bg-gradient-to-r from-indigo-900/20 to-purple-900/20 rounded-2xl p-6 mb-6 backdrop-blur-sm border border-indigo-700/30">
        <div className="flex items-start justify-between">
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-2">
              <Database className="w-5 h-5 text-indigo-400" />
              <h2 className="text-lg font-semibold text-white">
                Farming Activity
              </h2>
              <div
                className={`ml-2 inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full text-xs font-medium ${
                  isFarmingActive
                    ? "bg-green-500/20 text-green-400"
                    : "bg-red-500/20 text-red-400"
                }`}
              >
                <div
                  className={`w-1.5 h-1.5 rounded-full ${
                    isFarmingActive ? "bg-green-400" : "bg-red-400"
                  }`}
                />
                {isFarmingActive ? "Active" : "Inactive"}
              </div>
            </div>
            {isFarmingActive && (
              <p className="text-sm text-gray-300 mb-1">
                Farming{" "}
                <span className="text-green-400 font-medium">
                  {activeCount}
                </span>{" "}
                accounts,{" "}
                <span className="text-yellow-400 font-medium">
                  {queueCount}
                </span>{" "}
                in queue
              </p>
            )}
            <p className="text-sm text-gray-300 mb-1">
              Automatically farm hours on selected Steam accounts
            </p>
            <p className="text-xs text-gray-400">
              Run multiple accounts simultaneously to increase Steam hours
            </p>
          </div>
          <button
            onClick={() => setIsFarmingManagerOpen(true)}
            className="cursor-pointer flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 rounded-lg text-sm font-medium transition-all shadow-lg hover:shadow-xl"
          >
            <Play className="w-4 h-4" />
            {isFarmingActive ? "Farming" : "Start"}
          </button>
        </div>
      </div>

      {/* Сетка карточек действий – без scale при наведении */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        {/* Add Free Games */}
        <div className="rounded-2xl bg-gradient-to-br from-blue-900/20 to-cyan-900/20 border border-blue-700/30 p-6 transition-all hover:shadow-blue-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-blue-500/20 rounded-xl">
                <Gift className="w-6 h-6 text-blue-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Add Free Games
                </h3>
                <p className="text-sm text-gray-300">
                  Add all free Steam games
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Automatically claim all available free games
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsFreeGamesModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <Gift className="w-4 h-4" />
              Add Games
            </button>
          </div>
        </div>

        {/* Create Badge */}
        <div className="rounded-2xl bg-gradient-to-br from-purple-900/20 to-pink-900/20 border border-purple-700/30 p-6 transition-all hover:shadow-purple-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-purple-500/20 rounded-xl">
                <Award className="w-6 h-6 text-purple-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Create Badge
                </h3>
                <p className="text-sm text-gray-300">Create Steam game badge</p>
                <p className="text-xs text-gray-400 mt-1">
                  Craft a badge for any Steam game
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsBadgeModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-purple-600 hover:bg-purple-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <Award className="w-4 h-4" />
              Create Badge
            </button>
          </div>
        </div>

        {/* Purchase Background */}
        <div className="rounded-2xl bg-gradient-to-br from-pink-900/20 to-rose-900/20 border border-pink-700/30 p-6 transition-all hover:shadow-pink-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-pink-500/20 rounded-xl">
                <Image className="w-6 h-6 text-pink-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Profile Background
                </h3>
                <p className="text-sm text-gray-300">
                  Buy random profile background
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Purchase a random Steam profile background
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsBackgroundModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-pink-600 hover:bg-pink-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <Image className="w-4 h-4" />
              Purchase
            </button>
          </div>
        </div>

        {/* Activate Vouchers */}
        <div className="rounded-2xl bg-gradient-to-br from-orange-900/20 to-amber-900/20 border border-orange-700/30 p-6 transition-all hover:shadow-orange-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-orange-500/20 rounded-xl">
                <Ticket className="w-6 h-6 text-orange-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Activate Vouchers
                </h3>
                <p className="text-sm text-gray-300">
                  Activate Steam wallet codes
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  For limited accounts without wallet funds
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsVouchersModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-orange-600 hover:bg-orange-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <Ticket className="w-4 h-4" />
              Activate
            </button>
          </div>
        </div>

        {/* Send Random Trades to Bots */}
        <div className="rounded-2xl bg-gradient-to-br from-blue-900/20 to-indigo-900/20 border border-blue-700/30 p-6 transition-all hover:shadow-blue-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-blue-500/20 rounded-xl">
                <Send className="w-6 h-6 text-blue-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Send Random Trades
                </h3>
                <p className="text-sm text-gray-300">
                  Send random items to your other bots
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Distribute inventory items randomly among selected bots
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsSendTradeModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <Send className="w-4 h-4" />
              Send Trades
            </button>
          </div>
        </div>

        {/* Collect Items from Bots */}
        <div className="rounded-2xl bg-gradient-to-br from-emerald-900/20 to-teal-900/20 border border-emerald-700/30 p-6 transition-all hover:shadow-emerald-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-emerald-500/20 rounded-xl">
                <Package className="w-6 h-6 text-emerald-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Collect Items
                </h3>
                <p className="text-sm text-gray-300">
                  Gather all items from bots into one account
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Transfers complete inventories to a single target
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsCollectItemsModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <Package className="w-4 h-4" />
              Collect
            </button>
          </div>
        </div>

        {/* Mass Sell Items */}
        <div className="rounded-2xl bg-gradient-to-br from-amber-900/20 to-yellow-900/20 border border-amber-700/30 p-6 transition-all hover:shadow-amber-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-amber-500/20 rounded-xl">
                <DollarSign className="w-6 h-6 text-amber-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">
                  Mass Sell Items
                </h3>
                <p className="text-sm text-gray-300">
                  Sell all marketable items from inventory
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Automatic price calculation based on market
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  – requires manual confirmation
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsMassSellModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-amber-600 hover:bg-amber-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <DollarSign className="w-4 h-4" />
              Sell Items
            </button>
          </div>
        </div>

        {/* Buy CS2 Item */}
        <div className="rounded-2xl bg-gradient-to-br from-cyan-900/20 to-blue-900/20 border border-cyan-700/30 p-6 transition-all hover:shadow-cyan-500/20">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div className="flex items-start gap-3">
              <div className="p-2 bg-cyan-500/20 rounded-xl">
                <ShoppingBag className="w-6 h-6 text-cyan-300" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-white">Buy CS2</h3>
                <p className="text-sm text-gray-300">
                  Automatically purchases CS2 for accounts
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Buying CS2 Prime on a no-limit account
                </p>
              </div>
            </div>
            <button
              onClick={() => setIsBuyCs2ModalOpen(true)}
              className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-cyan-600 hover:bg-cyan-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
            >
              <ShoppingBag className="w-4 h-4" />
              Buy Game
            </button>
          </div>
        </div>
      </div>

      {/* Marketplace Unlock Section – тоже убираем scale */}
      <div className="rounded-2xl bg-gradient-to-br from-green-900/20 to-emerald-900/20 border border-green-700/30 p-6 transition-all hover:shadow-green-500/20">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-start gap-3">
            <div className="p-2 bg-green-500/20 rounded-xl">
              <ShoppingCart className="w-6 h-6 text-green-300" />
            </div>
            <div>
              <h2 className="text-lg font-semibold text-white">
                Marketplace Unlock
              </h2>
              <p className="text-sm text-gray-300">
                Activate your Steam marketplace with the cheapest item
              </p>
              <p className="text-xs text-gray-400 mt-1">
                Purchase a cheap item to unlock marketplace access. After
                purchase, the marketplace will be available in 7 days.
              </p>
            </div>
          </div>
          <button
            onClick={() => setIsPurchaseModalOpen(true)}
            className="cursor-pointer flex items-center gap-2 px-5 py-2.5 bg-green-600 hover:bg-green-500 rounded-xl text-sm font-semibold text-white transition-all shadow-lg hover:shadow-xl active:scale-95"
          >
            <ShoppingCart className="w-4 h-4" />
            Purchase Item
          </button>
        </div>
      </div>

      {error && (
        <div className="p-3 bg-red-500/20 border border-red-500 rounded-lg text-red-300 text-sm">
          {error}
        </div>
      )}

      {/* Modals (без изменений) */}
      <FarmingManagerModal
        isOpen={isFarmingManagerOpen}
        onClose={() => setIsFarmingManagerOpen(false)}
        accounts={accounts}
      />
      <PurchaseItemModal
        isOpen={isPurchaseModalOpen}
        onClose={() => setIsPurchaseModalOpen(false)}
        accounts={accounts}
      />
      <AddFreeGamesModal
        isOpen={isFreeGamesModalOpen}
        onClose={() => setIsFreeGamesModalOpen(false)}
        accounts={accounts}
      />
      <CreateBadgeModal
        isOpen={isBadgeModalOpen}
        onClose={() => setIsBadgeModalOpen(false)}
        accounts={accounts}
      />
      <PurchaseBackgroundModal
        isOpen={isBackgroundModalOpen}
        onClose={() => setIsBackgroundModalOpen(false)}
        accounts={accounts}
      />
      <ActivateVouchersModal
        isOpen={isVouchersModalOpen}
        onClose={() => setIsVouchersModalOpen(false)}
        accounts={accounts}
      />
      <SendTradeToBotsModal
        isOpen={isSendTradeModalOpen}
        onClose={() => setIsSendTradeModalOpen(false)}
        accounts={accounts}
      />
      <CollectItemsFromBotsModal
        isOpen={isCollectItemsModalOpen}
        onClose={() => setIsCollectItemsModalOpen(false)}
        accounts={accounts}
      />
      <MassSellItemsModal
        isOpen={isMassSellModalOpen}
        onClose={() => setIsMassSellModalOpen(false)}
        accounts={accounts}
      />
      <BuyCs2ItemModal
        isOpen={isBuyCs2ModalOpen}
        onClose={() => setIsBuyCs2ModalOpen(false)}
        accounts={accounts}
      />
    </div>
  );
}
