// components/Market/MarketTabs.tsx
import { Package, ShoppingCart, Search, XCircle } from "lucide-react";

interface MarketTabsProps {
  activeTab: "listings" | "orders";
  onTabChange: (tab: "listings" | "orders") => void;
  listingsCount: number;
  ordersCount: number;
  searchQuery: string;
  onSearchChange: (value: string) => void;
  searchPlaceholder: string;
}

export function MarketTabs({
  activeTab,
  onTabChange,
  listingsCount,
  ordersCount,
  searchQuery,
  onSearchChange,
  searchPlaceholder,
}: MarketTabsProps) {
  return (
    <div className="flex justify-between items-center mb-6 border-b border-gray-700">
      <div className="flex gap-2">
        <button
          onClick={() => onTabChange("listings")}
          className={`px-4 py-2 text-sm font-medium transition-colors ${
            activeTab === "listings"
              ? "text-emerald-400 border-b-2 border-emerald-400"
              : "text-gray-400 hover:text-gray-300"
          }`}
        >
          <Package size={16} className="inline mr-2" />
          Active Listings ({listingsCount})
        </button>
        <button
          onClick={() => onTabChange("orders")}
          className={`px-4 py-2 text-sm font-medium transition-colors ${
            activeTab === "orders"
              ? "text-emerald-400 border-b-2 border-emerald-400"
              : "text-gray-400 hover:text-gray-300"
          }`}
        >
          <ShoppingCart size={16} className="inline mr-2" />
          Buy Orders ({ordersCount})
        </button>
      </div>

      <div className="relative pb-2">
        <Search className="absolute left-3 top-3/7 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
        <input
          type="text"
          placeholder={searchPlaceholder}
          value={searchQuery}
          onChange={(e) => onSearchChange(e.target.value)}
          className="pl-9 pr-4 py-1.5 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-emerald-500 w-64"
        />
        {searchQuery && (
          <button
            onClick={() => onSearchChange("")}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-300"
          >
            <XCircle size={14} />
          </button>
        )}
      </div>
    </div>
  );
}
