// pages/TradePage.tsx
import { useState, useEffect, useRef } from "react";
import { RefreshCw } from "lucide-react";
import { TradeOffer, TradeOfferStatus, SteamAccountInfo } from "../types";
import { accountApi } from "@/services/api";
import { useAccountLogin } from "@/hooks/use-account-login";
import { AuthenticationRequired } from "@/components/AuthenticationRequired";

interface TradesPageProps {
  account: SteamAccountInfo | null;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
}

interface RawTradeOffer {
  id: string;
  state: number;
  message: string;
  itemsToGive: RawItem[];
  itemsToReceive: RawItem[];
  isOurOffer: boolean;
  created: string;
  updated: string;
  expires: string;
  partner: { accountid: number };
}

interface RawItem {
  appid: number;
  contextid: string;
  assetid: string;
  name: string;
  icon_url: string;
  amount: number;
}

const mapStateToStatus = (state: number): TradeOfferStatus => {
  switch (state) {
    case 2:
      return TradeOfferStatus.Active;
    case 3:
      return TradeOfferStatus.Completed;
    case 4:
      return TradeOfferStatus.Declined;
    case 5:
      return TradeOfferStatus.Cancelled;
    case 7:
      return TradeOfferStatus.InEscrow;
    default:
      return TradeOfferStatus.Active;
  }
};

const transformTradeOffer = (raw: RawTradeOffer): TradeOffer => ({
  tradeId: raw.id,
  partnerName: `User ${raw.partner.accountid}`,
  partnerAvatar: "",
  message: raw.message,
  itemsToGive: raw.itemsToGive.map((item) => ({
    name: item.name,
    assetid: item.assetid,
    amount: item.amount,
    icon_url: item.icon_url,
  })),
  itemsToReceive: raw.itemsToReceive.map((item) => ({
    name: item.name,
    assetid: item.assetid,
    amount: item.amount,
    icon_url: item.icon_url,
  })),
  status: mapStateToStatus(raw.state),
  timeCreated: new Date(raw.created).getTime() / 1000,
  timeUpdated: new Date(raw.updated).getTime() / 1000,
  isOurOffer: raw.isOurOffer,
});

const formatDate = (timestamp: number): string => {
  const date = new Date(timestamp * 1000);
  return date.toLocaleString();
};

const getStatusText = (status: TradeOfferStatus): string => {
  switch (status) {
    case TradeOfferStatus.Active:
      return "Active";
    case TradeOfferStatus.InEscrow:
      return "In Escrow";
    case TradeOfferStatus.Completed:
      return "Completed";
    case TradeOfferStatus.Declined:
      return "Declined";
    case TradeOfferStatus.Cancelled:
      return "Cancelled";
    default:
      return "Unknown";
  }
};

const getStatusColor = (status: TradeOfferStatus): string => {
  switch (status) {
    case TradeOfferStatus.Active:
      return "text-green-400 bg-green-400/10";
    case TradeOfferStatus.InEscrow:
      return "text-yellow-400 bg-yellow-400/10";
    case TradeOfferStatus.Completed:
      return "text-blue-400 bg-blue-400/10";
    case TradeOfferStatus.Declined:
    case TradeOfferStatus.Cancelled:
      return "text-red-400 bg-red-400/10";
    default:
      return "text-gray-400 bg-gray-400/10";
  }
};

export function TradePage({ account, onUpdateAccount }: TradesPageProps) {
  const [activeOffers, setActiveOffers] = useState<TradeOffer[]>([]);
  const [historyOffers, setHistoryOffers] = useState<TradeOffer[]>([]);
  const [loadingActive, setLoadingActive] = useState(false);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [processingIds, setProcessingIds] = useState<Set<string>>(new Set());

  const { loggingIn, handleLogin, loginError } = useAccountLogin({
    account,
    onUpdateAccount,
  });

  const currentAccountNameRef = useRef<string | null>(null);

  // Загрузка активных трейдов
  const fetchActiveOffers = async () => {
    if (!account || !account.cookies) return;
    const accountName = account.accountName;
    currentAccountNameRef.current = accountName;
    setLoadingActive(true);
    setError(null);
    const result = await accountApi.getActiveTradeOffers(accountName);
    if (currentAccountNameRef.current !== accountName) return;
    if (result.data && Array.isArray(result.data)) {
      //@ts-ignore
      const transformed = result.data.map(transformTradeOffer);
      setActiveOffers(transformed);
    } else {
      setActiveOffers([]);
      if (result.error) setError(result.error);
    }
    setLoadingActive(false);
  };

  // Загрузка истории (все завершённые/отменённые трейды от даты создания аккаунта)
  const fetchHistoryOffers = async () => {
    if (!account || !account.cookies) return;
    const accountName = account.accountName;
    currentAccountNameRef.current = accountName;
    setLoadingHistory(true);
    setError(null);
    // Формируем дату начала: memberSince аккаунта или пустая строка (все трейды)
    let dateString = "";
    const memberSince = account.profileData?.memberSince;
    if (memberSince) {
      const d = new Date(memberSince);
      d.setDate(d.getDate() + 1);
      if (!isNaN(d.getTime())) {
        dateString = d.toISOString().split("T")[0];
      }
    }
    const result = await accountApi.getHistoricalTradeOffers(
      accountName,
      dateString,
    );
    if (currentAccountNameRef.current !== accountName) return;
    if (result.data && Array.isArray(result.data)) {
      //@ts-ignore
      const transformed = result.data.map(transformTradeOffer);
      setHistoryOffers(transformed);
    } else {
      setHistoryOffers([]);
      if (result.error) setError(result.error);
    }
    setLoadingHistory(false);
  };

  // Принятие входящего трейда
  const handleAccept = async (tradeId: string) => {
    if (!account || processingIds.has(tradeId)) return;
    if (!account.cookies) {
      setError("Account is not logged in. Please login first.");
      return;
    }
    setProcessingIds((prev) => new Set(prev).add(tradeId));
    const result = await accountApi.acceptOffer(account.accountName, tradeId);
    if (result.success) {
      setActiveOffers((prev) => prev.filter((o) => o.tradeId !== tradeId));
      await fetchHistoryOffers(); // обновляем историю
    } else {
      setError(result.error || "Failed to accept trade offer");
    }
    setProcessingIds((prev) => {
      const newSet = new Set(prev);
      newSet.delete(tradeId);
      return newSet;
    });
  };

  // Отклонение входящего или отмена своего трейда
  const handleDecline = async (tradeId: string) => {
    if (!account || processingIds.has(tradeId)) return;
    if (!account.cookies) {
      setError("Account is not logged in. Please login first.");
      return;
    }
    setProcessingIds((prev) => new Set(prev).add(tradeId));
    const result = await accountApi.declineOffer(account.accountName, tradeId);
    if (result.success) {
      setActiveOffers((prev) => prev.filter((o) => o.tradeId !== tradeId));
      await fetchHistoryOffers();
    } else {
      setError(result.error || "Failed to decline/cancel trade offer");
    }
    setProcessingIds((prev) => {
      const newSet = new Set(prev);
      newSet.delete(tradeId);
      return newSet;
    });
  };

  // Загружаем активные трейды и историю при монтировании / смене аккаунта
  useEffect(() => {
    if (!account?.cookies) return;
    fetchActiveOffers();
    fetchHistoryOffers();
    const interval = setInterval(fetchActiveOffers, 10000);
    return () => clearInterval(interval);
  }, [account]);

  // Сброс при смене аккаунта
  useEffect(() => {
    setActiveOffers([]);
    setHistoryOffers([]);
    setError(null);
    setProcessingIds(new Set());
    currentAccountNameRef.current = account?.accountName || null;
  }, [account]);

  const renderItems = (
    items: TradeOffer["itemsToGive"],
    type: "give" | "receive",
  ) => {
    if (!items.length) return null;
    const colorClass = type === "give" ? "text-red-300" : "text-green-300";
    const arrow = type === "give" ? "➤ You give:" : "◀ You receive:";
    return (
      <div
        className={`text-sm ${colorClass} mt-1 flex flex-wrap gap-2 items-center`}
      >
        <span>{arrow}</span>
        <div className="flex flex-wrap gap-2">
          {items.map((item, idx) => (
            <div
              key={idx}
              className="flex items-center gap-1 bg-gray-800/50 rounded px-2 py-0.5"
            >
              {item.icon_url && (
                <img
                  src={`https://community.akamai.steamstatic.com/economy/image/${item.icon_url}/32fx32f`}
                  alt={item.name}
                  className="w-5 h-5 object-contain"
                  onError={(e) => (e.currentTarget.style.display = "none")}
                />
              )}
              <span>{item.name}</span>
              {item?.amount! > 1 && (
                <span className="text-xs">x{item.amount}</span>
              )}
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderTradeOffer = (offer: TradeOffer, isHistory: boolean = false) => {
    // Определяем, какие кнопки показывать для активных трейдов
    let actionButtons = null;
    if (!isHistory && offer.status === TradeOfferStatus.Active) {
      if (!offer.isOurOffer!) {
        // Входящий активный трейд → обе кнопки
        actionButtons = (
          <div className="flex gap-2 flex-shrink-0">
            <button
              onClick={() => handleAccept(offer.tradeId)}
              disabled={processingIds.has(offer.tradeId)}
              className="px-3 py-1 bg-green-600 hover:bg-green-700 rounded text-sm transition-colors disabled:opacity-50 cursor-pointer"
            >
              Accept
            </button>
            <button
              onClick={() => handleDecline(offer.tradeId)}
              disabled={processingIds.has(offer.tradeId)}
              className="px-3 py-1 bg-red-600 hover:bg-red-700 rounded text-sm transition-colors disabled:opacity-50 cursor-pointer"
            >
              Decline
            </button>
          </div>
        );
      } else {
        // Исходящий активный трейд → только Cancel (Decline)
        actionButtons = (
          <div className="flex gap-2 flex-shrink-0">
            <button
              onClick={() => handleDecline(offer.tradeId)}
              disabled={processingIds.has(offer.tradeId)}
              className="px-3 py-1 bg-red-600 hover:bg-red-700 rounded text-sm transition-colors disabled:opacity-50 cursor-pointer"
            >
              Cancel
            </button>
          </div>
        );
      }
    }

    return (
      <div
        key={offer.tradeId}
        className="flex items-start gap-3 p-3 bg-gray-700/30 rounded-lg"
      >
        {offer.partnerAvatar && (
          <img
            src={offer.partnerAvatar}
            alt="avatar"
            className="w-10 h-10 rounded-full object-cover flex-shrink-0"
            onError={(e) => (e.currentTarget.style.display = "none")}
          />
        )}
        <div className="flex-1">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="font-medium">{offer.partnerName}</span>
            <span
              className={`text-xs px-2 py-0.5 rounded-full ${getStatusColor(offer.status)}`}
            >
              {getStatusText(offer.status)}
            </span>
            <span className="text-xs text-gray-400">
              {formatDate(offer.timeCreated)}
            </span>
          </div>
          {offer.message && (
            <div className="text-sm text-gray-300 mt-1">💬 {offer.message}</div>
          )}
          {renderItems(offer.itemsToGive, "give")}
          {renderItems(offer.itemsToReceive, "receive")}
          <div className="text-xs text-gray-400 mt-1">ID: {offer.tradeId}</div>
        </div>
        {actionButtons}
      </div>
    );
  };

  if (!account) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center text-gray-400">No account selected</div>
      </div>
    );
  }

  if (!account.cookies && account.status === "offline") {
    return (
      <AuthenticationRequired
        handleLogin={handleLogin}
        loggingIn={loggingIn}
        loginError={loginError}
        text="You need to be logged in to manage trade offers"
      />
    );
  }

  if (account.status === "logining") {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-purple-500 mx-auto mb-4"></div>
          <div className="text-gray-300 text-lg font-medium mb-2">
            Logging in...
          </div>
          <div className="text-gray-400 text-sm">
            Please wait while we establish connection
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Trade Offers</h1>
        <button
          onClick={fetchActiveOffers}
          disabled={loadingActive}
          className="p-2 rounded-md hover:bg-gray-700 transition-colors disabled:opacity-50"
          title="Refresh active offers"
        >
          <RefreshCw
            size={18}
            className={loadingActive ? "animate-spin" : ""}
          />
        </button>
      </div>

      {/* Активные трейды */}
      <div className="bg-gray-800/40 rounded-lg p-6 mb-6">
        <h2 className="text-xl font-semibold mb-4">Active Trades</h2>
        {loadingActive && activeOffers.length === 0 ? (
          <div className="flex justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-500"></div>
          </div>
        ) : activeOffers.length === 0 ? (
          <div className="text-center text-gray-400 py-8">
            No active trade offers
          </div>
        ) : (
          <div className="space-y-3">
            {activeOffers.map((o) => renderTradeOffer(o, false))}
          </div>
        )}
      </div>

      {/* История трейдов (все завершённые/отменённые от memberSince) */}
      <div className="bg-gray-800/40 rounded-lg p-6">
        <h2 className="text-xl font-semibold mb-4">Completed Trades</h2>
        {loadingHistory && historyOffers.length === 0 ? (
          <div className="flex justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-500"></div>
          </div>
        ) : historyOffers.length === 0 ? (
          <div className="text-center text-gray-400 py-8">
            No historical offers found
          </div>
        ) : (
          <div className="space-y-3">
            {historyOffers.map((o) => renderTradeOffer(o, true))}
          </div>
        )}
      </div>

      {error && (
        <div className="mt-4 p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
          {error}
        </div>
      )}
    </div>
  );
}
