// components/Farming/FarmingManagerModal.tsx
import { useState, useEffect, useCallback, useRef } from "react";
import {
  Search,
  X,
  Play,
  Square,
  Clock,
  CheckSquare,
  Square as SquareIcon,
  StopCircle,
  Users,
  Loader2,
  List,
  TrendingUp,
  CheckCircle,
  RefreshCw,
} from "lucide-react";
import { SteamAccountInfo } from "@/types";
import { accountApi } from "@/services/api";
import { cn } from "@/lib/utils";

interface FarmingManagerModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: SteamAccountInfo[];
}

// Real server data structure
interface FarmingItem {
  login: string;
  game: string;
  startTime: string;
}

interface AllAccountsData {
  queue: string[] | FarmingItem[];
  farming: FarmingItem[];
  completed: string[] | FarmingItem[];
  isFarming: boolean;
}

export function FarmingManagerModal({
  isOpen,
  onClose,
  accounts,
}: FarmingManagerModalProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedAccounts, setSelectedAccounts] = useState<Set<string>>(
    new Set(),
  );
  const [farmTime, setFarmTime] = useState(60);
  const [farmThreads, setFarmThreads] = useState(1);
  const [isProcessing, setIsProcessing] = useState(false);
  const [farmingData, setFarmingData] = useState<AllAccountsData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [autoRefresh, setAutoRefresh] = useState(true);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const filteredAccounts = accounts.filter((acc) =>
    acc.accountName.toLowerCase().includes(searchTerm.toLowerCase()),
  );

  useEffect(() => {
    if (!isOpen) {
      setSelectedAccounts(new Set());
      setSearchTerm("");
      setError(null);
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    }
  }, [isOpen]);

  const fetchFarmingData = useCallback(async () => {
    try {
      const result = await accountApi.getMassPlayGameInfo();
      console.log(result.data);
      if (result.data) {
        //@ts-ignore
        setFarmingData(result.data);
        setError(null);
      } else if (result.error) {
        setError(result.error);
      }
    } catch (err) {
      setError("Failed to load farming data");
    }
  }, []);

  useEffect(() => {
    if (isOpen) {
      fetchFarmingData();
    }
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isOpen, fetchFarmingData]);

  useEffect(() => {
    if (autoRefresh && farmingData?.isFarming && isOpen) {
      if (intervalRef.current) clearInterval(intervalRef.current);
      intervalRef.current = setInterval(fetchFarmingData, 5000);
    } else if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [autoRefresh, farmingData?.isFarming, isOpen, fetchFarmingData]);

  const toggleAccount = (accountName: string) => {
    if (isProcessing) return;
    setSelectedAccounts((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(accountName)) newSet.delete(accountName);
      else newSet.add(accountName);
      return newSet;
    });
  };

  const selectAllFiltered = () => {
    if (isProcessing) return;
    const allNames = filteredAccounts.map((a) => a.accountName);
    setSelectedAccounts(new Set(allNames));
  };

  const deselectAllFiltered = () => {
    if (isProcessing) return;
    setSelectedAccounts(new Set());
  };

  const startFarming = async () => {
    if (selectedAccounts.size === 0) {
      setError("Please select at least one account");
      return;
    }
    if (isProcessing) return;

    setIsProcessing(true);
    setError(null);
    try {
      const result = await accountApi.massPlayGame(
        Array.from(selectedAccounts),
        farmTime,
        farmThreads,
      );
      if (result.success) {
        await fetchFarmingData();
        setSelectedAccounts(new Set());
      } else {
        setError(result.error || "Failed to start farming");
      }
    } catch (err: any) {
      setError(err.message || "Unknown error");
    } finally {
      setIsProcessing(false);
    }
  };

  const stopAllFarming = async () => {
    if (!farmingData?.isFarming) {
      setError("No active farming");
      return;
    }
    setIsProcessing(true);
    try {
      //@ts-ignore
      const result = await accountApi.stopMassFarming();
      if (result.success) {
        await fetchFarmingData();
      } else {
        setError(result.error || "Failed to stop farming");
      }
    } catch (err: any) {
      setError(err.message || "Unknown error");
    } finally {
      setIsProcessing(false);
    }
  };

  const isFarmingActive = farmingData?.isFarming ?? false;

  const getQueueList = (): string[] => {
    const queue = farmingData?.queue ?? [];
    if (queue.length === 0) return [];
    if (typeof queue[0] === "string") {
      return queue as string[];
    } else if (typeof queue[0] === "object" && "login" in queue[0]) {
      return (queue as FarmingItem[]).map((item) => item.login);
    }
    return [];
  };

  const getFarmingList = (): FarmingItem[] => {
    return farmingData?.farming ?? [];
  };

  const getCompletedList = (): string[] => {
    const completed = farmingData?.completed ?? [];
    if (completed.length === 0) return [];
    if (typeof completed[0] === "string") {
      return completed as string[];
    } else if (typeof completed[0] === "object" && "login" in completed[0]) {
      return (completed as FarmingItem[]).map((item) => item.login);
    }
    return [];
  };

  const queueList = getQueueList();
  const farmingList = getFarmingList();
  const completedList = getCompletedList();

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
      onClick={(e) =>
        e.target === e.currentTarget && !isProcessing && onClose()
      }
    >
      <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-6xl max-h-[90vh] flex flex-col overflow-hidden border border-gray-700">
        {/* Header */}
        <div className="flex justify-between items-center p-5 border-b border-gray-700">
          <div>
            <h2 className="text-xl font-semibold text-white flex items-center gap-2">
              <Users className="w-5 h-5 text-indigo-400" />
              Game Activity Farming
            </h2>
          </div>
          <button
            onClick={onClose}
            disabled={isProcessing}
            className="text-gray-400 hover:text-white transition-colors disabled:opacity-50"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
          {/* Left column – account selection */}
          <div className="w-full lg:w-2/5 border-r border-gray-700 flex flex-col">
            <div className="p-4 border-b border-gray-700 space-y-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search accounts..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  disabled={isProcessing}
                />
              </div>
              <div className="flex gap-2">
                <button
                  onClick={selectAllFiltered}
                  disabled={isProcessing || filteredAccounts.length === 0}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50"
                >
                  <CheckSquare className="w-3 h-3" />
                  Select all
                </button>
                <button
                  onClick={deselectAllFiltered}
                  disabled={isProcessing || filteredAccounts.length === 0}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50"
                >
                  <SquareIcon className="w-3 h-3" />
                  Deselect all
                </button>
              </div>
              <div className="text-xs text-gray-300 bg-gray-800/50 rounded px-2 py-1">
                Selected: {selectedAccounts.size} account(s)
              </div>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-2">
              {filteredAccounts.length === 0 ? (
                <div className="text-center text-gray-400 py-8 text-sm">
                  No accounts found
                </div>
              ) : (
                filteredAccounts.map((acc) => {
                  const isChecked = selectedAccounts.has(acc.accountName);
                  const isInQueue = queueList.includes(acc.accountName);
                  const isFarmingNow = farmingList.some(
                    (f) => f.login === acc.accountName,
                  );
                  const isCompletedNow = completedList.includes(
                    acc.accountName,
                  );

                  let statusBadge = null;
                  if (isFarmingNow)
                    statusBadge = (
                      <span className="text-xs text-indigo-400 ml-1">
                        (farming)
                      </span>
                    );
                  else if (isInQueue)
                    statusBadge = (
                      <span className="text-xs text-yellow-400 ml-1">
                        (queued)
                      </span>
                    );
                  else if (isCompletedNow)
                    statusBadge = (
                      <span className="text-xs text-green-400 ml-1">
                        (completed)
                      </span>
                    );

                  return (
                    <label
                      key={acc.accountName}
                      className={cn(
                        "flex items-center gap-3 p-2 rounded-lg transition",
                        isChecked
                          ? "bg-indigo-900/50 ring-1 ring-indigo-500"
                          : "bg-gray-800/60 hover:bg-gray-700/60",
                        isProcessing && "opacity-50 cursor-not-allowed",
                      )}
                    >
                      <input
                        type="checkbox"
                        checked={isChecked}
                        onChange={() => toggleAccount(acc.accountName)}
                        disabled={isProcessing}
                        className="w-4 h-4 text-indigo-500 focus:ring-indigo-500 rounded disabled:opacity-50"
                      />
                      <span className="text-sm font-medium text-white flex-1">
                        {acc.accountName}
                      </span>
                      <span className="text-xs text-gray-400 ml-auto">
                        {acc.activity?.farming_activity &&
                          "last Use: " +
                            new Date(
                              acc.activity?.farming_activity,
                            ).toLocaleDateString()}
                      </span>
                      {statusBadge}
                    </label>
                  );
                })
              )}
            </div>
          </div>

          {/* Right column – control panel and statuses */}
          <div className="w-full lg:w-3/5 flex flex-col">
            {/* Parameters panel */}
            <div className="p-4 border-b border-gray-700 space-y-3">
              <div className="flex items-center gap-4 flex-wrap">
                <div className="flex items-center gap-2">
                  <Clock className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-white">
                    Farm time (minutes):
                  </span>
                </div>
                <input
                  type="number"
                  min={1}
                  max={1440}
                  value={farmTime}
                  onChange={(e) =>
                    setFarmTime(Math.max(1, parseInt(e.target.value) || 1))
                  }
                  disabled={isProcessing || isFarmingActive}
                  className="w-24 px-2 py-1 bg-gray-800 border border-gray-600 rounded text-white text-sm"
                />
              </div>
              <div className="flex items-center gap-4 flex-wrap">
                <div className="flex items-center gap-2">
                  <Users className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-white">Threads:</span>
                </div>
                <input
                  type="number"
                  min={1}
                  max={10}
                  value={farmThreads}
                  onChange={(e) =>
                    setFarmThreads(Math.max(1, parseInt(e.target.value) || 1))
                  }
                  disabled={isProcessing || isFarmingActive}
                  className="w-24 px-2 py-1 bg-gray-800 border border-gray-600 rounded text-white text-sm"
                />
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setAutoRefresh(!autoRefresh)}
                  disabled={isProcessing}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded transition-colors disabled:opacity-50"
                >
                  <RefreshCw
                    className={cn("w-3 h-3", autoRefresh && "animate-spin")}
                  />
                  Auto-refresh {autoRefresh ? "ON" : "OFF"}
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {error && (
                <div className="bg-red-900/30 border border-red-700/50 rounded-lg p-2 text-sm text-red-400">
                  {error}
                </div>
              )}

              {/* Queue */}
              <div className="bg-gray-800/40 rounded-xl border border-yellow-700/30 overflow-hidden">
                <div className="bg-yellow-900/20 px-4 py-2 border-b border-yellow-700/30 flex items-center gap-2">
                  <List className="w-4 h-4 text-yellow-400" />
                  <span className="text-sm font-medium text-yellow-400">
                    Farming queue
                  </span>
                  <span className="ml-auto text-xs bg-yellow-500/20 text-yellow-400 px-2 py-0.5 rounded-full">
                    {queueList.length}
                  </span>
                </div>
                <div className="p-3 max-h-40 overflow-y-auto">
                  {queueList.length === 0 ? (
                    <div className="text-xs text-gray-500 text-center">
                      No accounts in queue
                    </div>
                  ) : (
                    <div className="flex flex-wrap gap-2">
                      {queueList.map((name) => (
                        <span
                          key={name}
                          className="inline-flex items-center px-2 py-1 bg-yellow-500/10 text-yellow-300 rounded-lg text-xs font-mono"
                        >
                          {name}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Currently farming */}
              <div className="bg-gray-800/40 rounded-xl border border-indigo-700/30 overflow-hidden">
                <div className="bg-indigo-900/20 px-4 py-2 border-b border-indigo-700/30 flex items-center gap-2">
                  <TrendingUp className="w-4 h-4 text-indigo-400" />
                  <span className="text-sm font-medium text-indigo-400">
                    Currently farming
                  </span>
                  <span className="ml-auto text-xs bg-indigo-500/20 text-indigo-400 px-2 py-0.5 rounded-full">
                    {farmingList.length}
                  </span>
                </div>
                <div className="p-3 max-h-40 overflow-y-auto">
                  {farmingList.length === 0 ? (
                    <div className="text-xs text-gray-500 text-center">
                      No accounts farming right now
                    </div>
                  ) : (
                    <div className="flex flex-wrap gap-2">
                      {farmingList.map((item) => (
                        <div
                          key={item.login}
                          className="inline-flex flex-col px-2 py-1 bg-indigo-500/10 text-indigo-300 rounded-lg text-xs font-mono"
                        >
                          <span>{item.login}</span>
                          <span className="text-[10px] text-gray-400">
                            game: {item.game}
                          </span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              {/* Completed */}
              <div className="bg-gray-800/40 rounded-xl border border-green-700/30 overflow-hidden">
                <div className="bg-green-900/20 px-4 py-2 border-b border-green-700/30 flex items-center gap-2">
                  <CheckCircle className="w-4 h-4 text-green-400" />
                  <span className="text-sm font-medium text-green-400">
                    Completed
                  </span>
                  <span className="ml-auto text-xs bg-green-500/20 text-green-400 px-2 py-0.5 rounded-full">
                    {completedList.length}
                  </span>
                </div>
                <div className="p-3 max-h-40 overflow-y-auto">
                  {completedList.length === 0 ? (
                    <div className="text-xs text-gray-500 text-center">
                      No completed farms yet
                    </div>
                  ) : (
                    <div className="flex flex-wrap gap-2">
                      {completedList.map((name) => (
                        <span
                          key={name}
                          className="inline-flex items-center px-2 py-1 bg-green-500/10 text-green-300 rounded-lg text-xs font-mono"
                        >
                          {name}
                        </span>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer buttons */}
        <div className="p-5 border-t border-gray-700 flex justify-between gap-3">
          <button
            onClick={onClose}
            disabled={isProcessing}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm transition-colors disabled:opacity-50"
          >
            Close
          </button>
          <div className="flex gap-3">
            {isFarmingActive && (
              <button
                onClick={stopAllFarming}
                disabled={isProcessing}
                className="flex items-center gap-2 px-6 py-2.5 bg-red-600 hover:bg-red-700 rounded-lg text-sm font-medium transition-all shadow-lg hover:shadow-xl disabled:opacity-50"
              >
                <StopCircle className="w-4 h-4" />
                Stop all
              </button>
            )}
            <button
              onClick={startFarming}
              disabled={
                isProcessing || selectedAccounts.size === 0 || isFarmingActive
              }
              className={cn(
                "flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-medium transition-all shadow-lg hover:shadow-xl disabled:opacity-50",
                "bg-indigo-600 hover:bg-indigo-700",
              )}
            >
              {isProcessing ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Play className="w-4 h-4" />
              )}
              Start farming
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
