// components/AccountList/AccountList.tsx
import { useState, useEffect, useRef } from "react";
import {
  Filter,
  X,
  Wallet,
  ShoppingBag,
  Ban,
  AlertTriangle,
  Check,
  Circle,
} from "lucide-react";
import { SteamAccountInfo, Tag } from "../../types";
import { accountApi } from "../../services/api";
import { AccountItem } from "./AccountItem";
import { TagChip } from "../Tags/TagChip";

interface AccountListProps {
  activePage: string;
  accounts: SteamAccountInfo[];
  selectedAccount: SteamAccountInfo | null;
  onSelectAccount: (account: SteamAccountInfo) => void;
  onOpenConfirmations?: (account: SteamAccountInfo) => void;
  onOpenProfile: (account: SteamAccountInfo) => void;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
}

// TOTP helpers (без изменений)
const getTOTPExpiresAt = (): number => {
  const now = Date.now();
  const msInWindow = 30000;
  const currentWindowStart = Math.floor(now / msInWindow) * msInWindow;
  return currentWindowStart + msInWindow;
};

const getTimeLeftInWindow = (): number => {
  const now = Date.now();
  const msInWindow = 30000;
  const timeInWindow = now % msInWindow;
  return Math.ceil((msInWindow - timeInWindow) / 1000);
};

export function AccountList({
  activePage,
  accounts,
  selectedAccount,
  onSelectAccount,
  onUpdateAccount,
  onOpenConfirmations,
  onOpenProfile,
}: AccountListProps) {
  // TOTP state (без изменений)
  const [totpState, setTotpState] = useState<
    Record<string, { requested: boolean; timeLeft: number; expiresAt: number }>
  >({});
  const [loadingTotp, setLoadingTotp] = useState<Record<string, boolean>>({});

  // Фильтры
  const [selectedTagIds, setSelectedTagIds] = useState<Set<number>>(new Set());
  const [allTags, setAllTags] = useState<Tag[]>([]);
  const [showFilter, setShowFilter] = useState(false);
  const filterRef = useRef<HTMLDivElement>(null);
  const buttonRef = useRef<HTMLDivElement>(null);
  const [filterHasWallet, setFilterHasWallet] = useState<boolean | null>(null);
  const [filterMarketOpen, setFilterMarketOpen] = useState<boolean | null>(
    null,
  );
  const [filterLimited, setFilterLimited] = useState<boolean | null>(null);
  const [filterBans, setFilterBans] = useState<boolean | null>(null);

  // Загружаем все теги
  useEffect(() => {
    const loadTags = async () => {
      const res = await accountApi.getAllTags();
      if (res.success && res.data) setAllTags(res.data);
    };
    loadTags();
  }, [accounts]);

  // Закрываем панель при клике вне
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (
        filterRef.current &&
        !filterRef.current.contains(e.target as Node) &&
        buttonRef.current &&
        !buttonRef.current.contains(e.target as Node)
      ) {
        setShowFilter(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleTagToggle = (tagId: number) => {
    setSelectedTagIds((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(tagId)) newSet.delete(tagId);
      else newSet.add(tagId);
      return newSet;
    });
  };

  const clearAllFilters = () => {
    setSelectedTagIds(new Set());
    setFilterHasWallet(null);
    setFilterMarketOpen(null);
    setFilterLimited(null);
    setFilterBans(null);
  };

  // Фильтрация аккаунтов
  const filteredAccounts = accounts.filter((account) => {
    if (selectedTagIds.size > 0) {
      const hasTag = account.tags?.some((tag) => selectedTagIds.has(tag.id));
      if (!hasTag) return false;
    }
    if (filterHasWallet !== null && account.hasWallet !== filterHasWallet)
      return false;
    if (filterMarketOpen !== null && account.market.open !== filterMarketOpen)
      return false;
    if (filterLimited !== null && account.limited !== filterLimited)
      return false;
    if (filterBans !== null) {
      const hasAnyBan = !!(
        account.bans?.vac ||
        account.bans?.game ||
        account.bans?.community ||
        account.bans?.kt
      );
      if (hasAnyBan !== filterBans) return false;
    }
    return true;
  });

  // TOTP функции
  const fetchAndCopyTOTP = async (accountName: string) => {
    if (loadingTotp[accountName]) return;
    setLoadingTotp((prev) => ({ ...prev, [accountName]: true }));
    const result = await accountApi.getTOTP(accountName);
    if (result.success && result.code) {
      await navigator.clipboard.writeText(result.code);
      const expiresAt = getTOTPExpiresAt();
      const timeLeft = getTimeLeftInWindow();
      setTotpState((prev) => ({
        ...prev,
        [accountName]: { requested: true, timeLeft, expiresAt },
      }));
    } else {
      console.error("Failed to get TOTP:", result.error);
    }
    setLoadingTotp((prev) => ({ ...prev, [accountName]: false }));
  };

  useEffect(() => {
    const updateTimersAndCleanup = () => {
      const now = Date.now();
      const currentTimeLeft = getTimeLeftInWindow();
      setTotpState((prev) => {
        const newState = { ...prev };
        let hasChanges = false;
        Object.keys(newState).forEach((accountName) => {
          const state = newState[accountName];
          if (state.expiresAt <= now) {
            delete newState[accountName];
            hasChanges = true;
          } else if (state.timeLeft !== currentTimeLeft) {
            state.timeLeft = currentTimeLeft;
            hasChanges = true;
          }
        });
        return hasChanges ? newState : prev;
      });
    };
    updateTimersAndCleanup();
    const interval = setInterval(updateTimersAndCleanup, 1000);
    return () => clearInterval(interval);
  }, []);

  const showTOTP = async (accountName: string, e: React.MouseEvent) => {
    e.stopPropagation();
    await fetchAndCopyTOTP(accountName);
  };

  const handleConfirmations = (
    account: SteamAccountInfo,
    e: React.MouseEvent,
  ) => {
    e.stopPropagation();
    onOpenConfirmations?.(account);
  };

  // Количество активных фильтров (для индикатора)
  const activeFiltersCount =
    (filterHasWallet !== null ? 1 : 0) +
    (filterMarketOpen !== null ? 1 : 0) +
    (filterLimited !== null ? 1 : 0) +
    (filterBans !== null ? 1 : 0) +
    selectedTagIds.size;

  return (
    <div className="flex-1 flex flex-col overflow-hidden">
      {/* Кнопка фильтра с индикатором */}
      <div className="flex justify-end items-center p-2 border-b border-gray-700">
        <div
          ref={buttonRef}
          className="relative"
          onMouseEnter={() => setShowFilter(true)}
        >
          <button className="relative p-1.5 rounded-md hover:bg-gray-700 transition-colors">
            <Filter size={16} className="text-gray-400" />
            {activeFiltersCount > 0 && (
              <span className="absolute -top-0.5 -right-0.5 w-2 h-2 bg-cyan-500 rounded-full animate-pulse" />
            )}
          </button>
          {showFilter && (
            <div
              ref={filterRef}
              onMouseLeave={() => setShowFilter(false)}
              className="absolute right-0 mt-2 w-80 bg-gray-800 border border-gray-700 rounded-xl shadow-2xl z-10 p-4 backdrop-blur-sm"
            >
              <div className="flex justify-between items-center">
                <h4 className="text-sm font-semibold text-white">Filters</h4>
                {activeFiltersCount > 0 && (
                  <button
                    onClick={clearAllFilters}
                    className="text-xs text-gray-300 hover:text-white flex items-center gap-1 transition-colors"
                  >
                    <X size={12} /> Clear all
                  </button>
                )}
              </div>

              {/* Фильтр по тегам */}
              <div className="mb-4">
                <div className="flex justify-between items-center mb-2"></div>
                <div className="space-y-1.5 max-h-32 overflow-y-auto pr-1">
                  {allTags.length === 0 && (
                    <p className="text-xs text-gray-500">No tags created yet</p>
                  )}
                  {allTags.map((tag) => (
                    <label
                      key={tag.id}
                      className="flex items-center gap-2 cursor-pointer text-sm"
                    >
                      <input
                        type="checkbox"
                        checked={selectedTagIds.has(tag.id)}
                        onChange={() => handleTagToggle(tag.id)}
                        className="rounded bg-gray-700 border-gray-600 text-cyan-500 focus:ring-cyan-500"
                      />
                      <TagChip tag={tag} small />
                    </label>
                  ))}
                </div>
              </div>

              <div className="border-t border-gray-700 my-3"></div>

              {/* Фильтры в сетке 2x2 */}
              <div className="grid grid-cols-2 gap-3">
                {/* Wallet */}
                <div>
                  <div className="flex items-center gap-1 text-xs text-gray-300 mb-1.5">
                    <Wallet size={12} /> Wallet
                  </div>
                  <div className="flex gap-1">
                    <button
                      onClick={() =>
                        setFilterHasWallet(
                          filterHasWallet === true ? null : true,
                        )
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterHasWallet === true
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      Yes
                    </button>
                    <button
                      onClick={() =>
                        setFilterHasWallet(
                          filterHasWallet === false ? null : false,
                        )
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterHasWallet === false
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      No
                    </button>
                  </div>
                </div>

                {/* Market */}
                <div>
                  <div className="flex items-center gap-1 text-xs text-gray-300 mb-1.5">
                    <ShoppingBag size={12} /> Market
                  </div>
                  <div className="flex gap-1">
                    <button
                      onClick={() =>
                        setFilterMarketOpen(
                          filterMarketOpen === true ? null : true,
                        )
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterMarketOpen === true
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      Open
                    </button>
                    <button
                      onClick={() =>
                        setFilterMarketOpen(
                          filterMarketOpen === false ? null : false,
                        )
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterMarketOpen === false
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      Closed
                    </button>
                  </div>
                </div>

                {/* Limited */}
                <div>
                  <div className="flex items-center gap-1 text-xs text-gray-300 mb-1.5">
                    <AlertTriangle size={12} /> Limited
                  </div>
                  <div className="flex gap-1">
                    <button
                      onClick={() =>
                        setFilterLimited(filterLimited === true ? null : true)
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterLimited === true
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      Yes
                    </button>
                    <button
                      onClick={() =>
                        setFilterLimited(filterLimited === false ? null : false)
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterLimited === false
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      No
                    </button>
                  </div>
                </div>

                {/* Bans */}
                <div>
                  <div className="flex items-center gap-1 text-xs text-gray-300 mb-1.5">
                    <Ban size={12} /> Bans
                  </div>
                  <div className="flex gap-1">
                    <button
                      onClick={() =>
                        setFilterBans(filterBans === true ? null : true)
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterBans === true
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      Yes
                    </button>
                    <button
                      onClick={() =>
                        setFilterBans(filterBans === false ? null : false)
                      }
                      className={`flex-1 py-1 text-xs rounded-md transition-all cursor-pointer ${
                        filterBans === false
                          ? "bg-cyan-600 text-white"
                          : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                      }`}
                    >
                      No
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Список аккаунтов */}
      <div className="flex-1 overflow-y-auto overflow-x-hidden">
        {filteredAccounts.map((account) => {
          const state = totpState[account.accountName];
          const isTotpActive = state?.requested && state.expiresAt > Date.now();
          const timeLeft = state?.timeLeft || getTimeLeftInWindow();

          return (
            <AccountItem
              key={account.accountName}
              activePage={activePage}
              account={account}
              isSelected={selectedAccount?.accountName === account.accountName}
              onSelect={onSelectAccount}
              isTotpActive={isTotpActive || false}
              timeLeft={timeLeft}
              loadingTotp={loadingTotp[account.accountName]}
              onShowTOTP={showTOTP}
              onUpdateAccount={onUpdateAccount}
              onOpenProfile={onOpenProfile}
              onConfirmations={(_, e) => handleConfirmations(account, e)}
            />
          );
        })}
        {filteredAccounts.length === 0 && (
          <div className="flex items-center justify-center py-8 text-gray-500">
            <p className="text-sm">No accounts match the filters</p>
          </div>
        )}
      </div>
    </div>
  );
}
