// hooks/useMarketData.ts
import { useState, useCallback, useRef } from "react";
import { SteamAccountInfo, MarketListing, MarketOrder } from "../types";
import { accountApi } from "../services/api";

interface UseMarketDataProps {
  account: SteamAccountInfo | null;
  onListingsUpdate?: () => void;
  onOrdersUpdate?: () => void;
}

export function useMarketData({
  account,
  onListingsUpdate,
  onOrdersUpdate,
}: UseMarketDataProps) {
  const [listings, setListings] = useState<MarketListing[]>([]);
  const [orders, setOrders] = useState<MarketOrder[]>([]);
  const [loading, setLoading] = useState(false);
  const [loadingOrders, setLoadingOrders] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [selectedListing, setSelectedListing] = useState<MarketListing | null>(
    null,
  );
  const [selectedOrder, setSelectedOrder] = useState<MarketOrder | null>(null);

  // Refs to prevent infinite loops
  const isFetchingListings = useRef(false);
  const isFetchingOrders = useRef(false);

  const resetData = useCallback(() => {
    setListings([]);
    setOrders([]);
    setError(null);
    setProcessingId(null);
    setSelectedListing(null);
    setSelectedOrder(null);
    isFetchingListings.current = false;
    isFetchingOrders.current = false;
  }, []);

  const fetchListings = useCallback(async () => {
    if (!account?.cookies) return;
    if (isFetchingListings.current) return;

    isFetchingListings.current = true;
    setLoading(true);
    setError(null);
    try {
      const result = await accountApi.getMarketListings(account.accountName);
      if (result.success && result.data) {
        setListings(result.data);
        onListingsUpdate?.();
      } else {
        setError(result.error || "Failed to load listings");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setLoading(false);
      isFetchingListings.current = false;
    }
  }, [account, onListingsUpdate]);

  const fetchOrders = useCallback(async () => {
    if (!account?.cookies) return;
    if (isFetchingOrders.current) return;

    isFetchingOrders.current = true;
    setLoadingOrders(true);
    setError(null);
    try {
      const result = await accountApi.getMarketOrders(account.accountName);
      if (result.success && result.data) {
        setOrders(result.data);
        onOrdersUpdate?.();
      } else {
        setError(result.error || "Failed to load orders");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setLoadingOrders(false);
      isFetchingOrders.current = false;
    }
  }, [account, onOrdersUpdate]);

  const handleCancelListing = useCallback(async () => {
    if (!account || !selectedListing || processingId) return;

    setProcessingId(selectedListing.listingid);
    try {
      const result = await accountApi.cancelMarketListing(
        account.accountName,
        selectedListing.listingid,
      );
      if (result.success) {
        setListings((prev) =>
          prev.filter((l) => l.listingid !== selectedListing.listingid),
        );
        setSelectedListing(null);
      } else {
        setError(result.error || "Failed to cancel listing");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setProcessingId(null);
    }
  }, [account, selectedListing, processingId]);

  const handleCancelOrder = useCallback(async () => {
    if (!account || !selectedOrder || processingId) return;

    setProcessingId(selectedOrder.order_id);
    try {
      const result = await accountApi.cancelMarketOrder(
        account.accountName,
        selectedOrder.order_id,
      );
      if (result.success) {
        setOrders((prev) =>
          prev.filter((o) => o.order_id !== selectedOrder.order_id),
        );
        setSelectedOrder(null);
      } else {
        setError(result.error || "Failed to cancel order");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setProcessingId(null);
    }
  }, [account, selectedOrder, processingId]);

  const openCancelListingModal = useCallback((listing: MarketListing) => {
    setSelectedListing(listing);
  }, []);

  const openCancelOrderModal = useCallback((order: MarketOrder) => {
    setSelectedOrder(order);
  }, []);

  return {
    listings,
    orders,
    loading,
    loadingOrders,
    error,
    processingId,
    selectedListing,
    selectedOrder,
    fetchListings,
    fetchOrders,
    handleCancelListing,
    handleCancelOrder,
    openCancelListingModal,
    openCancelOrderModal,
    setSelectedListing,
    setSelectedOrder,
    setProcessingId,
    setError,
    resetData,
  };
}
