// components/inventory/SellModal.tsx
import { Tag, Loader2, CheckCircle, XCircle, Package } from "lucide-react";
import { Modal } from "../Modal";
import { SellItemRow } from "./SellItemRow";
import { SelectedItemWithPrice } from "@/types";

interface SellModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedItems: SelectedItemWithPrice[];
  loadingItems: Set<string>;
  processingAction: boolean;
  notification: { type: "success" | "error"; message: string } | null;
  detailedResult: { ok: string[]; error: string[] } | null;
  error: string | null;
  totalLoadingItems: number;
  loadedCount: number;
  onPriceChange: (assetId: string, price: string) => void;
  onPriceMinusOneCent: (assetId: string, currentPrice: number) => void;
  onOpenPriceModal: (
    item: SelectedItemWithPrice,
    type: "instant" | "market",
  ) => void;
  onCreateListings: () => void;
  formatPrice: (price: number, prefix?: string, suffix?: string) => string;
}

export function SellModal({
  isOpen,
  onClose,
  selectedItems,
  loadingItems,
  processingAction,
  notification,
  detailedResult,
  error,
  totalLoadingItems,
  loadedCount,
  onPriceChange,
  onPriceMinusOneCent,
  onOpenPriceModal,
  onCreateListings,
  formatPrice,
}: SellModalProps) {
  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Sell Items"
      icon={<Tag className="w-5 h-5 text-emerald-400" />}
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors cursor-pointer"
          >
            Cancel
          </button>
          <button
            onClick={onCreateListings}
            disabled={
              processingAction ||
              selectedItems.length === 0 ||
              totalLoadingItems > 0
            }
            className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 cursor-pointer disabled:opacity-50"
          >
            {processingAction ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                Creating Listings...
              </>
            ) : (
              <>
                <Tag size={16} />
                Create Listings ({selectedItems.length})
              </>
            )}
          </button>
        </div>
      }
      maxWidth="lg"
    >
      <div className="p-4 space-y-4">
        {notification && (
          <div
            className={`p-3 rounded-lg flex items-center gap-2 ${
              notification.type === "success"
                ? "bg-emerald-500/20 border border-emerald-500 text-emerald-400"
                : "bg-red-500/20 border border-red-500 text-red-400"
            }`}
          >
            {notification.type === "success" ? (
              <CheckCircle size={18} />
            ) : (
              <XCircle size={18} />
            )}
            <span className="text-sm">{notification.message}</span>
          </div>
        )}

        {/* Loading Progress Bar */}
        {totalLoadingItems > 0 && (
          <div className="bg-gray-800/50 rounded-lg p-3">
            <div className="flex justify-between text-sm text-gray-400 mb-2">
              <span>Loading market prices...</span>
              <span>
                {loadedCount} /{totalLoadingItems + loadedCount}
              </span>
            </div>
            <div className="w-full bg-gray-700 rounded-full h-2">
              <div
                className="bg-emerald-500 h-2 rounded-full transition-all duration-300"
                style={{
                  width: `${(loadedCount / (totalLoadingItems + loadedCount)) * 100}%`,
                }}
              />
            </div>
          </div>
        )}

        {selectedItems.length === 0 && totalLoadingItems === 0 ? (
          <div className="text-center py-8 text-gray-400">
            <Package size={48} className="mx-auto mb-3 opacity-50" />
            <p>No items selected</p>
          </div>
        ) : (
          <div className="space-y-3 max-h-96 overflow-y-auto">
            {selectedItems.map((item) => {
              const isLoading = loadingItems.has(item.assetid);
              const isPending = item.listingStatus === "pending";
              const isSuccess = item.listingStatus === "success";
              const isError = item.listingStatus === "error";

              return (
                <SellItemRow
                  key={item.assetid}
                  item={item}
                  isLoading={isLoading}
                  isPending={isPending}
                  isSuccess={isSuccess}
                  isError={isError}
                  onPriceChange={onPriceChange}
                  onPriceMinusOneCent={onPriceMinusOneCent}
                  onOpenPriceModal={onOpenPriceModal}
                  formatPrice={formatPrice}
                />
              );
            })}
          </div>
        )}

        {detailedResult &&
          (detailedResult.ok.length > 0 || detailedResult.error.length > 0) && (
            <div className="p-3 bg-gray-800/50 rounded-lg">
              <div className="text-sm font-medium text-white mb-2">
                Listing Results:
              </div>
              {detailedResult.ok.length > 0 && (
                <div className="text-xs text-emerald-400 mb-1">
                  ✓ Successfully listed: {detailedResult.ok.length} item(s)
                </div>
              )}
              {detailedResult.error.length > 0 && (
                <div className="text-xs text-red-400">
                  ✗ Failed: {detailedResult.error.length} item(s)
                </div>
              )}
            </div>
          )}

        {error && (
          <div className="p-2 bg-red-500/20 border border-red-500 rounded-lg text-red-400 text-sm">
            {error}
          </div>
        )}
      </div>
    </Modal>
  );
}
