// pages/MarketPage.tsx
import { useState, useEffect, useRef } from "react";
import { SteamAccountInfo } from "../types";
import { MarketHeader } from "../components/Market/MarketHeader";
import { MarketTabs } from "../components/Market/MarketTabs";
import { ListingsTab } from "../components/Market/ListingsTab";
import { OrdersTab } from "../components/Market/OrdersTab";
import { CancelListingModal } from "../components/Market/CancelListingModal";
import { CancelOrderModal } from "../components/Market/CancelOrderModal";
import { SellItemModal } from "../components/Market/SellItemModal";
import { useMarketData } from "../hooks/use-market-data";
import { CreateOrderModal } from "../components/Market/CreateOrderModal";
import { accountApi } from "../services/api";
import { AuthenticationRequired } from "@/components/AuthenticationRequired";
import { useAccountLogin } from "@/hooks/use-account-login";

interface MarketPageProps {
  account: SteamAccountInfo | null;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
  setActivePage: (page: string) => void;
}

export function MarketPage({
  account,
  onUpdateAccount,
  setActivePage,
}: MarketPageProps) {
  const [activeTab, setActiveTab] = useState<"listings" | "orders">("listings");
  const [listingsSearchQuery, setListingsSearchQuery] = useState("");
  const [ordersSearchQuery, setOrdersSearchQuery] = useState("");

  // Modal states
  const [cancelListingModalOpen, setCancelListingModalOpen] = useState(false);
  const [cancelOrderModalOpen, setCancelOrderModalOpen] = useState(false);
  const [sellItemModalOpen, setSellItemModalOpen] = useState(false);
  const [createOrderModalOpen, setCreateOrderModalOpen] = useState(false);

  // Ref to track initial load for current account
  const currentAccountNameRef = useRef<string | null>(null);

  const {
    listings,
    orders,
    loading,
    loadingOrders,
    error,
    processingId,
    selectedListing,
    selectedOrder,
    fetchListings,
    fetchOrders,
    handleCancelListing,
    handleCancelOrder,
    openCancelListingModal,
    openCancelOrderModal,
    setSelectedListing,
    setSelectedOrder,
    setProcessingId,
    resetData,
  } = useMarketData({ account });

  const { loggingIn, handleLogin, loginError } = useAccountLogin({
    account,
    onUpdateAccount,
  });

  // Reset and reload when account changes
  useEffect(() => {
    if (!account?.cookies) return;

    // Check if account changed
    if (currentAccountNameRef.current !== account.accountName) {
      // Reset ref for new account
      currentAccountNameRef.current = account.accountName;

      // Reset data and load for new account
      resetData();
      fetchListings();
      fetchOrders();
    }
  }, [account, fetchListings, fetchOrders, resetData]);

  const handleRefresh = () => {
    if (activeTab === "listings") {
      fetchListings();
    } else {
      fetchOrders();
    }
  };

  if (!account) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center text-gray-400">No account selected</div>
      </div>
    );
  }
  // Проверка на активную сессию (cookies)
  if (!account.cookies) {
    return (
      <AuthenticationRequired
        text={"You need to be logged in to manage market listings and orders."}
        handleLogin={handleLogin}
        loggingIn={loggingIn}
        loginError={loginError}
      />
    );
  }
  // Проверка на бан торговой площадки
  if (account.bans?.kt === true) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="bg-gray-800/60 rounded-xl p-8 max-w-md text-center border border-gray-700 shadow-xl">
          <div className="text-red-400 text-5xl mb-4">🚫</div>
          <h2 className="text-xl font-bold mb-2">Market Ban Detected</h2>
          <p className="text-gray-300 mb-4">
            This account has a Steam Market ban . You cannot trade or use the
            market.
          </p>
          <p className="text-sm text-gray-400">
            Please contact Steam Support for more information.
          </p>
        </div>
      </div>
    );
  }

  if (account.market.willOpen) {
    return (
      <div className="max-w-6xl mx-auto">
        <MarketHeader
          account={account}
          onRefresh={handleRefresh}
          isLoading={loading || loadingOrders}
        />
        <div className="flex items-center justify-center h-[80vh]">
          <div className="flex items-center">
            <div className="bg-gray-800/60 rounded-xl p-8 max-w-md text-center border border-gray-700 shadow-xl">
              <div className="text-yellow-400 text-5xl mb-4">⚠️</div>
              <h2 className="text-xl font-bold mb-2">Account Limited</h2>
              <p className="text-gray-300 mb-4">
                Access to the Steam Market will open on{" "}
                {new Date(account.market?.willOpen).toString()}.
              </p>
            </div>
          </div>
        </div>
      </div>
    );
  }
  // Проверка на лимиты аккаунта (limited или отсутствие кошелька)
  if (account.limited === true || account.hasWallet === false) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="bg-gray-800/60 rounded-xl p-8 max-w-md text-center border border-gray-700 shadow-xl">
          <div className="text-yellow-400 text-5xl mb-4">⚠️</div>
          <h2 className="text-xl font-bold mb-2">Account Limited</h2>
          <p className="text-gray-300 mb-4">
            This account has restrictions. To use the Steam Market, you need to:
          </p>
          <ul className="text-sm text-gray-400 text-left mb-6 space-y-1">
            <li>• Add at least $5 to your Steam Wallet</li>
            <li>• Purchase a cheap item through the panel.</li>
          </ul>
          <div className="bg-gray-900/50 rounded-lg p-3 text-xs text-gray-500">
            Note: Some features may be unavailable until the account is fully
            unlocked.
          </div>
        </div>
      </div>
    );
  }

  const currentSearchQuery =
    activeTab === "listings" ? listingsSearchQuery : ordersSearchQuery;
  const setCurrentSearchQuery = (value: string) => {
    if (activeTab === "listings") {
      setListingsSearchQuery(value);
    } else {
      setOrdersSearchQuery(value);
    }
  };

  return (
    <div className="max-w-6xl mx-auto">
      <MarketHeader
        account={account}
        onRefresh={handleRefresh}
        onCreateOrder={() => setCreateOrderModalOpen(true)}
        isLoading={loading || loadingOrders}
      />

      <MarketTabs
        activeTab={activeTab}
        onTabChange={setActiveTab}
        listingsCount={listings.length}
        ordersCount={orders.length}
        searchQuery={currentSearchQuery}
        onSearchChange={setCurrentSearchQuery}
        searchPlaceholder={`Search ${activeTab === "listings" ? "listings" : "orders"}...`}
      />

      {activeTab === "listings" && (
        <ListingsTab
          listings={listings}
          loading={loading}
          searchQuery={listingsSearchQuery}
          processingId={processingId}
          setActivePage={setActivePage}
          onCancelListing={(listing) => {
            openCancelListingModal(listing);
            setCancelListingModalOpen(true);
          }}
        />
      )}

      {activeTab === "orders" && (
        <OrdersTab
          orders={orders}
          loading={loadingOrders}
          searchQuery={ordersSearchQuery}
          processingId={processingId}
          onCancelOrder={(order) => {
            openCancelOrderModal(order);
            setCancelOrderModalOpen(true);
          }}
        />
      )}

      {error && (
        <div className="mt-4 p-3 bg-red-500/20 border border-red-500 rounded-lg text-red-400 text-sm">
          {error}
        </div>
      )}

      <CancelListingModal
        isOpen={cancelListingModalOpen}
        listing={selectedListing}
        onClose={() => {
          setCancelListingModalOpen(false);
          setSelectedListing(null);
        }}
        onConfirm={async () => {
          await handleCancelListing();
          setCancelListingModalOpen(false);
        }}
        isProcessing={processingId !== null}
      />

      <CancelOrderModal
        isOpen={cancelOrderModalOpen}
        order={selectedOrder}
        onClose={() => {
          setCancelOrderModalOpen(false);
          setSelectedOrder(null);
        }}
        onConfirm={async () => {
          await handleCancelOrder();
          setCancelOrderModalOpen(false);
        }}
        isProcessing={processingId !== null}
      />

      <SellItemModal
        isOpen={sellItemModalOpen}
        account={account}
        onClose={() => setSellItemModalOpen(false)}
        onSuccess={() => {
          fetchListings();
        }}
      />

      <CreateOrderModal
        isOpen={createOrderModalOpen}
        account={account}
        onClose={() => setCreateOrderModalOpen(false)}
        onSuccess={() => {
          fetchOrders();
        }}
      />
    </div>
  );
}
