// components/AccountList/AccountItem.tsx
import { ShoppingBag, Shield, Gift, Settings, Key } from "lucide-react";
import { cn } from "../../lib/utils";
import { SteamAccountInfo, Tag } from "../../types";
import { AccountAvatar } from "./AccountAvatar";
import { AccountInfo } from "./AccountInfo";
import { AccountActions } from "./AccountActions";
import { StatusIcon } from "./StatusIcon";
import { LoginWithTOTPButton } from "./LoginViaTOTP";
import { accountApi } from "@/services/api";
import { TagChip } from "../Tags/TagChip";
import { useState } from "react";
import { TagsModal } from "../Tags/TagsModal";

interface AccountItemProps {
  activePage: string;
  account: SteamAccountInfo;
  isSelected: boolean;
  onSelect: (account: SteamAccountInfo) => void;
  onOpenProfile: (account: SteamAccountInfo) => void;
  isTotpActive: boolean;
  timeLeft: number;
  loadingTotp?: boolean;
  onShowTOTP: (accountName: string, e: React.MouseEvent) => void;
  onConfirmations: (accountName: string, e: React.MouseEvent) => void;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void; // добавили
}

export function AccountItem({
  activePage,
  account,
  isSelected,
  onSelect,
  onOpenProfile,
  isTotpActive,
  timeLeft,
  loadingTotp,
  onShowTOTP,
  onConfirmations,
  onUpdateAccount,
}: AccountItemProps) {
  const confirmationStatus = {
    market: account.confirmations?.market ?? true,
    trade: account.confirmations?.trade ?? true,
    gift: account.confirmations?.acceptGiftTrade ?? false,
    system: account.confirmations?.system ?? true,
  };
  const [tagsModalOpen, setTagsModalOpen] = useState(false);

  const handleItemClick = () => onSelect(account);
  const handleAvatarClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onOpenProfile(account);
  };
  const handleManageTags = (e: React.MouseEvent) => {
    e.stopPropagation();
    setTagsModalOpen(true);
  };

  // После изменения тегов перезагружаем их с сервера и обновляем аккаунт
  const handleTagsUpdated = async () => {
    try {
      const result = await accountApi.getAccountTags(account.accountName);
      if (result.success && result.data) {
        const updatedAccount = { ...account, tags: result.data };
        onUpdateAccount?.(updatedAccount);
      }
    } catch (err) {
      console.error("Failed to refresh tags", err);
    }
  };

  return (
    <>
      <div
        className={cn(
          "border-b border-gray-800 transition-all duration-200",
          isSelected && "bg-indigo-500/10 border-l-2 border-l-indigo-500",
        )}
      >
        <div
          onClick={handleItemClick}
          onKeyDown={(e) => {
            if (e.key === "Enter" || e.key === " ") {
              e.preventDefault();
              onSelect(account);
            }
          }}
          role="button"
          tabIndex={0}
          className={cn(
            "w-full py-2.5 px-3 text-left transition-colors cursor-pointer group",
            isSelected && "bg-indigo-500/5",
          )}
        >
          <div className="flex items-center gap-3">
            <div
              onClick={handleAvatarClick}
              className="cursor-pointer transition-opacity hover:opacity-80"
              title="Click to view profile"
            >
              <AccountAvatar
                activePage={activePage}
                isSelected={isSelected}
                avatar={account.profileData.avatar}
                username={account.profileData.name}
              />
            </div>

            <div className="flex-1 cursor-pointer transition-colors rounded px-1 -mx-1">
              <AccountInfo account={account} />
            </div>

            {account.sharedSecret !== "" &&
            account.identity_secret !== "" &&
            account.status !== "logining" ? (
              <AccountActions
                activePage={activePage}
                account={account}
                isTotpActive={isTotpActive}
                timeLeft={timeLeft}
                isSelected={isSelected}
                loadingTotp={loadingTotp}
                onShowTOTP={onShowTOTP}
                onConfirmations={onConfirmations}
              />
            ) : (
              <>
                {account.status === "offline" && account.refreshToken && (
                  <div className="flex flex-col items-end gap-1.5">
                    <button
                      onClick={async () =>
                        await accountApi.login([account.accountName])
                      }
                      className="inline-flex items-center gap-1.5 rounded-md bg-indigo-500/10 px-2 py-1 text-[10px] font-medium text-indigo-400 hover:bg-indigo-500/20 transition-colors whitespace-nowrap cursor-pointer"
                      aria-label="Login with Steam Guard"
                    >
                      <Key size={10} />
                      Login via Token
                    </button>
                  </div>
                )}
                {account.status === "offline" && !account.refreshToken && (
                  <LoginWithTOTPButton
                    accountName={account.accountName}
                    password={account.password}
                  />
                )}
              </>
            )}
          </div>

          <div
            className={cn(
              activePage !== "main" && "flex items-center justify-between",
            )}
          >
            {activePage !== "main" && (
              <span className="mt-1 text-xs text-emerald-400 font-mono truncate">
                {account.balance?.formattedBalance}{" "}
              </span>
            )}

            {account.sharedSecret !== "" &&
            account.sharedSecret &&
            account.steamid !== "" &&
            account.cookies &&
            (account.confirmations.acceptGiftTrade ||
              account.confirmations.market ||
              account.confirmations.system ||
              account.confirmations.trade) ? (
              <div className="flex items-center justify-end gap-1.5 mt-1.5 pl-11">
                <StatusIcon
                  isActive={confirmationStatus.market}
                  icon={<ShoppingBag size={9} />}
                  label="Market confirmation"
                  activeText="Market: On"
                  inactiveText="Market: Off"
                />
                <StatusIcon
                  isActive={confirmationStatus.trade}
                  icon={<Shield size={9} />}
                  label="Trade confirmation"
                  activeText="Trade: On"
                  inactiveText="Trade: Off"
                />
                <StatusIcon
                  isActive={confirmationStatus.gift}
                  icon={<Gift size={9} />}
                  label="Gift confirmation"
                  activeText="Gift: On"
                  inactiveText="Gift: Off"
                />
                <StatusIcon
                  isActive={confirmationStatus.system}
                  icon={<Settings size={9} />}
                  label="System confirmation"
                  activeText="System: On"
                  inactiveText="System: Off"
                />
              </div>
            ) : null}
          </div>

          <div className="mt-1 flex">
            <div className="flex flex-wrap gap-1">
              {account.tags?.map((tag: Tag) => (
                <TagChip key={tag.id} tag={tag} small />
              ))}
            </div>
            <button
              onClick={handleManageTags}
              className="opacity-0 group-hover:opacity-100 transition-opacity text-gray-400 text-xs hover:text-gray-300 duration-300 cursor-pointer ml-1"
              title="Manage tags"
            >
              +tag
            </button>
          </div>
        </div>
      </div>

      <TagsModal
        isOpen={tagsModalOpen}
        onClose={() => setTagsModalOpen(false)}
        account={account}
        onTagsUpdated={handleTagsUpdated}
      />
    </>
  );
}
