// components/PrivacyModal.tsx
import { useState } from "react";
import {
  X,
  Lock,
  Users,
  Eye,
  Gift,
  Gamepad,
  Clock,
  User,
  MessageSquare,
  Package,
  Save,
  Loader2,
} from "lucide-react";

interface PrivacyModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (settings: PrivacySettings) => Promise<void>;
  initialSettings: PrivacySettings;
  isSaving: boolean;
}

export interface PrivacySettings {
  profile: string;
}

const PRIVACY_OPTIONS = [
  {
    value: "1",
    label: "Private",
    icon: <Lock size={16} />,
    description: "Only you can see",
  },
  {
    value: "2",
    label: "Friends Only",
    icon: <Users size={16} />,
    description: "Only friends can see",
  },
  {
    value: "3",
    label: "Public",
    icon: <Eye size={16} />,
    description: "Anyone can see",
  },
];

export function PrivacyModal({
  isOpen,
  onClose,
  onSave,
  initialSettings,
  isSaving,
}: PrivacyModalProps) {
  const [settings, setSettings] = useState<PrivacySettings>(initialSettings);

  if (!isOpen) return null;

  const handleSave = async () => {
    await onSave(settings);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70">
      <div className="bg-gray-800 rounded-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl border border-gray-700">
        <div className="sticky top-0 bg-gray-800 border-b border-gray-700 px-6 py-4 flex justify-between items-center">
          <h2 className="text-xl font-bold text-white">Privacy Settings</h2>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-white transition-colors cursor-pointer"
          >
            <X size={24} />
          </button>
        </div>

        <div className="p-6 space-y-6">
          {/* Profile Privacy */}
          <div>
            <label className="text-sm font-medium text-gray-300 flex items-center gap-2 mb-2">
              <User size={16} /> Profile Privacy
            </label>
            <div className="grid grid-cols-3 gap-2">
              {PRIVACY_OPTIONS.map((opt) => (
                <button
                  key={opt.value}
                  onClick={() =>
                    setSettings({ ...settings, profile: opt.value })
                  }
                  className={`p-3 rounded-lg border text-left transition-all ${
                    settings.profile === opt.value
                      ? "border-indigo-500 bg-indigo-500/20 text-indigo-300"
                      : "border-gray-700 bg-gray-800/50 text-gray-400 hover:border-gray-600"
                  }`}
                >
                  <div className="flex items-center gap-2 mb-1">
                    {opt.icon}
                    <span className="font-medium">{opt.label}</span>
                  </div>
                  <p className="text-xs opacity-75">{opt.description}</p>
                </button>
              ))}
            </div>
          </div>

          <div className="sticky bottom-0 bg-gray-800 border-t border-gray-700 px-6 py-4 flex justify-end gap-3">
            <button
              onClick={onClose}
              className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors cursor-pointer"
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              disabled={isSaving}
              className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 rounded-lg text-sm font-medium transition-colors disabled:opacity-50 flex items-center gap-2 cursor-pointer"
            >
              {isSaving ? (
                <Loader2 size={16} className="animate-spin" />
              ) : (
                <Save size={16} />
              )}
              Save Settings
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
