import { useCallback, useEffect, useMemo, useState } from "react";
import { InventoryAllItem, SteamAccountInfo } from "../types";
import { accountApi } from "@/services/api";

export const useMainPageStats = (accounts: SteamAccountInfo[]) => {
  const accountsWithWallet = useMemo(() => {
    return accounts.filter(
      (account) => account.hasWallet && account.balance !== null,
    );
  }, [accounts]);

  const accountsWithoutWallet = useMemo(() => {
    return accounts.filter(
      (account) => !account.hasWallet || account.balance === null,
    );
  }, [accounts]);

  const balances = useMemo(() => {
    const map = new Map<number, number>();
    for (const account of accountsWithWallet) {
      const currency = Number(account.balance!.currency);
      const value = account.balance!.value;
      if (map.has(currency)) {
        map.set(currency, map.get(currency)! + value);
      } else {
        map.set(currency, value);
      }
    }
    return map;
  }, [accountsWithWallet]);

  const totalBalanceUSD = useMemo(() => {
    return accountsWithWallet.reduce((sum, account) => {
      if (
        account.balance?.usdbalance !== undefined &&
        typeof account.balance.usdbalance === "number"
      ) {
        return sum + account.balance.usdbalance;
      }

      return sum;
    }, 0);
  }, [accountsWithWallet]);

  const accountStats = {
    total: accounts.length,
    limited: accounts.filter((a) => a.limited).length,
    online: accounts.filter((a) => a.status === "online").length,
    offline: accounts.filter((a) => a.status === "offline").length,
    logining: accounts.filter((a) => a.status === "logining").length,
    farm: accounts.filter((a) => a.status === "farm").length,
    nolimited: accounts.filter((a) => !a.limited).length,
    withWallet: accountsWithWallet.length,
    withoutWallet: accountsWithoutWallet.length,
  };

  const banStats = {
    total: accounts.filter(
      (a) => a.bans.vac || a.bans.game || a.bans.community || a.bans.kt,
    ).length,
    vacBans: accounts.filter((a) => a.bans.vac).length,
    gameBans: accounts.filter((a) => a.bans.game).length,
    communityBans: accounts.filter((a) => a.bans.community).length,
    tradeBans: accounts.filter((a) => a.bans.kt).length,
  };

  const [inventoryItems, setInventoryItems] = useState<InventoryAllItem[]>([]);
  const [loadingInventory, setLoadingInventory] = useState(false);

  const loadInventory = useCallback(async () => {
    setLoadingInventory(true);
    const result = await accountApi.getAllInventory();
    if (result.success && result.data) {
      setInventoryItems(result.data.items);
      // возможно, также сохранить общую сумму, если она не вычисляется на фронте
    } else {
      console.error(result.error);
      setInventoryItems([]);
    }
    setLoadingInventory(false);
  }, []);

  const refreshInventory = useCallback(async () => {
    setLoadingInventory(true);
    const result = await accountApi.refreshInventory();
    if (result.success) {
      await loadInventory(); // перезагружаем данные после обновления
    } else {
      console.error("Refresh failed:", result.error);
    }
    setLoadingInventory(false);
  }, [loadInventory]);
  useEffect(() => {
    const fetch = async () => {
      await loadInventory();
    };
    fetch();
  }, []);
  const inventoryStats = useMemo(() => {
    if (!inventoryItems.length) {
      return {
        totalItems: 0,
        totalValue: 0,
        topGames: [],
        cheapItemsCount: 0,
      };
    }

    const gamesMap = new Map<string, { count: number; totalPrice: number }>();
    let totalValueSum = 0;
    let cheapItemsCount = 0;

    for (const item of inventoryItems) {
      const price = item.price ?? 0;
      totalValueSum += price;
      if (price < 0.1) {
        cheapItemsCount++;
      }

      const gameId = item.appId;
      const existing = gamesMap.get(gameId);
      if (existing) {
        existing.count += 1;
        existing.totalPrice += price;
      } else {
        gamesMap.set(gameId, { count: 1, totalPrice: price });
      }
    }

    const topGames = Array.from(gamesMap.entries())
      .map(([gameId, data]) => ({
        gameId,
        gameName: getGameNameById(gameId),
        count: data.count,
        totalValue: data.totalPrice,
      }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 3);

    return {
      totalItems: inventoryItems.length,
      totalValue: totalValueSum,
      topGames,
      cheapItemsCount,
    };
  }, [inventoryItems]);

  return {
    accountsWithWallet,
    accountsWithoutWallet,
    balances,
    totalBalanceUSD,
    accountStats,
    banStats,
    inventoryStats,
    loadingInventory,
    refreshInventory,
  };
};

function getGameNameById(appId: string): string {
  const games: Record<string, string> = {
    "730": "CS2",
    "570": "Dota 2",
    "440": "Team Fortress 2",
  };
  return games[appId] || `Game ${appId}`;
}
