// components/AccountList/AccountInfo.tsx
import { Circle, Globe } from "lucide-react";
import { SteamAccountInfo } from "../../types";

const statusColors = {
  online: "text-emerald-400",
  offline: "text-gray-500",
  logining: "text-yellow-400",
  farm: "text-indigo-400",
};

interface AccountInfoProps {
  account: SteamAccountInfo;
}

// Функция для укорачивания длинного логина (на 1/5)
const truncateLogin = (login: string): string => {
  if (login.length <= 15) return login;
  // Уменьшаем длину на 1/5
  const newLength = Math.floor(login.length * 0.8);
  return login.slice(0, newLength) + "...";
};

export function AccountInfo({ account }: AccountInfoProps) {
  const displayName = truncateLogin(account.accountName);

  return (
    <div className="flex-1 min-w-0">
      <div className="flex items-center gap-1.5">
        <p
          className="text-sm font-medium text-white truncate"
          title={account.accountName}
        >
          {displayName}
        </p>
        <Circle
          size={5}
          className={`fill-current ${statusColors[account.status]} flex-shrink-0`}
        />
      </div>

      {account.ipAddress && (
        <div className="mt-0.5 flex items-center gap-1">
          <Globe size={8} className="text-gray-600 flex-shrink-0" />
          <span className="text-[10px] text-gray-500 font-mono truncate">
            {account.ipAddress}
          </span>
        </div>
      )}
    </div>
  );
}
