// hooks/useInventory.ts
import { useState, useEffect, useCallback, useRef } from "react";
import {
  SteamAccountInfo,
  SteamInventoryItem,
  OrderSpreadData,
} from "../types";
import { accountApi } from "../services/api";
import { GameOption } from "@/constants/games.constants";
import { SelectedItemWithPrice } from "@/types";

// Кэш: ключ = `${marketHashName}_${currency}`
const priceCache = new Map<string, OrderSpreadData>();

export function useInventory(
  account: SteamAccountInfo | null,
  selectedGame: GameOption | null,
) {
  const [inventory, setInventory] = useState<SteamInventoryItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedItems, setSelectedItems] = useState<Set<string>>(new Set());
  const [itemPrices, setItemPrices] = useState<
    Map<string, SelectedItemWithPrice>
  >(new Map());
  const [loadingItems, setLoadingItems] = useState<Set<string>>(new Set());
  const intervalRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const loadedMarketHashesRef = useRef<Set<string>>(new Set()); // храним ключи `${hash}_${currency}`

  const fetchInventory = useCallback(async () => {
    if (!account?.cookies || !selectedGame) return;
    setLoading(true);
    setError(null);
    setSelectedItems(new Set());
    try {
      const result = await accountApi.getInventory(
        account.accountName,
        selectedGame.appId,
        selectedGame.contextId,
      );
      if (result.success && result.data) {
        setInventory(result.data);
      } else {
        setError(result.error || "Failed to load inventory");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setLoading(false);
    }
  }, [account, selectedGame]);

  const fetchOrderSpreadForItem = async (
    item: SteamInventoryItem,
    currency: number,
  ): Promise<OrderSpreadData | null> => {
    if (!account) return null;
    const marketHashName = item.market_hash_name || item.name || "";
    const cacheKey = `${marketHashName}_${currency}`;
    if (priceCache.has(cacheKey)) {
      console.log(`Using cached price for: ${cacheKey}`);
      return priceCache.get(cacheKey) || null;
    }
    try {
      const result = await accountApi.getOrderSpread(
        account.accountName,
        selectedGame?.appId!,
        marketHashName,
      );
      if (result.success && result.data) {
        priceCache.set(cacheKey, result.data);
        return result.data;
      }
      return null;
    } catch (err) {
      console.error(`Failed to load price for ${cacheKey}:`, err);
      return null;
    }
  };

  const startLoadingPrices = async (itemsToLoad: SteamInventoryItem[]) => {
    if (!account) return;

    // Сбрасываем состояния перед началом
    setItemPrices(new Map());
    setLoadingItems(new Set(itemsToLoad.map((item) => item.assetid)));
    loadedMarketHashesRef.current.clear();
    if (intervalRef.current) clearInterval(intervalRef.current);

    const currency = account.balance?.currency || 1;

    // Группируем по уникальной паре (market_hash_name, currency)
    const uniqueKeyMap = new Map<string, SteamInventoryItem>();
    for (const item of itemsToLoad) {
      const hash = item.market_hash_name || item.name || "";
      const key = `${hash}_${currency}`;
      if (!uniqueKeyMap.has(key)) {
        uniqueKeyMap.set(key, item);
      }
    }

    const uniqueItems = Array.from(uniqueKeyMap.values());

    // Загружаем цены для каждого уникального ключа последовательно
    for (const uniqueItem of uniqueItems) {
      const hash = uniqueItem.market_hash_name || uniqueItem.name || "";
      const key = `${hash}_${currency}`;
      if (loadedMarketHashesRef.current.has(key)) continue;
      loadedMarketHashesRef.current.add(key);

      // Запрашиваем данные для этого ключа
      const orderSpread = await fetchOrderSpreadForItem(uniqueItem, currency);
      const instantPrice = orderSpread?.buy_orders?.[0]?.price || 0;
      const marketPrice = orderSpread?.sell_orders?.[0]?.price || 0;

      // Обновляем itemPrices для ВСЕХ предметов, у которых такой же ключ
      setItemPrices((prev) => {
        const newMap = new Map(prev);
        for (const originalItem of itemsToLoad) {
          const h = originalItem.market_hash_name || originalItem.name || "";
          const k = `${h}_${currency}`;
          if (k === key) {
            const customPrice = instantPrice
              ? instantPrice.toString()
              : marketPrice
                ? marketPrice.toString()
                : "";
            newMap.set(originalItem.assetid, {
              ...originalItem,
              customPrice,
              instantSellPrice: instantPrice,
              marketPrice: marketPrice,
              priceLoaded: true,
              fullOrderSpread: orderSpread!,
            });
          }
        }
        return newMap;
      });

      // Убираем загруженные предметы из loadingItems
      setLoadingItems((prev) => {
        const newSet = new Set(prev);
        for (const originalItem of itemsToLoad) {
          const h = originalItem.market_hash_name || originalItem.name || "";
          const k = `${h}_${currency}`;
          if (k === key) {
            newSet.delete(originalItem.assetid);
          }
        }
        return newSet;
      });

      // Небольшая задержка, чтобы React успел отрендерить прогресс (опционально)
      await new Promise((resolve) => setTimeout(resolve, 0));
    }
  };

  const handleSelectAll = () => {
    if (selectedItems.size === inventory.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(inventory.map((item) => item.assetid)));
    }
  };

  const handleItemSelect = (assetId: string) => {
    setSelectedItems((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(assetId)) newSet.delete(assetId);
      else newSet.add(assetId);
      return newSet;
    });
  };

  const updateItemPrice = (assetId: string, price: string) => {
    setItemPrices((prev) => {
      const newMap = new Map(prev);
      const current = newMap.get(assetId);
      if (current) newMap.set(assetId, { ...current, customPrice: price });
      return newMap;
    });
  };

  const setPriceMinusOneCent = (assetId: string, currentPrice: number) => {
    const newPrice = (currentPrice - 0.01).toFixed(2);
    updateItemPrice(assetId, newPrice);
  };

  const clearPrices = () => {
    setItemPrices(new Map());
    setLoadingItems(new Set());
    loadedMarketHashesRef.current.clear();
    if (intervalRef.current) clearInterval(intervalRef.current);
  };

  const clearPriceCache = () => {
    priceCache.clear();
    loadedMarketHashesRef.current.clear();
  };

  useEffect(() => {
    if (selectedGame) fetchInventory();
  }, [selectedGame, fetchInventory]);

  return {
    inventory,
    loading,
    error,
    selectedItems,
    itemPrices,
    loadingItems,
    handleItemSelect,
    handleSelectAll,
    startLoadingPrices,
    updateItemPrice,
    setPriceMinusOneCent,
    clearPrices,
    clearPriceCache,
    fetchInventory,
    setError,
    setSelectedItems,
  };
}
