// components/inventory/TradeModal.tsx

import { useState } from "react";
import {
  Send,
  Link2,
  AlertCircle,
  Loader2,
  CheckCircle,
  XCircle,
  Package,
  ChevronDown,
} from "lucide-react";
import { Modal } from "../Modal";
import { SteamAccountInfo } from "@/types";

interface TradeModalProps {
  currency: string;
  accounts: SteamAccountInfo[];
  isOpen: boolean;
  onClose: () => void;
  selectedCount: number;
  totalPrice: number; // добавить
  onSendTrade: (tradeUrl: string) => Promise<void>;
  notification: { type: "success" | "error"; message: string } | null;
  error: string | null;
  sending: boolean;
}

export function TradeModal({
  currency,
  accounts,
  isOpen,
  onClose,
  selectedCount,
  totalPrice,
  onSendTrade,
  notification,
  error,
  sending,
}: TradeModalProps) {
  const [tradeUrl, setTradeUrl] = useState("");
  const [selectedAccount, setSelectedAccount] =
    useState<SteamAccountInfo | null>(null);

  const handleSend = () => {
    if (tradeUrl.trim()) {
      onSendTrade(tradeUrl);
    }
  };

  const sortedAccount = accounts.filter(
    (acc) => !acc.bans.community && !acc.bans.kt,
  );

  const handleSelectAccount = (selectedTradeUrl: string) => {
    setSelectedAccount(
      sortedAccount.find(
        (acc) => acc.profileData.tradelink?.toString() === selectedTradeUrl,
      ) || null,
    );
    setTradeUrl(selectedTradeUrl);
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Send Trade Offer"
      icon={<Send className="w-5 h-5 text-blue-400" />}
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors cursor-pointer"
          >
            Cancel
          </button>
          <button
            onClick={handleSend}
            disabled={sending || !tradeUrl.trim()}
            className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 cursor-pointer disabled:opacity-50"
          >
            {sending ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                Sending Trade...
              </>
            ) : (
              <>
                <Send size={16} />
                Send Trade Offer
              </>
            )}
          </button>
        </div>
      }
      maxWidth="md"
    >
      <div className="p-4 space-y-4">
        {notification && (
          <div
            className={`p-3 rounded-lg flex items-center gap-2 ${
              notification.type === "success"
                ? "bg-emerald-500/20 border border-emerald-500 text-emerald-400"
                : "bg-red-500/20 border border-red-500 text-red-400"
            }`}
          >
            {notification.type === "success" ? (
              <CheckCircle size={18} />
            ) : (
              <XCircle size={18} />
            )}
            <span className="text-sm">{notification.message}</span>
          </div>
        )}

        <div className="bg-gray-800/50 rounded-lg p-3">
          <div className="flex items-center gap-2 mb-2">
            <Package size={16} className="text-blue-400" />
            <span className="text-sm font-medium text-white">
              Selected Items
            </span>
          </div>
          <div className="text-sm text-gray-300">
            {selectedCount} item(s) will be sent in this trade offer
          </div>
          {/* Отображение общей стоимости, если есть */}
          {totalPrice > 0 && (
            <div className="mt-2 pt-2 border-t border-gray-700">
              <div className="flex justify-between items-center">
                <span className="text-sm text-gray-400">Estimated total:</span>
                <span className="text-sm font-semibold text-emerald-400">
                  {totalPrice.toFixed(2)}
                  {currency}
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-1">
                * Based on the prices you entered for each item
              </p>
            </div>
          )}
        </div>

        {/* Блок выбора аккаунта (dropdown) */}
        {sortedAccount.length > 0 && (
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Select from your account
            </label>
            <div className="relative">
              <select
                value={selectedAccount?.profileData.tradelink?.toString() || ""}
                onChange={(e) => handleSelectAccount(e.target.value)}
                className="w-full pl-3 pr-8 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white appearance-none focus:outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer"
              >
                <option value="">-- Choose an account --</option>
                {sortedAccount.map((acc) => (
                  <option
                    style={{
                      color:
                        acc.tags.length === 1 ? acc.tags[0].color : undefined,
                    }}
                    key={acc.accountName}
                    value={acc.profileData.tradelink?.toString()}
                    //@ts-ignore
                    onChange={(e) => handleSelectAccount(e.target.value)}
                  >
                    {acc.accountName}{" "}
                  </option>
                ))}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
            </div>
          </div>
        )}

        {/* Поле ручного ввода */}
        <div>
          <label className="block text-sm font-medium text-gray-300 mb-2">
            Trade Offer URL
          </label>
          <div className="relative">
            <Link2 className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              value={tradeUrl}
              onChange={(e) => setTradeUrl(e.target.value)}
              placeholder="https://steamcommunity.com/tradeoffer/new/?partner=..."
              className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <p className="mt-1 text-xs text-gray-500">
            You can paste any trade URL or select one from your bots above.
          </p>
        </div>

        <div className="p-3 bg-blue-500/10 rounded-lg border border-blue-500/30">
          <div className="flex items-start gap-2">
            <AlertCircle
              size={16}
              className="text-blue-400 mt-0.5 flex-shrink-0"
            />
            <div className="text-xs text-gray-400">
              <p className="mb-1">Important:</p>
              <ul className="list-disc list-inside space-y-0.5 ml-1">
                <li>Trade offers require confirmation from the recipient</li>
                <li>Items will be removed from your inventory</li>
                <li>You can check trade status in your Steam account</li>
              </ul>
            </div>
          </div>
        </div>

        {error && (
          <div className="p-2 bg-red-500/20 border border-red-500 rounded-lg text-red-400 text-sm">
            {error}
          </div>
        )}
      </div>
    </Modal>
  );
}
