import { TrendingUp, TrendingDown } from "lucide-react";
import { Modal } from "../Modal";
import { PriceModalType, SelectedItemWithPrice } from "@/types";
interface PriceDetailsModalProps {
  isOpen: boolean;
  onClose: () => void;
  item: SelectedItemWithPrice | null;
  modalType: PriceModalType;
  formatPrice: (price: number, prefix?: string, suffix?: string) => string;
}

export function PriceDetailsModal({
  isOpen,
  onClose,
  item,
  modalType,
  formatPrice,
}: PriceDetailsModalProps) {
  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={
        modalType === "instant" ? "Instant Sell Prices" : "Market Price Details"
      }
      icon={
        modalType === "instant" ? (
          <TrendingUp className="w-5 h-5 text-green-400" />
        ) : (
          <TrendingDown className="w-5 h-5 text-red-400" />
        )
      }
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors cursor-pointer"
          >
            Close
          </button>
        </div>
      }
      maxWidth="md"
    >
      <div className="p-4 space-y-4">
        {item && (
          <>
            <div className="flex items-center gap-3 p-3 bg-gray-800/50 rounded-lg">
              <div className="w-12 h-12 flex-shrink-0">
                <img
                  src={`https://community.cloudflare.steamstatic.com/economy/image/${item.icon_url}`}
                  alt={item.market_hash_name}
                  className="w-full h-full object-contain"
                  onError={(e) => {
                    e.currentTarget.src =
                      "https://steamcommunity.com/images/icon_loading.gif";
                  }}
                />
              </div>
              <div className="flex-1">
                <div className="font-medium text-white">
                  {item.market_hash_name}
                </div>
                <div className="text-xs text-gray-400">{item.type}</div>
              </div>
            </div>

            {modalType === "instant" && item.fullOrderSpread?.buy_orders && (
              <div>
                <h3 className="text-sm font-medium text-gray-300 mb-3 flex items-center gap-2">
                  <TrendingUp size={14} className="text-green-400" />
                  Buy Orders (Highest to Lowest)
                </h3>
                <div className="space-y-2 max-h-64 overflow-y-auto">
                  {item.fullOrderSpread.buy_orders.map((order, idx) => (
                    <div
                      key={idx}
                      className="flex justify-between items-center p-2 bg-gray-800/30 rounded-lg"
                    >
                      <span className="text-sm text-green-400 font-medium">
                        {formatPrice(
                          order.price,
                          item.fullOrderSpread?.price_prefix || "",
                          item.fullOrderSpread?.price_suffix || "",
                        )}
                      </span>
                      <span className="text-xs text-gray-400">
                        Quantity: {order.quantity}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {modalType === "market" && item.fullOrderSpread?.sell_orders && (
              <div>
                <h3 className="text-sm font-medium text-gray-300 mb-3 flex items-center gap-2">
                  <TrendingDown size={14} className="text-red-400" />
                  Sell Orders (Lowest to Highest)
                </h3>
                <div className="space-y-2 max-h-64 overflow-y-auto">
                  {item.fullOrderSpread.sell_orders.map((order, idx) => (
                    <div
                      key={idx}
                      className="flex justify-between items-center p-2 bg-gray-800/30 rounded-lg"
                    >
                      <span className="text-sm text-red-400 font-medium">
                        {formatPrice(
                          order.price,
                          item.fullOrderSpread?.price_prefix || "",
                          item.fullOrderSpread?.price_suffix || "",
                        )}
                      </span>
                      <span className="text-xs text-gray-400">
                        Quantity: {order.quantity}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </Modal>
  );
}
