// pages/ProfilePage.tsx
import { useState } from "react";
import {
  User,
  Edit2,
  X,
  Shield,
  Clock,
  AlertCircle,
  MapPin,
  Users,
  Loader2,
  Lock,
  Eye,
  Settings,
  Gamepad,
  Save,
  Wallet,
  Ban,
  CheckCircle,
  ShoppingCart,
  ChevronDown,
  ChevronUp,
} from "lucide-react";
import { SteamAccountInfo } from "../types";
import { accountApi } from "../services/api";
import { AuthenticationRequired } from "../components/AuthenticationRequired";
import { useAccountLogin } from "@/hooks/use-account-login";
import { PrivacyModal } from "@/components/PrivacyModal";

interface ProfilePageProps {
  account: SteamAccountInfo | null;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
}

interface EditableProfileData {
  name: string;
  realName: string;
  summary: string;
  country: string | null;
  customURL: string;
}

interface PrivacySettings {
  profile: string;
}

interface CountryOption {
  code: string;
  name: string;
}

const STATIC_COUNTRIES: CountryOption[] = [
  { code: "RU", name: "Russia" },
  { code: "US", name: "United States" },
  { code: "GB", name: "United Kingdom" },
  { code: "DE", name: "Germany" },
  { code: "FR", name: "France" },
  { code: "CA", name: "Canada" },
  { code: "AU", name: "Australia" },
  { code: "JP", name: "Japan" },
  { code: "CN", name: "China" },
  { code: "BR", name: "Brazil" },
];

// Вспомогательный компонент для сворачиваемого списка игр
const CollapsibleList = ({
  items,
  limit = 20,
}: {
  items: { appid: number; name: string }[];
  limit?: number;
}) => {
  const [expanded, setExpanded] = useState(false);
  const displayed = expanded ? items : items.slice(0, limit);
  const hasMore = items.length > limit;
  return (
    <div className="space-y-1">
      {displayed.map((game) => (
        <div key={game.appid} className="text-sm text-gray-300 truncate">
          {game.name}{" "}
          <span className="text-gray-500 text-xs">({game.appid})</span>
        </div>
      ))}
      {hasMore && (
        <button
          onClick={() => setExpanded(!expanded)}
          className="text-xs text-indigo-400 hover:text-indigo-300 flex items-center gap-1 mt-1"
        >
          {expanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
          {expanded ? "Show less" : `Show ${items.length - limit} more`}
        </button>
      )}
    </div>
  );
};

// Вспомогательный компонент для строки "ключ-значение"
const InfoRow = ({
  label,
  value,
  icon,
}: {
  label: string;
  value: React.ReactNode;
  icon?: React.ReactNode;
}) => (
  <div className="flex justify-between items-start py-2 border-b border-gray-700/50 last:border-0">
    <span className="text-gray-400 text-sm flex items-center gap-1">
      {icon && <span className="w-4 h-4 text-gray-500">{icon}</span>}
      {label}:
    </span>
    <span className="text-white text-sm text-right break-all max-w-[60%]">
      {value}
    </span>
  </div>
);

export function ProfilePage({ account, onUpdateAccount }: ProfilePageProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [countries] = useState<CountryOption[]>(STATIC_COUNTRIES);
  const [isPrivacyModalOpen, setIsPrivacyModalOpen] = useState(false);
  const [showAllGames, setShowAllGames] = useState(false);

  const [editedData, setEditedData] = useState<EditableProfileData>({
    name: account?.profileData?.name || "",
    realName: account?.profileData?.realName || "",
    summary: account?.profileData?.summary || "",
    country: null,
    customURL: account?.profileData?.profileUrl ?? "",
  });
  const { handleLogin, loggingIn, loginError } = useAccountLogin({
    account,
    onUpdateAccount,
  });

  const [privacySettings, setPrivacySettings] = useState<PrivacySettings>({
    profile: account?.profileData?.visibilityState?.toString() || "3",
  });

  if (!account?.cookies) {
    return (
      <AuthenticationRequired
        text="You need to be logged in to manage profile settings."
        handleLogin={handleLogin}
        loggingIn={loggingIn}
        loginError={loginError}
      />
    );
  }

  if (!account) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center text-gray-400">No account selected</div>
      </div>
    );
  }

  const handleEditClick = () => {
    setEditedData({
      name: account.profileData?.name || "",
      realName: account.profileData?.realName || "",
      summary: account.profileData?.summary || "",
      country: null,
      customURL: account.profileData?.profileUrl ?? "",
    });
    setIsEditing(true);
  };

  const handleSavePrivacySettings = async (settings: PrivacySettings) => {
    try {
      const result = await accountApi.editPrivacySettings(
        account.accountName,
        settings,
      );
      if (result.success) {
        setPrivacySettings({ profile: settings.profile });
      }
    } catch (err) {
      console.error("Failed to save privacy settings:", err);
      throw err;
    }
  };

  const handleCancelEdit = () => {
    setIsEditing(false);
    setEditedData({
      name: account.profileData?.name || "",
      realName: account.profileData?.realName || "",
      summary: account.profileData?.summary || "",
      country: null,
      customURL: account.profileData?.profileUrl ?? "",
    });
  };

  const handleSaveProfile = async () => {
    setIsSaving(true);
    try {
      let customUrlValue = editedData.customURL;
      if (customUrlValue) {
        const match = customUrlValue.match(/\/(id|profiles)\/([^\/?]+)/i);
        if (match && match[2]) {
          customUrlValue = match[2];
        }
        if (customUrlValue.match(/^\d+$/)) {
          customUrlValue = "";
        }
      }

      const result = await accountApi.editProfile(account.accountName, {
        name: editedData.name,
        realName: editedData.realName,
        summary: editedData.summary,
        country: editedData.country ?? undefined,
        customURL: customUrlValue || undefined,
      });

      if (result.success) {
        setEditedData({
          name: editedData.name,
          realName: editedData.realName,
          summary: editedData.summary,
          country: editedData.country ?? "",
          customURL: customUrlValue || "",
        });
        setIsEditing(false);
      }
    } catch (err) {
      console.error("Failed to save profile:", err);
    } finally {
      setIsSaving(false);
    }
  };

  const formatDate = (date?: Date) => {
    if (!date) return "Unknown";
    return date.toLocaleDateString();
  };

  const getStatusBadge = () => {
    switch (account.status) {
      case "online":
        return { text: "Online", color: "bg-emerald-500/20 text-emerald-400" };
      case "offline":
        return { text: "Offline", color: "bg-gray-500/20 text-gray-400" };
      case "farm":
        return { text: "Farming", color: "bg-indigo-500/20 text-indigo-400" };
      case "logining":
        return {
          text: "Logging in...",
          color: "bg-yellow-500/20 text-yellow-400",
        };
      default:
        return { text: "Unknown", color: "bg-gray-500/20 text-gray-400" };
    }
  };

  const status = getStatusBadge();

  // Режим редактирования оставлен без изменений (только внешний вид)
  if (isEditing) {
    return (
      <div className="max-w-4xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold">Edit Profile</h1>
          <button
            onClick={handleCancelEdit}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 cursor-pointer"
          >
            <X size={16} />
            Cancel
          </button>
        </div>

        <div className="bg-gray-800/40 rounded-lg p-6 space-y-4">
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-300">
              Profile Name
            </label>
            <input
              type="text"
              value={editedData.name}
              onChange={(e) =>
                setEditedData({ ...editedData, name: e.target.value })
              }
              className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-300">
              Real Name
            </label>
            <input
              type="text"
              value={editedData.realName}
              onChange={(e) =>
                setEditedData({ ...editedData, realName: e.target.value })
              }
              placeholder="Enter your real name"
              className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-300">Country</label>
            <select
              value={editedData.country ?? ""}
              onChange={(e) =>
                setEditedData({ ...editedData, country: e.target.value })
              }
              className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
            >
              <option value="">Select country</option>
              {countries.map((country) => (
                <option key={country.code} value={country.code}>
                  {country.name}
                </option>
              ))}
            </select>
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-300">
              About Me
            </label>
            <textarea
              value={editedData.summary}
              onChange={(e) =>
                setEditedData({ ...editedData, summary: e.target.value })
              }
              placeholder="Tell something about yourself..."
              rows={4}
              className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none"
            />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-sm font-medium text-gray-300">
              Custom URL
            </label>
            <input
              type="text"
              value={editedData.customURL}
              onChange={(e) =>
                setEditedData({ ...editedData, customURL: e.target.value })
              }
              placeholder="steamcommunity.com/id/your-custom-url"
              className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <p className="text-xs text-gray-500">
              Only letters, numbers, and underscores
            </p>
          </div>
          <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-gray-700">
            <button
              onClick={handleCancelEdit}
              className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleSaveProfile}
              disabled={isSaving}
              className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 disabled:opacity-50"
            >
              {isSaving ? (
                <Loader2 size={16} className="animate-spin" />
              ) : (
                <Save size={16} />
              )}
              Save Changes
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ========== РЕЖИМ ПРОСМОТРА (расширенный) ==========
  return (
    <div className="max-w-6xl mx-auto px-4">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Profile</h1>
        <div className="flex gap-2">
          <button
            onClick={() => setIsPrivacyModalOpen(true)}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 cursor-pointer"
          >
            <Settings size={16} />
            Privacy
          </button>
          <button
            onClick={handleEditClick}
            className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 cursor-pointer"
          >
            <Edit2 size={16} />
            Edit Profile
          </button>
        </div>
      </div>

      {/* Основная карточка профиля (оставлена без изменений, но можно улучшить) */}
      <div className="bg-gray-800/40 rounded-lg overflow-hidden mb-6">
        <div className="h-32 bg-gradient-to-r from-indigo-600/30 to-purple-600/30" />
        <div className="px-6 pb-6">
          <div className="flex flex-col md:flex-row gap-6 -mt-12">
            <div className="flex-shrink-0">
              <div className="w-24 h-24 rounded-full bg-gray-700 border-4 border-gray-800 overflow-hidden">
                {account.profileData?.avatar ? (
                  <img
                    src={account.profileData.avatar}
                    alt={account.profileData.name || account.accountName}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-indigo-600/30">
                    <User size={40} className="text-indigo-400" />
                  </div>
                )}
              </div>
            </div>
            <div className="flex-1">
              <div className="flex flex-wrap items-center gap-3 mb-2">
                <h2 className="text-2xl font-bold text-white">
                  {account.profileData?.name || account.accountName}
                </h2>
                <span
                  className={`px-2 py-0.5 rounded-full text-xs font-medium ${status.color}`}
                >
                  {status.text}
                </span>
              </div>
              <p className="text-gray-400 text-sm">
                Steam ID: {account.steamid}
              </p>
              <p className="text-gray-400 text-sm">
                Account Name: {account.accountName}
              </p>
            </div>
            <div className="flex-shrink-0 text-center">
              <div className="w-16 h-16 rounded-full bg-indigo-600/20 border-2 border-indigo-500 flex items-center justify-center">
                <span className="text-2xl font-bold text-indigo-400">
                  {account.profileData?.level || 0}
                </span>
              </div>
              <p className="text-xs text-gray-400 mt-1">Steam Level</p>
            </div>
          </div>

          <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-4">
            <InfoRow
              label="Real Name"
              value={
                account.profileData?.realName || (
                  <span className="text-gray-500 italic">Not set</span>
                )
              }
              icon={<User size={12} />}
            />
            <InfoRow
              label="Country"
              value={
                account.profileData?.country || (
                  <span className="text-gray-500 italic">Not set</span>
                )
              }
              icon={<MapPin size={12} />}
            />
            <InfoRow
              label="Member Since"
              value={formatDate(account.profileData?.memberSince)}
              icon={<Clock size={12} />}
            />
            <div className="col-span-full">
              <InfoRow
                label="About Me"
                value={
                  account.profileData?.summary || (
                    <span className="text-gray-500 italic">
                      No description provided
                    </span>
                  )
                }
                icon={<AlertCircle size={12} />}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Дополнительные секции (сетка 1-2 колонки) */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Кошелёк */}
        {account.balance && account.hasWallet && (
          <div className="bg-gray-800/40 rounded-lg p-5">
            <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
              <Wallet size={18} className="text-emerald-400" />
              Steam Wallet
            </h3>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span className="text-gray-400">Balance:</span>
                <span className="text-emerald-400 font-medium">
                  {account.balance.formattedBalance}
                </span>
              </div>
              {account.balance.usdbalance > 0 && (
                <div className="flex justify-between">
                  <span className="text-gray-400">≈ USD:</span>
                  <span className="text-white">
                    ${account.balance.usdbalance.toFixed(2)}
                  </span>
                </div>
              )}
              <div className="flex justify-between">
                <span className="text-gray-400">Last updated:</span>
                <span className="text-white text-sm">
                  {account.balance.lastUpdated?.toLocaleString() || "Unknown"}
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Баны */}
        <div className="bg-gray-800/40 rounded-lg p-5">
          <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
            <Ban size={18} className="text-red-400" />
            Bans
          </h3>
          <div className="space-y-2">
            <div className="flex justify-between">
              <span className="text-gray-400">VAC:</span>
              <span
                className={
                  account.bans?.vac
                    ? "text-red-400 font-medium"
                    : "text-green-400"
                }
              >
                {account.bans?.vac ? "Banned" : "Clean"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Game Ban:</span>
              <span
                className={
                  account.bans?.game ? "text-red-400" : "text-green-400"
                }
              >
                {account.bans?.game ? "Yes" : "No"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Community Ban:</span>
              <span
                className={
                  account.bans?.community ? "text-red-400" : "text-green-400"
                }
              >
                {account.bans?.community ? "Yes" : "No"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Trade Ban (KT):</span>
              <span
                className={account.bans?.kt ? "text-red-400" : "text-green-400"}
              >
                {account.bans?.kt ? "Yes" : "No"}
              </span>
            </div>
            {account.bans?.appids && account.bans.appids.length > 0 && (
              <div className="flex justify-between">
                <span className="text-gray-400">Banned games:</span>
                <span className="text-white text-right">
                  {account.bans.appids.join(", ")}
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Ограничения и статус */}
        <div className="bg-gray-800/40 rounded-lg p-5">
          <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
            <Shield size={18} className="text-indigo-400" />
            Account Restrictions
          </h3>
          <div className="space-y-2">
            <div className="flex justify-between">
              <span className="text-gray-400">Limited Account:</span>
              <span
                className={
                  account.limited ? "text-yellow-400" : "text-green-400"
                }
              >
                {account.limited ? "Yes" : "No"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Email Validated:</span>
              <span
                className={
                  account.emailValidated ? "text-green-400" : "text-red-400"
                }
              >
                {account.emailValidated ? "Yes" : "No"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Cookies (Session):</span>
              <span
                className={account.cookies ? "text-green-400" : "text-red-400"}
              >
                {account.cookies ? "Active" : "Missing"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Wallet Enabled:</span>
              <span
                className={
                  account.hasWallet ? "text-green-400" : "text-gray-400"
                }
              >
                {account.hasWallet ? "Yes" : "No"}
              </span>
            </div>
            {account.ipAddress && (
              <div className="flex justify-between">
                <span className="text-gray-400">Public IP:</span>
                <span className="text-white font-mono text-xs">
                  {account.ipAddress}
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Активность на рынке */}
        {(account.activeOrders !== null || account.activeListings !== null) && (
          <div className="bg-gray-800/40 rounded-lg p-5">
            <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
              <ShoppingCart size={18} className="text-cyan-400" />
              Market Activity
            </h3>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span className="text-gray-400">Active Listings:</span>
                <span className="text-white">
                  {account.activeListings ?? "—"}
                </span>
              </div>
              <div className="flex justify-between">
                <span className="text-gray-400">Active Buy Orders:</span>
                <span className="text-white">
                  {account.activeOrders ?? "—"}
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Подтверждения */}
        <div className="bg-gray-800/40 rounded-lg p-5">
          <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
            <CheckCircle size={18} className="text-blue-400" />
            Auto‑confirmation Settings
          </h3>
          <div className="space-y-2">
            <div className="flex justify-between">
              <span className="text-gray-400">Trade Confirmations:</span>
              <span
                className={
                  account.confirmations?.trade
                    ? "text-green-400"
                    : "text-gray-400"
                }
              >
                {account.confirmations?.trade ? "Enabled" : "Disabled"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Market Confirmations:</span>
              <span
                className={
                  account.confirmations?.market
                    ? "text-green-400"
                    : "text-gray-400"
                }
              >
                {account.confirmations?.market ? "Enabled" : "Disabled"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">System Confirmations:</span>
              <span
                className={
                  account.confirmations?.system
                    ? "text-green-400"
                    : "text-gray-400"
                }
              >
                {account.confirmations?.system ? "Enabled" : "Disabled"}
              </span>
            </div>
            <div className="flex justify-between">
              <span className="text-gray-400">Accept Gift/Trade:</span>
              <span
                className={
                  account.confirmations?.acceptGiftTrade
                    ? "text-green-400"
                    : "text-gray-400"
                }
              >
                {account.confirmations?.acceptGiftTrade
                  ? "Enabled"
                  : "Disabled"}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Владельческие игры (ownedGames) */}
      {account.ownedGames && account.ownedGames.length > 0 && (
        <div className="mt-6 bg-gray-800/40 rounded-lg p-5">
          <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
            <Gamepad size={18} className="text-purple-400" />
            Owned Games ({account.ownedGames.length})
          </h3>
          <CollapsibleList items={account.ownedGames} limit={20} />
        </div>
      )}

      {/* Дополнительная информация о подтверждениях (steamid, identity secret) */}
      <div className="mt-6 text-center text-xs text-gray-500 border-t border-gray-700 pt-4">
        <div className="flex justify-center gap-4 flex-wrap">
          <span>Account ID: {account.accountid}</span>
          {account.identity_secret && (
            <span className="text-emerald-400">2FA Secret: Active</span>
          )}
          {account.sharedSecret && (
            <span className="text-emerald-400">Shared Secret: Present</span>
          )}
        </div>
      </div>

      {isPrivacyModalOpen && (
        <PrivacyModal
          isOpen={isPrivacyModalOpen}
          onClose={() => setIsPrivacyModalOpen(false)}
          onSave={handleSavePrivacySettings}
          initialSettings={privacySettings}
          isSaving={isSaving}
        />
      )}
    </div>
  );
}
