// components/LoginWithTOTPButton.tsx
import { useEffect, useState } from "react";
import { Key, Shield, AlertCircle, AlertTriangle } from "lucide-react";
import { Modal } from "../Modal";
import { accountApi } from "@/services/api";

interface LoginWithTOTPButtonProps {
  accountName: string;
  password: string;
}

export function LoginWithTOTPButton({
  accountName,
  password,
}: LoginWithTOTPButtonProps) {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [totpCode, setTotpCode] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  // Handle auto-submit when code reaches 5 characters
  useEffect(() => {
    if (totpCode.length === 5 && !isLoading) {
      handleSubmit();
    }
  }, [totpCode]); // This will trigger when totpCode changes to length 5
  const handleCodeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value
      .toUpperCase()
      .replace(/[^A-Z0-9]/g, "")
      .slice(0, 5);
    setTotpCode(value);
    setError("");
  };
  const handleSubmit = async () => {
    setIsLoading(true);
    setError("");

    try {
      // Now using the updated state
      const response = await accountApi.loginWithTOTP(
        accountName,
        password,
        totpCode, // This will be the correct 5-character code
      );

      if (!response) {
        throw new Error(response || "Failed to login");
      }

      handleCloseModal();
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Invalid code. Please try again.",
      );
      setTotpCode("");
    } finally {
      setIsLoading(false);
    }
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTotpCode("");
    setError("");
    setIsLoading(false);
  };

  return (
    <>
      {/* Warning and Button Container */}
      <div className="flex flex-col items-end gap-1.5">
        {/* Login Button */}
        <button
          onClick={() => setIsModalOpen(true)}
          className="inline-flex items-center gap-1.5 rounded-md bg-indigo-500/10 px-2 py-1 text-[10px] font-medium text-indigo-400 hover:bg-indigo-500/20 transition-colors whitespace-nowrap cursor-pointer"
          aria-label="Login with Steam Guard"
        >
          <Key size={10} />
          Login via Guard Code
        </button>
      </div>

      {/* Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={handleCloseModal}
        title="Login with TOTP Code"
        icon={<Shield className="w-5 h-5" />}
        maxWidth="md"
      >
        <div className="p-6 space-y-4">
          {/* Account Information */}
          <div className="bg-gray-800/50 rounded-lg p-3 space-y-2">
            <div className="flex justify-between items-center text-sm">
              <span className="text-gray-400">Account:</span>
              <span className="text-white font-medium">{accountName}</span>
            </div>
            <div className="flex justify-between items-center text-sm">
              <span className="text-gray-400">Password:</span>
              <span className="text-white font-mono text-xs">
                {"•".repeat(Math.min(password?.length || 0, 10))}
              </span>
            </div>
          </div>

          {/* TOTP Input Field */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-gray-300 flex items-center gap-2">
              <Key className="w-4 h-4" />
              Steam Guard Code
            </label>
            <div className="relative">
              <input
                type="text"
                value={totpCode}
                onChange={handleCodeChange}
                className={`
                  w-full bg-gray-800 border rounded-lg px-4 py-3 text-center text-2xl
                  font-mono tracking-wider text-white placeholder-gray-500 uppercase
                  focus:outline-none focus:ring-2 transition-all duration-200
                  ${
                    error
                      ? "border-red-500 focus:ring-red-500/30 focus:border-red-500"
                      : "border-gray-700 focus:ring-indigo-500/30 focus:border-indigo-500"
                  }
                `}
                placeholder="A1B2C"
                maxLength={5}
                autoFocus
                disabled={isLoading}
              />

              {/* Input Indicator */}
              <div className="absolute inset-y-0 right-3 flex items-center gap-1.5">
                {[...Array(5)].map((_, i) => (
                  <div
                    key={i}
                    className={`h-1.5 rounded-full transition-all duration-200 ${
                      i < totpCode.length
                        ? "w-3 bg-indigo-500"
                        : "w-1.5 bg-gray-600"
                    }`}
                  />
                ))}
              </div>
            </div>

            <p className="text-[11px] text-gray-500">
              Enter 5-character Steam Guard code (letters A-Z and numbers 0-9)
            </p>
          </div>

          {/* Error Message */}
          {error && (
            <div className="flex items-center gap-2 text-red-400 text-sm bg-red-500/10 rounded-lg px-3 py-2">
              <AlertCircle className="w-4 h-4" />
              <span>{error}</span>
            </div>
          )}

          {/* Loading Indicator */}
          {isLoading && (
            <div className="flex items-center justify-center gap-2 text-indigo-400 text-sm">
              <div className="w-4 h-4 border-2 border-indigo-400/30 border-t-indigo-400 rounded-full animate-spin" />
              <span>Logging in...</span>
            </div>
          )}

          {/* Info Text */}
          <div className="text-center text-[10px] text-gray-600 pt-2">
            Code will be submitted automatically after entering 5 characters
          </div>
        </div>
      </Modal>
    </>
  );
}
