import { useState } from "react";
import {
  Home,
  Activity,
  TrendingUp,
  Package,
  RefreshCw,
  Menu,
  X,
  Power,
  Logs,
  Terminal,
} from "lucide-react";
import { cn } from "../lib/utils";
import { AccountControlModal } from "./AccountControlModal";
import { SteamAccountInfo } from "@/types";

interface SidebarProps {
  activePage: string;
  onPageChange: (page: string) => void;
  accounts: SteamAccountInfo[];
  onToggleAccount?: (accountName: string, enabled: boolean) => void;
  onStartFarming?: (accountName: string) => void;
}

// Основные пункты меню (верхняя часть)
const mainMenuItems = [
  { id: "main", label: "Main", icon: Home },
  { id: "market", label: "Market", icon: TrendingUp },
  { id: "trade", label: "Trade", icon: RefreshCw },
  { id: "inventory", label: "Inventory", icon: Package },
  { id: "activity", label: "Activity", icon: Activity },
];

// Нижние пункты (отображаются перед футером)
const bottomMenuItems = [{ id: "logs", label: "Logs", icon: Terminal }];

export function Sidebar({ activePage, onPageChange, accounts }: SidebarProps) {
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handlePageChange = (pageId: string) => {
    onPageChange(pageId);
    setIsMobileMenuOpen(false);
  };

  return (
    <>
      {/* Оверлей для мобильного меню */}
      {isMobileMenuOpen && (
        <div
          className="fixed inset-0 z-40 bg-black/80 lg:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Сайдбар */}
      <div
        className={cn(
          "fixed lg:relative z-50 bg-steam-dark text-white flex flex-col border-r border-gray-700 transition-all duration-300 ease-in-out",
          "lg:flex",
          isMobileMenuOpen ? "flex" : "hidden lg:flex",
          isCollapsed ? "w-20" : "w-64",
        )}
      >
        {/* Header с бургер-кнопкой */}
        <div
          className={cn(
            "p-4 border-b border-gray-700 flex items-center",
            isCollapsed ? "justify-center" : "justify-between gap-2",
          )}
        >
          {!isCollapsed ? (
            <div className="flex w-full">
              <div className="pl-1">
                <button
                  onClick={() => setIsCollapsed(!isCollapsed)}
                  className="flex items-center bg-steam-light p-1 border-gray-600 hover:bg-steam-blue transition-colors"
                  title="Развернуть меню"
                >
                  <Menu size={20} />
                </button>
              </div>
              <div className="flex ml-1.5">
                <p className="text-xl text-gray-200 font-bold bg-gradient-to-r from-indigo-400 to-emerald-400 bg-clip-text">
                  Steam
                </p>
                <p className="text-xl text-gray-200 font-bold bg-gradient-to-r from-indigo-400 to-emerald-400 bg-clip-text">
                  Node
                </p>
              </div>
            </div>
          ) : (
            <button
              onClick={() => setIsCollapsed(!isCollapsed)}
              className="flex items-center bg-steam-light p-1 border-gray-600 hover:bg-steam-blue transition-colors"
              title="Развернуть меню"
            >
              <Menu size={20} />
            </button>
          )}
        </div>

        {/* Основная навигация (Control + верхние пункты) */}
        <nav className="flex-1 py-4">
          <button
            onClick={() => setIsModalOpen(true)}
            className={cn(
              "w-full flex items-center transition-all duration-100 mb-2",
              "hover:bg-steam-light hover:text-white",
              "text-emerald-400 border-l-4 border-emerald-500",
              isCollapsed ? "justify-center px-2 py-3" : "px-6 py-3 gap-3",
            )}
            title={isCollapsed ? "Control" : undefined}
          >
            <Power size={20} className="shrink-0" />
            <span
              className={cn(
                "font-medium whitespace-nowrap transition-opacity duration-100",
                isCollapsed ? "opacity-0 w-0 hidden" : "opacity-100",
              )}
            >
              Control
            </span>
          </button>

          {mainMenuItems.map((item) => {
            const Icon = item.icon;
            const isActive = activePage === item.id;
            return (
              <button
                key={item.id}
                onClick={() => handlePageChange(item.id)}
                className={cn(
                  "w-full flex items-center transition-all duration-100",
                  "hover:bg-steam-light hover:text-white",
                  isActive
                    ? "bg-steam-blue text-white border-l-4 border-emerald-500"
                    : "text-gray-300",
                  isCollapsed ? "justify-center px-2 py-3" : "px-6 py-3 gap-3",
                )}
                title={isCollapsed ? item.label : undefined}
              >
                <Icon size={20} className="shrink-0" />
                <span
                  className={cn(
                    "font-medium whitespace-nowrap transition-opacity duration-100",
                    isCollapsed ? "opacity-0 w-0 hidden" : "opacity-100",
                  )}
                >
                  {item.label}
                </span>
              </button>
            );
          })}
        </nav>

        {/* Нижние пункты (перед футером) */}
        <div className="py-2">
          {bottomMenuItems.map((item) => {
            const Icon = item.icon;
            const isActive = activePage === item.id;
            return (
              <button
                key={item.id}
                onClick={() => handlePageChange(item.id)}
                className={cn(
                  "w-full flex items-center transition-all duration-100",
                  "hover:bg-steam-light hover:text-white",
                  isActive
                    ? "bg-steam-blue text-white border-l-4 border-emerald-500"
                    : "text-gray-300",
                  isCollapsed ? "justify-center px-2 py-3" : "px-6 py-3 gap-3",
                )}
                title={isCollapsed ? item.label : undefined}
              >
                <Icon size={20} className="shrink-0" />
                <span
                  className={cn(
                    "font-medium whitespace-nowrap transition-opacity duration-100",
                    isCollapsed ? "opacity-0 w-0 hidden" : "opacity-100",
                  )}
                >
                  {item.label}
                </span>
              </button>
            );
          })}
        </div>

        {/* Footer */}
        <div
          className={cn(
            "p-4 border-t border-gray-700",
            isCollapsed && "text-center",
          )}
        >
          {!isCollapsed ? (
            <>
              <p className="text-xs text-gray-500">Beta v1.0.3</p>
              <p className="text-xs text-gray-500 mt-1">Support: @s3x4ct</p>
            </>
          ) : (
            <div className="w-8 h-8 mx-auto rounded-full bg-gray-700 flex items-center justify-center">
              <span className="text-xs text-gray-400">v1</span>
            </div>
          )}
        </div>
      </div>

      {/* Кнопка-бургер для мобильных устройств */}
      <button
        onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        className="fixed top-4 left-4 z-50 rounded-lg bg-steam-dark p-2 text-white lg:hidden border border-gray-700"
      >
        {isMobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
      </button>

      {/* Отступ для контента на мобильных */}
      <div className="lg:hidden h-14" />

      {/* Модальное окно управления аккаунтами */}
      <AccountControlModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        accounts={accounts}
      />
    </>
  );
}
