// components/Market/OrdersTab.tsx
import { useMemo } from "react";
import { ShoppingCart, XCircle } from "lucide-react";
import { MarketOrder } from "../../types";
import { LoadingSpinner } from "../LoadingSpinner";

interface OrdersTabProps {
  orders: MarketOrder[];
  loading: boolean;
  searchQuery: string;
  processingId: string | null;
  onCancelOrder: (order: MarketOrder) => void;
}

const formatPrice = (price: string | null) => {
  if (!price) return "N/A";
  return price;
};

export function OrdersTab({
  orders,
  loading,
  searchQuery,
  processingId,
  onCancelOrder,
}: OrdersTabProps) {
  const filteredOrders = useMemo(() => {
    if (!searchQuery.trim()) return orders;
    const query = searchQuery.toLowerCase();
    return orders.filter((order) => order.title.toLowerCase().includes(query));
  }, [orders, searchQuery]);

  if (loading) {
    return <LoadingSpinner message="Loading active buy orders..." />;
  }

  return (
    <div className="bg-gray-800/40 rounded-lg p-6">
      <h2 className="text-xl font-semibold mb-4">
        Active Buy Orders
        {searchQuery && (
          <span className="text-sm text-gray-400 ml-2">
            (filtered from {orders.length})
          </span>
        )}
      </h2>

      {filteredOrders.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <ShoppingCart size={48} className="mx-auto mb-4 opacity-50" />
          <p>
            {searchQuery
              ? `No orders found matching "${searchQuery}"`
              : "No active buy orders"}
          </p>
          <p className="text-sm mt-2">
            {searchQuery
              ? "Try a different search term"
              : "Purchase orders you create will appear here"}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {filteredOrders.map((order) => (
            <div
              key={order.order_id}
              className="flex items-center justify-between p-4 bg-gray-700/30 rounded-lg hover:bg-gray-700/50 transition-colors"
            >
              <div className="flex items-center gap-4 flex-1 min-w-0">
                {order.image && (
                  <img
                    src={order.image}
                    alt={order.title}
                    className="w-12 h-12 rounded object-cover flex-shrink-0"
                    onError={(e) => (e.currentTarget.style.display = "none")}
                  />
                )}
                <div className="flex-1 min-w-0">
                  <h3 className="font-medium text-white truncate">
                    {order.title}
                  </h3>
                  <div className="flex items-center gap-4 mt-1 text-xs text-gray-400">
                    <span>{order.game}</span>
                    <span>Quantity: {order.quantity || "N/A"}</span>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-4 flex-shrink-0">
                <div className="text-right">
                  <div className="text-sm text-gray-400">
                    {formatPrice(order.price_per_unit)} / item
                  </div>
                  <div className="text-lg font-semibold text-emerald-400">
                    Total: {formatPrice(order.total_value)}
                  </div>
                </div>
                <button
                  onClick={() => onCancelOrder(order)}
                  disabled={processingId === order.order_id}
                  className="p-2 rounded-lg bg-red-500/20 text-red-400 hover:bg-red-500/30 transition-colors disabled:opacity-50"
                  title="Cancel order"
                >
                  {processingId === order.order_id ? (
                    <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <XCircle size={18} />
                  )}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
