import { cn } from "../lib/utils";
import {
  Wallet,
  Users,
  Shield,
  Package,
  RefreshCcw,
  RefreshCw,
} from "lucide-react";
import { ECurrencyCode } from "../types";
import { ActiveCard } from "../types/index.ts";

interface DashboardCardsProps {
  activeCard: ActiveCard;
  onCardClick: (card: ActiveCard) => void;
  totalBalanceUSD: number;
  balances: Map<number, number>;
  accountStats: {
    total: number;
    online: number;
    farm: number;
    offline: number;
    nolimited: number;
    limited: number;
    withoutWallet: number;
  };
  banStats: {
    total: number;
    vacBans: number;
    gameBans: number;
    tradeBans: number;
  };
  totalInventoryItems: number;
  totalInventoryValue: number;
  cheapItemsCount: number;
  topGames: { gameId: string; gameName: string; count: number }[];
  onRefreshInventory?: () => void; // опционально для кнопки обновления
  loadingInventory: boolean;
}

export function DashboardCards({
  activeCard,
  onCardClick,
  totalBalanceUSD,
  balances,
  accountStats,
  banStats,
  cheapItemsCount,
  totalInventoryItems,
  totalInventoryValue,
  topGames,
  onRefreshInventory,
  loadingInventory,
}: DashboardCardsProps) {
  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
      {/* Total Balance Card */}
      <div
        onClick={() => onCardClick("balance")}
        className={cn(
          "rounded-lg border border-indigo-500/20 hover:border-indigo-500 hover:to-emerald-500/80 bg-gradient-to-br from-indigo-500/5 to-emerald-500/5 p-4 cursor-pointer transition-all duration-200",
          activeCard === "balance" &&
            "ring-2 ring-indigo-500 ring-offset-2 ring-offset-background",
        )}
      >
        <div className="flex items-center gap-2 mb-3">
          <div className="rounded-md bg-indigo-500/10 p-1.5">
            <Wallet className="h-4 w-4 text-indigo-400" />
          </div>
          <h3 className="text-sm font-medium text-muted-foreground">
            Total Balance
          </h3>
        </div>
        <p className="text-2xl font-bold mb-4">
          $
          {typeof totalBalanceUSD === "number"
            ? totalBalanceUSD.toFixed(2)
            : "0.00"}
        </p>
        <div>
          {balances.size > 0 ? (
            Array.from(balances.entries()).map(([currency, value]) => (
              <div key={currency} className="flex justify-between text-xs">
                <span className="text-muted-foreground">
                  {ECurrencyCode[currency]}:
                </span>
                <span className="font-medium text-emerald-400">
                  {value?.toLocaleString() ?? "0"}
                </span>
              </div>
            ))
          ) : (
            <div className="text-xs text-muted-foreground text-center py-2">
              No wallet data available
            </div>
          )}
        </div>
        {accountStats.withoutWallet > 0 && (
          <div className="mt-2 text-xs text-muted-foreground border-t border-indigo-500/20 pt-2">
            {accountStats.withoutWallet} account(s) without wallet
          </div>
        )}
      </div>

      {/* Accounts Card */}
      <div
        onClick={() => onCardClick("accounts")}
        className={cn(
          "rounded-lg border border-indigo-500/20 hover:border-indigo-500 hover:to-purple-500/80 bg-gradient-to-br from-indigo-500/5 to-purple-500/5 p-4 cursor-pointer transition-all duration-200",
          activeCard === "accounts" &&
            "ring-2 ring-indigo-500 ring-offset-2 ring-offset-background",
        )}
      >
        <div className="flex items-center gap-2 mb-3">
          <div className="rounded-md bg-indigo-500/10 p-1.5">
            <Users className="h-4 w-4 text-indigo-400" />
          </div>
          <h3 className="text-sm font-medium text-muted-foreground">
            Accounts
          </h3>
        </div>
        <p className="text-2xl font-bold">{accountStats.total}</p>
        <div className="mt-3 space-y-1.5">
          <div className="flex justify-between text-xs">
            <span className="text-muted-foreground">Online</span>
            <span className="font-medium text-emerald-400">
              {accountStats.online}
            </span>
          </div>
          <div className="flex justify-between text-xs">
            <span className="text-muted-foreground">Farming</span>
            <span className="font-medium text-blue-400">
              {accountStats.farm}
            </span>
          </div>
          <div className="flex justify-between text-xs">
            <span className="text-muted-foreground">Offline</span>
            <span className="font-medium text-gray-400">
              {accountStats.offline}
            </span>
          </div>
          <div className="mt-3 grid gap-2 border-t border-indigo-500/20 pt-2">
            <div className="flex justify-between text-xs">
              <span className="text-muted-foreground">No Limit Accounts:</span>
              <span className="font-medium text-emerald-400">
                {accountStats.nolimited}
              </span>
            </div>
            <div className="flex justify-between text-xs">
              <span className="text-muted-foreground">Limited accounts</span>
              <span className="font-medium text-yellow-400">
                {accountStats.limited}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Bans Card */}
      <div
        onClick={() => onCardClick("bans")}
        className={cn(
          "rounded-lg border border-red-500/20 hover:border-red-500 hover:to-orange-500/80 bg-gradient-to-br from-red-500/5 to-orange-500/5 p-4 cursor-pointer transition-all duration-200",
          activeCard === "bans" &&
            "ring-2 ring-red-500 ring-offset-2 ring-offset-background",
        )}
      >
        <div className="flex items-center gap-2 mb-3">
          <div className="rounded-md bg-red-500/10 p-1.5">
            <Shield className="h-4 w-4 text-red-400" />
          </div>
          <h3 className="text-sm font-medium text-muted-foreground">Bans</h3>
        </div>
        <p className="text-2xl font-bold text-red-400">{banStats.total}</p>
        <div className="mt-3 space-y-1.5">
          <div className="flex justify-between text-xs">
            <span className="text-muted-foreground">VAC Bans</span>
            <span className="font-medium text-red-400">{banStats.vacBans}</span>
          </div>
          <div className="flex justify-between text-xs">
            <span className="text-muted-foreground">Game Bans</span>
            <span className="font-medium text-orange-400">
              {banStats.gameBans}
            </span>
          </div>
          <div className="flex justify-between text-xs">
            <span className="text-muted-foreground">Trade Bans</span>
            <span className="font-medium text-yellow-400">
              {banStats.tradeBans}
            </span>
          </div>
        </div>
      </div>

      {/* Inventory Card */}
      <div
        className={cn(
          "rounded-lg border border-emerald-500/20 hover:border-emerald-500 p-4 ",
        )}
      >
        <div className="flex items-center gap-2 mb-3">
          <div className="rounded-md bg-emerald-500/10 p-1.5">
            <Package className="h-4 w-4 text-emerald-400" />
          </div>
          <div className="w-full flex items-center justify-between">
            <h3 className="text-sm font-medium text-muted-foreground">
              Inventory
            </h3>
            {onRefreshInventory && (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  onRefreshInventory();
                }}
                className="mt-1 text-emerald-400  hover:text-emerald-200 cursor-pointer"
              >
                <RefreshCw
                  size={22}
                  className={loadingInventory ? "animate-spin" : ""}
                />
              </button>
            )}
          </div>
        </div>
        <p className="text-2xl font-bold text-emerald-400">
          ${totalInventoryValue.toFixed(2)}
        </p>
        {totalInventoryItems !== 0 ? (
          <p className="text-xs text-muted-foreground mt-0.5">
            {totalInventoryItems
              ? `Items: ${totalInventoryItems.toLocaleString()}`
              : "Need Refresh"}
          </p>
        ) : (
          <span className="text-muted-foreground text-xs">
            Automatically receive current prices
          </span>
        )}
        {totalInventoryItems !== 0 && (
          <div className="mt-3 pt-2 border-t border-emerald-500/20">
            <div className="flex justify-between text-xs">
              <span className="text-muted-foreground">
                Items priced {"<"} 0.1$:
              </span>

              <span className="text-yellow-400 font-medium">
                {cheapItemsCount}
              </span>
            </div>
          </div>
        )}
        <div className="mt-3">
          {topGames.length > 0 &&
            topGames.map((game) => (
              <div
                key={game.gameId}
                className="flex justify-between text-xs mt-1"
              >
                <span className="truncate max-w-[100px]">{game.gameName}</span>
                <span className="text-emerald-400 font-medium">
                  {game.count.toLocaleString()}
                </span>
              </div>
            ))}
        </div>
      </div>
    </div>
  );
}
