// components/inventory/InventoryGrid.tsx
import {
  Package,
  Search,
  Filter,
  Clock,
  Ban,
  CheckCircle,
  Lock,
} from "lucide-react";
import { SteamAccountInfo, SteamInventoryItem } from "../../types";
import { InventoryItem } from "./InventoryItem";
import { cn } from "@/lib/utils";
import { useState } from "react";

type FilterType =
  | "all"
  | "available"
  | "locked"
  | "tradable_only"
  | "marketable_only";

interface InventoryGridProps {
  account: SteamAccountInfo;
  inventory: SteamInventoryItem[];
  loading: boolean;
  error: string | null;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  handleSelectAll: () => void;
  selectedItems: Set<string>;
  onItemSelect: (assetId: string) => void;
  onSellClick: () => void;
  onTradeClick: () => void;
  selectedCount: number;
}

export function InventoryGrid({
  account,
  inventory,
  loading,
  error,
  searchQuery,
  onSearchChange,
  selectedItems,
  onItemSelect,
  onSellClick,
  onTradeClick,
  selectedCount,
}: InventoryGridProps) {
  const [filterType, setFilterType] = useState<FilterType>("all");
  const [showFilters, setShowFilters] = useState(false);

  const isItemSelectable = (item: SteamInventoryItem) => {
    return item.tradable === true || item.marketable === true;
  };

  const filteredInventory = inventory.filter((item) => {
    const matchesSearch =
      item.market_hash_name
        ?.toLowerCase()
        .includes(searchQuery.toLowerCase()) ||
      item.name?.toLowerCase().includes(searchQuery.toLowerCase());

    if (!matchesSearch) return false;

    const isTradable = item.tradable === true;
    const isMarketable = item.marketable === true;
    const isLocked = !isTradable && !isMarketable;
    const isFullyAvailable = isTradable && isMarketable;

    switch (filterType) {
      case "available":
        return isFullyAvailable;
      case "locked":
        return isLocked;
      case "tradable_only":
        return isTradable && !isMarketable;
      case "marketable_only":
        return isMarketable && !isTradable;
      default:
        return true;
    }
  });

  const stats = {
    total: inventory.length,
    available: inventory.filter(
      (i) => i.tradable === true && i.marketable === true,
    ).length,
    locked: inventory.filter(
      (i) => i.tradable !== true && i.marketable !== true,
    ).length,
    tradableOnly: inventory.filter(
      (i) => i.tradable === true && i.marketable !== true,
    ).length,
    marketableOnly: inventory.filter(
      (i) => i.marketable === true && i.tradable !== true,
    ).length,
  };

  const availableSelectedCount = Array.from(selectedItems).filter((assetId) => {
    const item = inventory.find((i) => i.assetid === assetId);
    return item && isItemSelectable(item);
  }).length;

  const handleSelectAllAvailable = () => {
    const selectableItems = filteredInventory.filter((item) =>
      isItemSelectable(item),
    );
    const allSelected = selectableItems.every((item) =>
      selectedItems.has(item.assetid),
    );

    if (allSelected) {
      selectableItems.forEach((item) => {
        if (selectedItems.has(item.assetid)) {
          onItemSelect(item.assetid);
        }
      });
    } else {
      selectableItems.forEach((item) => {
        if (!selectedItems.has(item.assetid)) {
          onItemSelect(item.assetid);
        }
      });
    }
  };

  const filters = [
    {
      value: "all",
      label: "All",
      icon: Package,
      count: stats.total,
      color: "gray",
    },
    {
      value: "available",
      label: "Available",
      icon: CheckCircle,
      count: stats.available,
      color: "emerald",
    },
    {
      value: "tradable_only",
      label: "Trade Only",
      icon: Ban,
      count: stats.tradableOnly,
      color: "blue",
    },
    {
      value: "marketable_only",
      label: "Market Only",
      icon: Ban,
      count: stats.marketableOnly,
      color: "yellow",
    },
    {
      value: "locked",
      label: "Locked",
      icon: Lock,
      count: stats.locked,
      color: "red",
    },
  ];

  if (loading) {
    return (
      <div className="bg-gray-800/40 rounded-xl p-8">
        <div className="flex flex-col items-center justify-center">
          <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-purple-500 mx-auto mb-3"></div>
          <div className="text-gray-400 text-sm">Loading inventory...</div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-500/10 border border-red-500/50 rounded-xl p-4 text-center">
        <div className="text-red-400 text-sm">{error}</div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Search and Actions Bar */}
      <div className="flex flex-col md:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-3.5 h-3.5 text-gray-400" />
          <input
            type="text"
            placeholder="Search items..."
            value={searchQuery}
            onChange={(e) => onSearchChange(e.target.value)}
            className="w-full pl-9 pr-3 py-2 bg-gray-800/80 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent"
          />
        </div>

        <div className="flex gap-2">
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={cn(
              "px-3 py-2 rounded-lg text-xs font-medium transition-all flex items-center gap-1.5",
              showFilters
                ? "bg-purple-600 text-white"
                : "bg-gray-800/80 text-gray-300 hover:bg-gray-700/80 border border-gray-700",
            )}
          >
            <Filter size={14} />
            Filters
          </button>

          <button
            onClick={handleSelectAllAvailable}
            disabled={
              filteredInventory.filter((i) => isItemSelectable(i)).length === 0
            }
            className="px-3 py-2 rounded-lg text-xs font-medium transition-all disabled:opacity-50 flex items-center gap-1.5 bg-gray-800/80 text-gray-300 hover:bg-gray-700/80 border border-gray-700"
          >
            <Package size={14} />
            Select Available
          </button>

          <button
            onClick={onSellClick}
            disabled={availableSelectedCount === 0}
            className="px-4 py-2 bg-gradient-to-r from-emerald-600 to-emerald-500 hover:from-emerald-500 hover:to-emerald-400 rounded-lg text-xs font-medium transition-all disabled:opacity-50 flex items-center gap-1.5"
          >
            Sell ({availableSelectedCount})
          </button>

          <button
            onClick={onTradeClick}
            disabled={
              availableSelectedCount === 0 ||
              !account.sharedSecret ||
              !account.identity_secret
            }
            className="px-4 py-2 bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-500 hover:to-blue-400 rounded-lg text-xs font-medium transition-all disabled:opacity-50 flex items-center gap-1.5"
          >
            Trade ({availableSelectedCount})
          </button>
        </div>
      </div>

      {/* Filters Panel */}
      {showFilters && (
        <div className="bg-gray-800/60 rounded-lg p-3 border border-gray-700/50">
          <div className="flex flex-wrap gap-1.5">
            {filters.map((filter) => {
              const Icon = filter.icon;
              const isActive = filterType === filter.value;
              const colorMap = {
                emerald:
                  "border-emerald-500/30 bg-emerald-500/10 text-emerald-400",
                blue: "border-blue-500/30 bg-blue-500/10 text-blue-400",
                yellow: "border-yellow-500/30 bg-yellow-500/10 text-yellow-400",
                red: "border-red-500/30 bg-red-500/10 text-red-400",
                gray: "border-gray-500/30 bg-gray-500/10 text-gray-400",
              };
              return (
                <button
                  key={filter.value}
                  onClick={() => setFilterType(filter.value as FilterType)}
                  className={cn(
                    "px-2.5 py-1 rounded-md text-[11px] font-medium transition-all flex items-center gap-1.5 border",
                    isActive
                      ? colorMap[filter.color as keyof typeof colorMap]
                      : "bg-gray-900/50 border-gray-700 text-gray-400 hover:bg-gray-800/50",
                  )}
                >
                  <Icon size={12} />
                  {filter.label}
                  <span
                    className={cn(
                      "px-1 rounded text-[10px]",
                      isActive ? "bg-white/20" : "bg-gray-700/50",
                    )}
                  >
                    {filter.count}
                  </span>
                </button>
              );
            })}
          </div>
        </div>
      )}

      {/* Warning for locked items */}
      {availableSelectedCount < selectedCount && (
        <div className="p-2 bg-amber-500/10 border border-amber-500/30 rounded-lg text-amber-400 text-xs flex items-center gap-1.5">
          <Clock size={12} />
          {selectedCount - availableSelectedCount} item(s) cannot be traded or
          sold
        </div>
      )}

      {/* Inventory Grid */}
      {filteredInventory.length === 0 ? (
        <div className="bg-gray-800/40 rounded-xl p-8 text-center">
          <Package size={32} className="mx-auto mb-2 opacity-50" />
          <p className="text-gray-400 text-sm">
            {searchQuery || filterType !== "all"
              ? "No items match your filters"
              : "No items in inventory"}
          </p>
        </div>
      ) : (
        <>
          <div className="text-xs text-gray-400">
            {filteredInventory.length} items
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-2">
            {filteredInventory.map((item) => (
              <InventoryItem
                key={item.assetid}
                item={item}
                isSelected={selectedItems.has(item.assetid)}
                onSelect={onItemSelect}
                isSelectable={isItemSelectable(item)}
              />
            ))}
          </div>
        </>
      )}
    </div>
  );
}
