import { useState, useCallback } from "react";
import { SteamAccountInfo } from "../types";
import { accountApi } from "@/services/api";

interface UseAccountLoginOptions {
  account: SteamAccountInfo | null;
  onUpdateAccount?: (updatedAccount: SteamAccountInfo) => void;
}

interface UseAccountLoginResult {
  handleLogin: () => Promise<void>;
  loggingIn: boolean;
  loginError: string | null;
}

export const useAccountLogin = ({
  account,
  onUpdateAccount,
}: UseAccountLoginOptions): UseAccountLoginResult => {
  const [loggingIn, setLoggingIn] = useState(false);
  const [loginError, setLoginError] = useState<string | null>(null);

  const handleLogin = useCallback(async () => {
    if (!account || loggingIn) return;
    setLoggingIn(true);
    setLoginError(null);
    try {
      const result = await accountApi.login([account.accountName]);
      if (result.success) {
        const updatedAccount: SteamAccountInfo = {
          ...account,
          cookies: true,
          status: "online",
        };
        if (onUpdateAccount) onUpdateAccount(updatedAccount);
      } else {
        setLoginError(result.error || "Failed to login");
      }
    } catch (err) {
      setLoginError("Network error. Please try again.");
    } finally {
      setLoggingIn(false);
    }
  }, [account, loggingIn, onUpdateAccount]);

  return { handleLogin, loggingIn, loginError };
};
