// components/inventory/InventoryItem.tsx
import {
  Check,
  Clock,
  Package2,
  Shield,
  X,
  AlertCircle,
  Star,
  TrendingUp,
  Award,
  Calendar,
  Timer,
} from "lucide-react";
import { SteamInventoryItem } from "../../types";
import { cn } from "@/lib/utils";
import { useState, useEffect } from "react";

interface InventoryItemProps {
  item: SteamInventoryItem;
  isSelected: boolean;
  onSelect: (assetId: string) => void;
  isSelectable: boolean;
}

// Универсальная функция для парсинга даты из описаний для любых игр
// Универсальная функция для парсинга даты из описаний для любых игр
function parseUnlockDate(item: SteamInventoryItem): Date | null {
  // Проверяем owner_descriptions (здесь обычно хранятся сообщения о блокировке)
  if (item.owner_descriptions && Array.isArray(item.owner_descriptions)) {
    for (const desc of item.owner_descriptions) {
      if (desc.value && typeof desc.value === "string") {
        const value = desc.value;

        // Новый формат: "⇆ This item is trade-protected and cannot be consumed, modified, or transferred until May 19, 2026 (7:00:00) GMT"
        let match = value.match(/until\s+([A-Za-z]+ \d{1,2},? \d{4})/i);
        if (match) {
          const dateStr = match[1].replace(",", "");
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }

        // Другой вариант того же формата с временем: "until May 19, 2026 (7:00:00)"
        match = value.match(
          /until\s+([A-Za-z]+ \d{1,2},? \d{4})\s*\([\d:]+\)/i,
        );
        if (match) {
          const dateStr = match[1].replace(",", "");
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }

        // Расширенный поиск любой даты в строке (формат: Month DD, YYYY)
        match = value.match(/([A-Za-z]+ \d{1,2},? \d{4})/);
        if (match) {
          const dateStr = match[1].replace(",", "");
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            // Дополнительно проверяем, что контекст действительно о блокировке
            const lowerValue = value.toLowerCase();
            if (
              lowerValue.includes("trade") ||
              lowerValue.includes("transfer") ||
              lowerValue.includes("protected") ||
              lowerValue.includes("cooldown")
            ) {
              return date;
            }
          }
        }

        // Формат Dota 2 из owner_descriptions
        // "On Trade Cooldown Until: Wed May 20 04:00:00 2026"
        match = value.match(
          /On Trade Cooldown Until:\s*(.+?)(?:\s*GMT|\s*UTC|$)/i,
        );
        if (match) {
          const dateStr = match[1].trim();
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }

        // Формат CS:GO / CS2
        match = value.match(/Tradable\/Marketable After\s+(.+?)\s*GMT/i);
        if (match) {
          const dateStr = match[1];
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }

        // Формат: "Tradable After ..."
        match = value.match(/Tradable After\s+(.+?)\s*GMT/i);
        if (match) {
          const dateStr = match[1];
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }
      }
    }
  }

  // Проверяем descriptions
  if (item.descriptions && Array.isArray(item.descriptions)) {
    for (const desc of item.descriptions) {
      if (desc.value && typeof desc.value === "string") {
        const value = desc.value;

        // Формат из descriptions
        let match = value.match(/until\s+([A-Za-z]+ \d{1,2},? \d{4})/i);
        if (match) {
          const dateStr = match[1].replace(",", "");
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }

        // Формат Dota 2
        match = value.match(/On Trade Cooldown Until:\s*(.+?)(?:\)|$)/i);
        if (match) {
          const dateStr = match[1].trim();
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }

        // Формат Team Fortress 2
        match = value.match(/Tradable After:\s*(.+?)\s*GMT/i);
        if (match) {
          const dateStr = match[1];
          const date = new Date(dateStr);
          if (!isNaN(date.getTime())) {
            return date;
          }
        }
      }
    }
  }

  // Проверяем cache_expiration
  if (item?.cache_expiration) {
    const date = new Date(item.cache_expiration);
    if (!isNaN(date.getTime())) {
      return date;
    }
  }

  // Проверяем market_tradable_restriction (количество дней блокировки)
  if (
    item.market_tradable_restriction &&
    typeof item.market_tradable_restriction === "number"
  ) {
    // Если есть restriction в днях, вычисляем дату
    const date = new Date();
    date.setDate(date.getDate() + item.market_tradable_restriction);
    return date;
  }

  return null;
}

// Компонент для обратного отсчета
function CountdownTimer({ targetDate }: { targetDate: Date }) {
  const [timeLeft, setTimeLeft] = useState<string>("");

  useEffect(() => {
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = targetDate.getTime() - now;

      if (distance < 0) {
        setTimeLeft("Available now");
        clearInterval(interval);
      } else {
        const days = Math.floor(distance / (1000 * 60 * 60 * 24));
        const hours = Math.floor(
          (distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60),
        );
        const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));

        if (days > 0) {
          setTimeLeft(`${days}d ${hours}h`);
        } else if (hours > 0) {
          setTimeLeft(`${hours}h ${minutes}m`);
        } else {
          setTimeLeft(`${minutes}m`);
        }
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [targetDate]);

  return (
    <div className="flex items-center justify-center gap-1 text-[10px] text-amber-400 font-mono">
      <Timer className="w-3 h-3 animate-pulse" />
      <span>{timeLeft}</span>
    </div>
  );
}

// Функция для получения цвета редкости (градиент)
function getRarityGradient(rarityName?: string): string {
  if (!rarityName) return "from-gray-800 to-gray-900";

  const rarityMap: Record<string, string> = {
    "Consumer Grade": "from-gray-700 via-gray-600 to-gray-700",
    "Industrial Grade": "from-blue-900 via-blue-800 to-blue-900",
    "Mil-Spec Grade": "from-blue-700 via-blue-600 to-blue-700",
    Restricted: "from-purple-800 via-purple-700 to-purple-800",
    Classified: "from-pink-800 via-pink-700 to-pink-800",
    Covert: "from-red-800 via-red-700 to-red-800",
    Contraband: "from-orange-700 via-orange-600 to-orange-700",
    "Base Grade": "from-gray-700 via-gray-600 to-gray-700",
    "High Grade": "from-blue-700 via-blue-600 to-blue-700",
    Remarkable: "from-purple-800 via-purple-700 to-purple-800",
    Exotic: "from-pink-800 via-pink-700 to-pink-800",
    Extraordinary: "from-red-800 via-red-700 to-red-800",
    Common: "from-gray-700 via-gray-600 to-gray-700",
    Rare: "from-blue-700 via-blue-600 to-blue-700",
    Mythical: "from-purple-800 via-purple-700 to-purple-800",
    Legendary: "from-pink-800 via-pink-700 to-pink-800",
    Arcana: "from-red-800 via-red-700 to-red-800",
    Ancient: "from-orange-700 via-orange-600 to-orange-700",
    Unique: "from-yellow-800 via-yellow-700 to-yellow-800",
  };

  return rarityMap[rarityName] || "from-gray-800 to-gray-900";
}

// Функция для получения цвета текста редкости
function getRarityTextColor(rarityName?: string): string {
  if (!rarityName) return "text-gray-400";

  const colorMap: Record<string, string> = {
    "Consumer Grade": "text-gray-300",
    "Industrial Grade": "text-blue-300",
    "Mil-Spec Grade": "text-blue-400",
    Restricted: "text-purple-400",
    Classified: "text-pink-400",
    Covert: "text-red-400",
    "Base Grade": "text-gray-300",
    "High Grade": "text-blue-400",
    Remarkable: "text-purple-400",
    Exotic: "text-pink-400",
    Extraordinary: "text-red-400",
    Common: "text-gray-300",
    Rare: "text-blue-400",
    Mythical: "text-purple-400",
    Legendary: "text-pink-400",
    Arcana: "text-red-400",
    Ancient: "text-orange-400",
    Unique: "text-yellow-400",
  };

  return colorMap[rarityName] || "text-gray-400";
}

// Функция для получения иконки редкости
function getRarityIcon(rarityName?: string) {
  if (!rarityName) return null;

  if (
    rarityName.includes("Consumer") ||
    rarityName.includes("Base") ||
    rarityName.includes("Common")
  )
    return <Package2 size={12} />;
  if (
    rarityName.includes("Industrial") ||
    rarityName.includes("High") ||
    rarityName.includes("Rare")
  )
    return <TrendingUp size={12} />;
  if (
    rarityName.includes("Mil-Spec") ||
    rarityName.includes("Remarkable") ||
    rarityName.includes("Mythical")
  )
    return <Award size={12} />;
  if (
    rarityName.includes("Restricted") ||
    rarityName.includes("Exotic") ||
    rarityName.includes("Legendary")
  )
    return <Star size={12} />;
  if (
    rarityName.includes("Classified") ||
    rarityName.includes("Extraordinary") ||
    rarityName.includes("Arcana")
  )
    return <Award size={12} />;
  if (
    rarityName.includes("Covert") ||
    rarityName.includes("Ancient") ||
    rarityName.includes("Unique")
  )
    return <Star size={12} />;

  return null;
}

export function InventoryItem({
  item,
  isSelected,
  onSelect,
  isSelectable,
}: InventoryItemProps) {
  const isTradable = item.tradable === true;
  const isMarketable = item.marketable === true;

  // Получаем дату разблокировки
  const unlockDate = parseUnlockDate(item);
  const currentDate = new Date();
  const isUnlockDatePassed = unlockDate ? unlockDate <= currentDate : false;

  // Определяем статус предмета
  const isFullyLocked = !isTradable && !isMarketable;
  const isPartiallyLocked =
    (isTradable && !isMarketable) || (!isTradable && isMarketable);

  // Если есть дата разблокировки и она еще не прошла, то предмет временно заблокирован
  const isTemporarilyLocked =
    (isFullyLocked || isPartiallyLocked) && unlockDate && !isUnlockDatePassed;
  const isPermanentlyLocked =
    (isFullyLocked || isPartiallyLocked) && !unlockDate;

  // Актуальный статус доступности (с учетом прошедшей даты)
  const actualIsTradable =
    isTradable || (isTemporarilyLocked && isUnlockDatePassed);
  const actualIsMarketable =
    isMarketable || (isTemporarilyLocked && isUnlockDatePassed);

  const rarityTag = item.tags?.find((tag) => tag.category === "Rarity");
  const rarityName = rarityTag?.name;
  const rarityGradient = getRarityGradient(rarityName);
  const rarityTextColor = getRarityTextColor(rarityName);
  const RarityIcon = getRarityIcon(rarityName);

  const exteriorTag = item.tags?.find((tag) => tag.category === "Exterior");
  const exteriorName = exteriorTag?.name;

  const typeTag = item.tags?.find((tag) => tag.category === "Type");
  const typeName = typeTag?.name;

  // Получаем специальный значок (★ для ножей)
  const qualityTag = item.tags?.find((tag) => tag.category === "Quality");
  const hasStar = qualityTag?.name === "★";

  const displayName = item.market_hash_name || item.name || "Unknown Item";

  const iconUrl = item.icon_url
    ? `https://community.akamai.steamstatic.com/economy/image/${item.icon_url}/360fx360f`
    : null;

  const handleCardClick = () => {
    if (isSelectable && !isPermanentlyLocked && !isTemporarilyLocked) {
      onSelect(item.assetid);
    }
  };

  // Определяем статус для отображения
  // В компоненте InventoryItem, обновите определение статусов
  const getTradeStatus = () => {
    // Сначала проверяем наличие owner_descriptions с сообщением о защите
    const hasProtectionMessage = item.owner_descriptions?.some(
      (desc: any) =>
        desc.value &&
        (desc.value.includes("trade-protected") ||
          desc.value.includes("On Trade Cooldown") ||
          desc.value.includes("Tradable After")),
    );

    // Если есть сообщение о защите, но дата уже прошла
    if (
      hasProtectionMessage &&
      isTemporarilyLocked &&
      unlockDate &&
      isUnlockDatePassed
    ) {
      return {
        text: "Available",
        color: "text-emerald-400",
        icon: <Check className="w-3.5 h-3.5" />,
      };
    }

    if (actualIsTradable && !hasProtectionMessage)
      return {
        text: "Available",
        color: "text-emerald-400",
        icon: <Check className="w-3.5 h-3.5" />,
      };

    if (isTemporarilyLocked && unlockDate)
      return {
        text: ``,
        color: "text-amber-400",
        icon: <Clock className="w-3.5 h-3.5" />,
      };

    return {
      text: "Never",
      color: "text-red-400",
      icon: <X className="w-3.5 h-3.5" />,
    };
  };

  const getMarketStatus = () => {
    // Аналогичная проверка для маркета
    const hasProtectionMessage = item.owner_descriptions?.some(
      (desc: any) =>
        desc.value &&
        (desc.value.includes("trade-protected") ||
          desc.value.includes("On Trade Cooldown") ||
          desc.value.includes("Tradable After")),
    );

    if (
      hasProtectionMessage &&
      isTemporarilyLocked &&
      unlockDate &&
      isUnlockDatePassed
    ) {
      return {
        text: "Available",
        color: "text-emerald-400",
        icon: <Check className="w-3.5 h-3.5" />,
      };
    }

    if (actualIsMarketable)
      return {
        text: "Available",
        color: "text-emerald-400",
        icon: <Check className="w-3.5 h-3.5" />,
      };

    if (isTemporarilyLocked && unlockDate)
      return {
        text: ``,
        color: "text-amber-400",
        icon: <Clock className="w-3.5 h-3.5" />,
      };

    return {
      text: "Never",
      color: "text-red-400",
      icon: <X className="w-3.5 h-3.5" />,
    };
  };

  const tradeStatus = getTradeStatus();
  const marketStatus = getMarketStatus();

  // Можно ли выбрать предмет
  const canSelect =
    isSelectable && !isPermanentlyLocked && !isTemporarilyLocked;

  return (
    <div
      onClick={handleCardClick}
      className={cn(
        "relative rounded-xl overflow-hidden transition-all duration-200 cursor-pointer h-full flex flex-col",
        "border-2",
        isSelected && canSelect
          ? "border-emerald-500 shadow-lg shadow-emerald-500/25 scale-[1.02]"
          : "border-gray-700",
        canSelect &&
          !isSelected &&
          "hover:border-gray-500 hover:scale-[1.01] hover:shadow-lg",
        (isPermanentlyLocked || isTemporarilyLocked) &&
          "cursor-not-allowed opacity-75",
      )}
    >
      <div
        className={cn(
          "bg-gradient-to-br p-3 h-full flex flex-col",
          rarityGradient,
        )}
      >
        {/* Индикатор выбора */}
        {isSelected && canSelect && (
          <div className="absolute top-2 left-2 z-10">
            <div className="bg-emerald-500 rounded-full p-1 shadow-lg">
              <Check className="w-3 h-3 text-white" />
            </div>
          </div>
        )}

        {/* Badge статуса */}
        <div className="absolute top-2 right-2 z-10 flex gap-1">
          {hasStar && (
            <div className="bg-gradient-to-r from-amber-500 to-yellow-500 rounded-full p-1 shadow-lg">
              <Star className="w-3 h-3 text-white" />
            </div>
          )}
          {isPartiallyLocked &&
            !isTemporarilyLocked &&
            !isPermanentlyLocked && (
              <div className="bg-blue-500 rounded-full p-1 shadow-lg">
                <AlertCircle className="w-3 h-3 text-white" />
              </div>
            )}
          {isTemporarilyLocked && (
            <div className="bg-amber-500 rounded-full p-1 shadow-lg">
              <Clock className="w-3 h-3 text-white" />
            </div>
          )}
          {isPermanentlyLocked && (
            <div className="bg-red-500 rounded-full p-1 shadow-lg">
              <Shield className="w-3 h-3 text-white" />
            </div>
          )}
        </div>

        {/* Иконка предмета */}
        <div className="flex justify-center py-3">
          {iconUrl ? (
            <img
              src={iconUrl}
              alt={displayName}
              className="w-20 h-20 object-contain drop-shadow-lg"
              loading="lazy"
            />
          ) : (
            <div className="w-20 h-20 bg-gray-800/50 rounded-xl flex items-center justify-center">
              <Package2 className="w-10 h-10 text-gray-600" />
            </div>
          )}
        </div>

        {/* Название предмета */}
        <div className="text-center px-1 mb-2 flex-1">
          <h3
            className="text-sm font-bold text-white line-clamp-2 drop-shadow-md"
            title={displayName}
          >
            {hasStar && "★ "}
            {displayName}
          </h3>

          {/* Качество и тип */}
          <div className="flex items-center justify-center gap-1.5 flex-wrap mt-1.5">
            {rarityName && (
              <span
                className={cn(
                  "text-[10px] font-semibold px-2 py-0.5 rounded-full bg-black/30 flex items-center gap-1",
                  rarityTextColor,
                )}
              >
                {RarityIcon}
                {rarityName}
              </span>
            )}
            {exteriorName && (
              <span className="text-[10px] text-gray-300 bg-black/30 px-2 py-0.5 rounded-full">
                {exteriorName}
              </span>
            )}
          </div>
          {typeName && (
            <div className="text-[9px] text-gray-400 mt-1.5">{typeName}</div>
          )}
        </div>

        {/* Статусы трейда и продажи */}
        <div className="space-y-1.5 mt-2 pt-2 border-t border-white/10">
          <div className="flex items-center justify-between text-xs px-1">
            <span className="text-gray-300 font-medium">Trade</span>
            <span
              className={cn(
                "flex items-center gap-1 font-medium",
                tradeStatus.color,
              )}
            >
              {tradeStatus.icon}
              <span className="text-[10px]">{tradeStatus.text}</span>
            </span>
          </div>
          <div className="flex items-center justify-between text-xs px-1">
            <span className="text-gray-300 font-medium">Market</span>
            <span
              className={cn(
                "flex items-center gap-1 font-medium",
                marketStatus.color,
              )}
            >
              {marketStatus.icon}
              <span className="text-[10px]">{marketStatus.text}</span>
            </span>
          </div>
        </div>

        {/* Обратный отсчет для временно заблокированных предметов */}
        {isTemporarilyLocked && unlockDate && (
          <div className="mt-2 pt-2 border-t border-white/10">
            <CountdownTimer targetDate={unlockDate} />
          </div>
        )}

        {/* Информация о постоянной блокировке */}
        {isPermanentlyLocked && (
          <div className="mt-2 pt-2 border-t border-white/10 text-center">
            <div className="flex items-center justify-center gap-1 text-[10px] text-red-400">
              <Shield className="w-3 h-3" />
              <span>Permanently locked</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
