// components/AccountList/AccountActions.tsx
import { Key, CheckCircle } from "lucide-react";
import { TOTPProgress } from "./TOTPProgress";
import { cn } from "@/lib/utils";
import { SteamAccountInfo } from "@/types";
import { accountApi } from "@/services/api";

interface AccountActionsProps {
  activePage: string;
  account: SteamAccountInfo;
  isTotpActive: boolean;
  timeLeft: number;
  isSelected: boolean;
  loadingTotp?: boolean;
  onShowTOTP: (accountName: string, e: React.MouseEvent) => void;
  onConfirmations: (accountName: string, e: React.MouseEvent) => void;
}

export function AccountActions({
  account,
  activePage,
  isTotpActive,
  timeLeft,
  isSelected,
  loadingTotp,
  onShowTOTP,
  onConfirmations,
}: AccountActionsProps) {
  return (
    <div className="flex flex-col items-end gap-1.5">
      <button
        onClick={(e) => onShowTOTP(account.accountName, e)}
        className="inline-flex items-center gap-1.5 rounded-md bg-indigo-500/10 px-2 py-1 text-[10px] font-medium text-indigo-400 hover:bg-indigo-500/20 transition-colors whitespace-nowrap cursor-pointer"
        aria-label="Show Steam Guard"
      >
        {isTotpActive && !loadingTotp ? (
          <TOTPProgress timeLeft={timeLeft} size={17} />
        ) : (
          <Key size={10} />
        )}
        Steam Guard
      </button>

      {/* Confirmations Button */}
      {account.cookies && (
        <>
          <button
            onClick={(e) => onConfirmations(account.accountName, e)}
            className={cn(
              isSelected && activePage === "confirmations"
                ? "bg-emerald-500/50 text-emerald-300 hover:bg-emerald-400/20"
                : "bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20",
              "inline-flex items-center justify-center gap-1.5 rounded-md  px-2 py-1 text-[10px] font-medium  transition-colors whitespace-nowrap cursor-pointer",
            )}
            aria-label="Confirmations"
          >
            <CheckCircle size={10} />
            Confirmations
          </button>
          {account.status === "offline" && account.refreshToken && (
            <div className="flex flex-col items-end gap-1.5">
              <button
                onClick={async () =>
                  await accountApi.login([account.accountName])
                }
                className="inline-flex items-center gap-1.5 rounded-md bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 px-2 py-1 text-[10px] font-medium  transition-colors whitespace-nowrap cursor-pointer"
                aria-label="Login with Steam Guard"
              >
                <Key size={10} />
                Login via Token
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}
