// components/Store/CreateBadgeModal.tsx
import { useState, useEffect, useRef } from "react";
import {
  Search,
  Terminal,
  X,
  Award,
  AlertCircle,
  Play,
  Square,
  Clock,
  CheckSquare,
  Square as SquareIcon,
  LogIn,
} from "lucide-react";
import { SteamAccountInfo } from "@/types";
import { accountApi } from "@/services/api";

interface CreateBadgeModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: SteamAccountInfo[];
}

interface LogEntry {
  id: number;
  accountName: string;
  timestamp: string;
  status: "pending" | "success" | "error";
  message: string;
  response?: any;
}

export function CreateBadgeModal({
  isOpen,
  onClose,
  accounts,
}: CreateBadgeModalProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedAccounts, setSelectedAccounts] = useState<Set<string>>(
    new Set(),
  );
  const [gameId, setGameId] = useState("");
  const [delaySeconds, setDelaySeconds] = useState(2);
  const [isProcessing, setIsProcessing] = useState(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const stopRequestedRef = useRef(false);
  const [loggingInAccounts, setLoggingInAccounts] = useState<Set<string>>(
    new Set(),
  );

  const filteredAccounts = accounts
    .filter((acc) =>
      acc.accountName.toLowerCase().includes(searchTerm.toLowerCase()),
    )
    .filter((acc) => acc.cookies === true && acc.identity_secret)
    .sort((a, b) => {
      if (a.cookies && !b.cookies) return -1;
      if (!a.cookies && b.cookies) return 1;
      return 0;
    });

  const selectableAccounts = filteredAccounts.filter(
    (acc) => acc.cookies === true && acc.identity_secret,
  );

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  const addLog = (
    accountName: string,
    status: LogEntry["status"],
    message: string,
    response?: any,
  ) => {
    setLogs((prev) => [
      ...prev,
      {
        id: Date.now() + Math.random(),
        accountName,
        timestamp: new Date().toLocaleTimeString(),
        status,
        message,
        response,
      },
    ]);
  };

  const toggleAccount = (accountName: string) => {
    if (isProcessing) return;
    const account = accounts.find((a) => a.accountName === accountName);
    if (account && account.cookies !== true) return;
    const newSet = new Set(selectedAccounts);
    if (newSet.has(accountName)) newSet.delete(accountName);
    else newSet.add(accountName);
    setSelectedAccounts(newSet);
  };

  const selectAllFiltered = () => {
    if (isProcessing) return;
    const newSet = new Set(selectedAccounts);
    selectableAccounts.forEach((acc) => newSet.add(acc.accountName));
    setSelectedAccounts(newSet);
  };

  const deselectAllFiltered = () => {
    if (isProcessing) return;
    const newSet = new Set(selectedAccounts);
    filteredAccounts.forEach((acc) => newSet.delete(acc.accountName));
    setSelectedAccounts(newSet);
  };

  const handleManualLogin = async (accountName: string) => {
    if (isProcessing || loggingInAccounts.has(accountName)) return;
    setLoggingInAccounts((prev) => new Set(prev).add(accountName));
    addLog(accountName, "pending", "Manual login requested...");
    try {
      const result = await accountApi.login([accountName]);
      if (result?.success) {
        addLog(accountName, "success", "Manual login successful");
        addLog(
          accountName,
          "success",
          "You may need to refresh the modal to see changes.",
        );
      } else {
        addLog(
          accountName,
          "error",
          `Manual login failed: ${result?.error || "Unknown error"}`,
        );
      }
    } catch (err) {
      addLog(
        accountName,
        "error",
        `Manual login error: ${err instanceof Error ? err.message : String(err)}`,
      );
    } finally {
      setLoggingInAccounts((prev) => {
        const newSet = new Set(prev);
        newSet.delete(accountName);
        return newSet;
      });
    }
  };

  const runCreateBadges = async () => {
    if (selectedAccounts.size === 0) {
      addLog("System", "error", "No accounts selected");
      return;
    }
    if (!gameId.trim()) {
      addLog("System", "error", "Please enter a Game ID");
      return;
    }
    if (isProcessing) return;

    stopRequestedRef.current = false;
    setIsProcessing(true);
    setLogs([]);

    const accountsList = Array.from(selectedAccounts);
    let successCount = 0;
    let errorCount = 0;

    for (let i = 0; i < accountsList.length; i++) {
      if (stopRequestedRef.current) {
        addLog("System", "error", "Process interrupted by user");
        break;
      }

      const accountName = accountsList[i];
      const account = accounts.find((a) => a.accountName === accountName);
      if (!account || account.cookies !== true) {
        addLog(
          accountName,
          "error",
          "Skipped: no valid session (cookies missing)",
        );
        errorCount++;
        continue;
      }

      addLog(accountName, "pending", `Creating badge for game ${gameId}...`);
      try {
        const response = await accountApi.createBandage(accountName, gameId);
        if (stopRequestedRef.current) {
          addLog("System", "error", "Process stopped after this account");
          break;
        }
        if (response.success) {
          addLog(
            accountName,
            "success",
            `✅ Badge created successfully!`,
            response.data,
          );
          successCount++;
        } else {
          addLog(accountName, "error", `❌ Error: ${response.error}`, response);
          errorCount++;
        }
      } catch (err: any) {
        addLog(
          accountName,
          "error",
          `❌ Exception: ${err.message || "Unknown error"}`,
        );
        errorCount++;
      }

      if (stopRequestedRef.current) break;
      if (i < accountsList.length - 1 && !stopRequestedRef.current) {
        await new Promise((resolve) =>
          setTimeout(resolve, delaySeconds * 1000),
        );
      }
    }

    addLog(
      "System",
      successCount > 0 && errorCount === 0 ? "success" : "error",
      `Finished. Success: ${successCount}, Errors: ${errorCount}`,
    );
    setIsProcessing(false);
    stopRequestedRef.current = false;
  };

  const stopProcess = () => {
    if (isProcessing && !stopRequestedRef.current) {
      stopRequestedRef.current = true;
      addLog(
        "System",
        "pending",
        "⏹️ Stop requested — waiting for current account to finish...",
      );
    }
  };

  const handleClose = () => {
    if (isProcessing) {
      if (confirm("Process is running. Are you sure you want to close?")) {
        stopProcess();
        onClose();
      }
    } else {
      onClose();
    }
  };

  const getStatusColor = (status: LogEntry["status"]) => {
    switch (status) {
      case "success":
        return "text-green-400";
      case "error":
        return "text-red-400";
      case "pending":
        return "text-yellow-400";
      default:
        return "text-gray-400";
    }
  };

  const getStatusIcon = (status: LogEntry["status"]) => {
    switch (status) {
      case "success":
        return "✅";
      case "error":
        return "❌";
      case "pending":
        return "⏳";
      default:
        return "📝";
    }
  };

  if (!isOpen) return null;

  const hasSelectable = selectableAccounts.length > 0;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
      onClick={(e) =>
        e.target === e.currentTarget && !isProcessing && handleClose()
      }
    >
      <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-5xl max-h-[90vh] flex flex-col overflow-hidden border border-gray-700">
        {/* Header */}
        <div className="flex justify-between items-center p-5 border-b border-gray-700">
          <div>
            <h2 className="text-xl font-semibold text-white flex items-center gap-2">
              <Award className="w-5 h-5 text-purple-400" />
              Create Steam Badge
            </h2>
            <p className="text-xs text-gray-400 mt-1">
              Select multiple accounts – badges will be created sequentially
              with delay
            </p>
            <div className="mt-2 p-2 bg-yellow-900/30 rounded border border-yellow-700/50">
              <div className="flex items-start gap-2">
                <AlertCircle size={14} className="text-yellow-400 mt-0.5" />
                <div className="text-xs text-yellow-300">
                  <p className="font-medium">Important notes:</p>
                  <ul className="list-disc list-inside ml-2 space-y-0.5">
                    <li>
                      Before using, check card prices and set{" "}
                      <strong>INSTANT_CARD_PURCHASE_COEFFICIENT</strong> in{" "}
                      <strong>settings.json</strong>.
                    </li>
                    <li>
                      Cards may not be purchased immediately due to low buy
                      orders – this is a <strong>test version</strong>.
                    </li>
                  </ul>
                </div>
              </div>
            </div>
          </div>
          <button
            onClick={handleClose}
            disabled={isProcessing}
            className="text-gray-400 hover:text-white disabled:opacity-50"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
          {/* LEFT COLUMN – accounts */}
          <div className="w-full md:w-2/5 border-r border-gray-700 flex flex-col">
            <div className="p-4 border-b border-gray-700 space-y-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search accounts..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
                  disabled={isProcessing}
                />
              </div>
              <div className="flex gap-2">
                <button
                  onClick={selectAllFiltered}
                  disabled={isProcessing || !hasSelectable}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50"
                >
                  <CheckSquare className="w-3 h-3" /> Select all
                </button>
                <button
                  onClick={deselectAllFiltered}
                  disabled={isProcessing || filteredAccounts.length === 0}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50"
                >
                  <SquareIcon className="w-3 h-3" /> Deselect all
                </button>
              </div>
              <div className="mb-3 p-2 bg-purple-900/20 rounded-lg border border-purple-500/30">
                <div className="text-xs text-gray-300">
                  Selected:{" "}
                  <span className="text-purple-400 font-semibold">
                    {selectedAccounts.size}
                  </span>{" "}
                  account(s)
                </div>
              </div>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-2">
              {filteredAccounts.length === 0 ? (
                <div className="text-center text-gray-400 py-8 text-sm">
                  No accounts found
                </div>
              ) : (
                filteredAccounts.map((acc) => {
                  const isActive = acc.cookies === true;
                  const isChecked = selectedAccounts.has(acc.accountName);
                  const isLoggingIn = loggingInAccounts.has(acc.accountName);
                  return (
                    <div
                      key={acc.accountName}
                      className={`flex items-center gap-3 p-2 rounded-lg transition ${
                        isProcessing ? "opacity-60 cursor-not-allowed" : ""
                      }`}
                    >
                      <label
                        className={`flex items-center gap-3 flex-1 cursor-pointer ${
                          !isActive ? "opacity-70" : ""
                        }`}
                      >
                        <input
                          type="checkbox"
                          checked={isChecked}
                          onChange={() => toggleAccount(acc.accountName)}
                          disabled={isProcessing || !isActive}
                          className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-purple-500 focus:ring-purple-500 disabled:opacity-50"
                        />
                        <span className="text-sm font-medium text-white">
                          {acc.accountName}
                        </span>
                        <span className="text-xs text-gray-400 ml-auto">
                          {acc.activity?.create_badge &&
                            "last Use: " +
                              new Date(
                                acc.activity?.create_badge,
                              ).toLocaleDateString()}
                        </span>
                      </label>
                      {!isActive ? (
                        <button
                          onClick={() => handleManualLogin(acc.accountName)}
                          disabled={isProcessing || isLoggingIn}
                          className="flex items-center gap-1 px-2 py-1 text-xs rounded-md bg-purple-600/80 hover:bg-purple-500 text-white transition-colors disabled:opacity-50"
                        >
                          {isLoggingIn ? (
                            <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
                          ) : (
                            <LogIn className="w-3 h-3" />
                          )}
                          {isLoggingIn ? "Logging..." : "Login"}
                        </button>
                      ) : (
                        <span className="text-xs text-green-400 ml-auto">
                          online
                        </span>
                      )}
                    </div>
                  );
                })
              )}
            </div>
          </div>

          {/* RIGHT COLUMN – settings & logs */}
          <div className="w-full md:w-3/5 flex flex-col">
            <div className="p-4 border-b border-gray-700 space-y-3">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Game ID
                </label>
                <input
                  type="text"
                  value={gameId}
                  onChange={(e) => setGameId(e.target.value)}
                  placeholder="Enter Steam Game ID (e.g., 730 for CS:GO)"
                  className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
                  disabled={isProcessing}
                />
                <p className="text-xs text-gray-400 mt-1">
                  Numeric Steam App ID of the game
                </p>
              </div>
              <div className="flex items-center gap-4 flex-wrap">
                <div className="flex items-center gap-2">
                  <Clock className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-white">
                    Delay between accounts:
                  </span>
                </div>
                <input
                  type="number"
                  min="0"
                  max="60"
                  step="0.5"
                  value={delaySeconds}
                  onChange={(e) =>
                    setDelaySeconds(parseFloat(e.target.value) || 0)
                  }
                  disabled={isProcessing}
                  className="w-20 px-2 py-1 bg-gray-800 border border-gray-600 rounded text-white text-sm"
                />
                <span className="text-xs text-gray-400">sec</span>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-3 space-y-2 font-mono text-xs">
              <div className="flex justify-between items-center mb-2">
                <div className="flex items-center gap-2">
                  <Terminal className="w-4 h-4 text-gray-400" />
                  <span className="text-sm font-medium text-white">Logs</span>
                </div>
                <button
                  onClick={() => setLogs([])}
                  disabled={isProcessing}
                  className="text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded transition-colors disabled:opacity-50"
                >
                  Clear
                </button>
              </div>
              {logs.length === 0 ? (
                <div className="text-center text-gray-500 py-8">
                  Logs will appear here...
                </div>
              ) : (
                logs.map((log) => (
                  <div key={log.id} className="border-l-2 border-gray-700 pl-2">
                    <div className="flex items-start gap-2 flex-wrap">
                      <span className="text-gray-500 shrink-0">
                        [{log.timestamp}]
                      </span>
                      <span
                        className={`${getStatusColor(log.status)} shrink-0`}
                      >
                        {getStatusIcon(log.status)}
                      </span>
                      <span className="text-gray-300 font-semibold shrink-0">
                        {log.accountName}:
                      </span>
                      <span className="text-gray-400 break-all">
                        {log.message}
                      </span>
                    </div>
                  </div>
                ))
              )}
              <div ref={logsEndRef} />
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-5 border-t border-gray-700 flex justify-between gap-3">
          <button
            onClick={handleClose}
            disabled={isProcessing}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm transition-colors disabled:opacity-50"
          >
            Close
          </button>
          <div className="flex gap-3">
            {isProcessing && (
              <button
                onClick={stopProcess}
                disabled={stopRequestedRef.current}
                className={`px-6 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors ${
                  stopRequestedRef.current
                    ? "bg-gray-600 cursor-not-allowed opacity-70"
                    : "bg-red-600 hover:bg-red-700"
                }`}
              >
                <Square className="w-4 h-4" />
                {stopRequestedRef.current ? "Stopping..." : "Stop"}
              </button>
            )}
            <button
              onClick={runCreateBadges}
              disabled={
                isProcessing ||
                selectedAccounts.size === 0 ||
                !gameId.trim() ||
                !hasSelectable
              }
              className="px-6 py-2 bg-purple-600 hover:bg-purple-700 rounded-lg text-sm font-medium flex items-center gap-2 disabled:opacity-50"
            >
              <Play className="w-4 h-4" />
              Create Badges
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
