// AccountsTable.tsx
import { useState, useEffect } from "react";
import { cn } from "../lib/utils";
import { SteamAccountInfo } from "../types";
import { SortHeader } from "./SortHeader";
import { accountStatusConfig } from "../constants/mainPage.constants";
import { AccountsSortField } from "../types/index";
import { Copy, CheckCheck, Eye, EyeOff, ExternalLink } from "lucide-react";

interface AccountsTableProps {
  accounts: SteamAccountInfo[];
  sortField: AccountsSortField;
  sortOrder: "asc" | "desc";
  onSort: (field: AccountsSortField) => void;
}

export function AccountsTable({
  accounts,
  sortField,
  sortOrder,
  onSort,
}: AccountsTableProps) {
  const [copiedLogin, setCopiedLogin] = useState<string | null>(null);

  const [visiblePasswords, setVisiblePasswords] = useState<
    Record<string, boolean>
  >({});
  const [showAllPasswords, setShowAllPasswords] = useState(false);
  const [hideSensitiveData, setHideSensitiveData] = useState(false);

  // Эффект для синхронизации showAllPasswords с visiblePasswords
  useEffect(() => {
    if (showAllPasswords) {
      // Показать все пароли
      const allVisible: Record<string, boolean> = {};
      accounts.forEach((account) => {
        allVisible[account.accountName] = true;
      });
      setVisiblePasswords(allVisible);
    } else {
      // Скрыть все пароли
      const allHidden: Record<string, boolean> = {};
      accounts.forEach((account) => {
        allHidden[account.accountName] = false;
      });
      setVisiblePasswords(allHidden);
    }
  }, [showAllPasswords, accounts]);

  // Функция для переключения всех паролей
  const toggleAllPasswords = (e: React.MouseEvent) => {
    e.stopPropagation();
    setShowAllPasswords(!showAllPasswords);
  };

  // Функция для переключения скрытия чувствительных данных
  const toggleHideSensitiveData = (e: React.MouseEvent) => {
    e.stopPropagation();
    setHideSensitiveData(!hideSensitiveData);
  };

  // Переключение видимости отдельного пароля
  const togglePasswordVisibility = (
    accountName: string,
    e: React.MouseEvent,
  ) => {
    e.stopPropagation();
    setVisiblePasswords((prev) => {
      const newState = {
        ...prev,
        [accountName]: !prev[accountName],
      };

      // Проверяем, все ли пароли видимы
      const allVisible = accounts.every(
        (account) => newState[account.accountName] === true,
      );
      const allHidden = accounts.every(
        (account) => newState[account.accountName] === false,
      );

      // Синхронизируем showAllPasswords
      if (allVisible) {
        setShowAllPasswords(true);
      } else if (allHidden) {
        setShowAllPasswords(false);
      } else {
        setShowAllPasswords(false);
      }

      return newState;
    });
  };

  // Копирование в буфер обмена
  const copyToClipboard = (
    text: string,
    type:
      | "login"
      | "password"
      | "email"
      | "steamid"
      | "tradeurl"
      | "profileUrl",
    accountName: string,
    e: React.MouseEvent,
  ) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);

    setCopiedLogin(accountName);
    setTimeout(() => setCopiedLogin(null), 2000);
  };

  // Функция для маскирования пароля (показывает первые 3 символа, остальные звездочки)
  const maskPassword = (password: string): string => {
    if (!password) return "••••••••";
    if (password.length <= 3) return password + "•••••";
    const firstThree = password.slice(0, 3);
    const masked = "•••••";
    return firstThree + masked;
  };

  // Функция для маскирования текста (показывает первые 3 символа, остальные звездочки)
  const maskText = (text: string): string => {
    if (!text) return "••••••••";
    if (text.length <= 3) return text + "•••••";
    const firstThree = text.slice(0, 3);
    return firstThree + "•••••";
  };

  // Функция для отображения пароля (скрытый или видимый)
  const getDisplayPassword = (password: string, isVisible: boolean): string => {
    if (!password) return "••••••••";
    if (isVisible) return password;
    return maskPassword(password);
  };

  // Функция для отображения чувствительных данных
  const getDisplayData = (value: string): string => {
    if (!value) return "—";
    if (hideSensitiveData) return maskText(value);
    return value;
  };

  return (
    <div>
      {/* Кнопки управления */}
      <div className="px-4 py-2 border-b border-border bg-secondary/20 flex justify-between items-center">
        <div className="text-sm text-muted-foreground">
          Total: {accounts.length} accounts
        </div>
        <div className="flex gap-2">
          {/* Кнопка для переключения всех паролей */}
          <button
            onClick={toggleAllPasswords}
            className="inline-flex items-center gap-2 rounded-md bg-indigo-500/10 px-3 py-1.5 text-xs font-medium text-indigo-400 hover:bg-indigo-500/20 transition-colors"
          >
            {showAllPasswords ? (
              <>
                <EyeOff size={14} />
                Hide All Passwords
              </>
            ) : (
              <>
                <Eye size={14} />
                Show All Passwords
              </>
            )}
          </button>

          {/* Кнопка для скрытия/показа всех данных */}
          <button
            onClick={toggleHideSensitiveData}
            className="inline-flex items-center gap-2 rounded-md bg-emerald-500/10 px-3 py-1.5 text-xs font-medium text-emerald-400 hover:bg-emerald-500/20 transition-colors"
          >
            {hideSensitiveData ? (
              <>
                <Eye size={14} />
                Show All Data
              </>
            ) : (
              <>
                <EyeOff size={14} />
                Hide Sensitive Data
              </>
            )}
          </button>
        </div>
      </div>

      <table className="w-full">
        <thead className="bg-secondary/50">
          <tr>
            <th className="text-left p-3 text-xs font-medium text-muted-foreground">
              Login
            </th>
            <th className="text-left p-3 text-xs font-medium text-muted-foreground">
              Password
            </th>
            <SortHeader
              label="Status"
              field="status"
              sortField={sortField}
              sortOrder={sortOrder}
              onSort={onSort}
            />

            <SortHeader
              label="Limit"
              field="limit"
              sortField={sortField}
              sortOrder={sortOrder}
              onSort={onSort}
            />
            <th className="text-left p-3 text-xs font-medium text-muted-foreground">
              Email
            </th>
            <th className="text-left p-3 text-xs font-medium text-muted-foreground">
              Steam ID
            </th>
            <th className="text-left p-3 text-xs font-medium text-muted-foreground">
              Trade
            </th>
            <th className="text-left p-3 text-xs font-medium text-muted-foreground">
              Profile
            </th>
          </tr>
        </thead>
        <tbody>
          {accounts.map((account) => {
            const isPasswordVisible = visiblePasswords[account.accountName];
            const displayPassword = getDisplayPassword(
              account.password,
              isPasswordVisible,
            );

            return (
              <tr
                key={account.accountName}
                className="border-t border-border hover:bg-secondary/20 transition-colors group"
              >
                {/* Login cell with copy */}
                <td className="p-3">
                  <div className="flex items-center gap-2 group/copy">
                    <span className="text-sm font-medium">
                      {getDisplayData(account.accountName)}
                    </span>
                    <button
                      onClick={(e) =>
                        copyToClipboard(
                          account.accountName,
                          "login",
                          account.accountName,
                          e,
                        )
                      }
                      className="opacity-0 group-hover/copy:opacity-100 transition-opacity text-muted-foreground hover:text-foreground"
                      aria-label="Copy login"
                    >
                      {copiedLogin === account.accountName ? (
                        <CheckCheck size={14} className="text-emerald-400" />
                      ) : (
                        <Copy size={14} className="cursor-pointer" />
                      )}
                    </button>
                  </div>
                </td>

                {/* Password cell with visibility toggle and copy */}
                <td className="p-3">
                  <div className="flex items-center gap-2">
                    <span className="text-sm text-muted-foreground font-mono">
                      {displayPassword}
                    </span>
                    <button
                      onClick={(e) =>
                        copyToClipboard(
                          account.password,
                          "password",
                          account.accountName,
                          e,
                        )
                      }
                      className="text-muted-foreground hover:text-foreground transition-colors cursor-pointer"
                      aria-label="Copy password"
                    >
                      {copiedLogin === account.accountName ? (
                        <CheckCheck size={14} className="text-emerald-400" />
                      ) : (
                        <Copy size={14} />
                      )}
                    </button>
                    <button
                      onClick={(e) =>
                        togglePasswordVisibility(account.accountName, e)
                      }
                      className="text-muted-foreground hover:text-foreground transition-colors cursor-pointer"
                      aria-label={
                        isPasswordVisible ? "Hide password" : "Show password"
                      }
                    >
                      {isPasswordVisible ? (
                        <EyeOff size={14} />
                      ) : (
                        <Eye size={14} />
                      )}
                    </button>
                  </div>
                </td>

                <td className="p-3">
                  <span
                    className={cn(
                      "inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-medium",
                      accountStatusConfig[account.status]?.color ||
                        "text-gray-400 bg-gray-500/10",
                    )}
                  >
                    {accountStatusConfig[account.status]?.icon}
                    {accountStatusConfig[account.status]?.label ||
                      account.status}
                  </span>
                </td>

                <td className="p-3">
                  {account.steamid && (
                    <span
                      className={cn(
                        "inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-medium",
                        account.limited
                          ? "text-red-400 bg-red-500/10"
                          : "text-emerald-400 bg-emerald-500/10",
                      )}
                    >
                      {account.limited ? "Limited" : "No Limit"}
                    </span>
                  )}
                </td>

                {/* Email cell with copy */}
                <td className="p-3">
                  <div className="flex items-center gap-2 group/copy">
                    <span className="text-sm font-medium">
                      {getDisplayData(account.email || "—")}
                    </span>
                    {account.email && (
                      <button
                        onClick={(e) =>
                          copyToClipboard(
                            account.email,
                            "email",
                            account.accountName,
                            e,
                          )
                        }
                        className="opacity-0 group-hover/copy:opacity-100 transition-opacity text-muted-foreground hover:text-foreground"
                        aria-label="Copy email"
                      >
                        {copiedLogin === account.accountName ? (
                          <CheckCheck size={14} className="text-emerald-400" />
                        ) : (
                          <Copy size={14} className="cursor-pointer" />
                        )}
                      </button>
                    )}
                  </div>
                </td>

                {/* Steam ID cell with copy */}
                <td className="p-3">
                  <div className="flex items-center gap-2 group/copy">
                    <span className="text-sm font-mono">
                      {getDisplayData(account.steamid || "—")}
                    </span>
                    {account.steamid && (
                      <button
                        onClick={(e) =>
                          copyToClipboard(
                            account.steamid,
                            "steamid",
                            account.accountName,
                            e,
                          )
                        }
                        className="opacity-0 group-hover/copy:opacity-100 transition-opacity text-muted-foreground hover:text-foreground"
                        aria-label="Copy Steam ID"
                      >
                        {copiedLogin === account.accountName ? (
                          <CheckCheck size={14} className="text-emerald-400" />
                        ) : (
                          <Copy size={14} className="cursor-pointer" />
                        )}
                      </button>
                    )}
                  </div>
                </td>

                {/* Trade link button */}
                <td className="p-3">
                  {account.profileData.tradelink && (
                    <button
                      onClick={(e) =>
                        copyToClipboard(
                          account.profileData.tradelink!,
                          "tradeurl",
                          account.accountName,
                          e,
                        )
                      }
                      className="inline-flex items-center gap-1 rounded-md bg-indigo-500/10 px-2 py-1 text-xs font-medium text-indigo-400 hover:bg-indigo-500/20 transition-colors cursor-pointer"
                    >
                      <ExternalLink size={10} />
                      Copy
                    </button>
                  )}
                </td>

                {/* Profile link button */}
                <td className="p-3">
                  {account.profileData.profileUrl && (
                    <button
                      onClick={(e) =>
                        copyToClipboard(
                          account.profileData.profileUrl!,
                          "profileUrl",
                          account.accountName,
                          e,
                        )
                      }
                      className="inline-flex items-center gap-1 rounded-md bg-indigo-500/10 px-2 py-1 text-xs font-medium text-indigo-400 hover:bg-indigo-500/20 transition-colors cursor-pointer"
                    >
                      <ExternalLink size={10} />
                      Copy
                    </button>
                  )}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}
