// components/Store/ActivateVouchersModal.tsx
import { useState, useEffect, useRef, useMemo } from "react";
import {
  Search,
  Square,
  Terminal,
  X,
  Ticket,
  Trash2,
  Clock,
  LogIn,
} from "lucide-react";
import { SteamAccountInfo, Tag } from "@/types";
import { accountApi } from "@/services/api";
import { TagChip } from "../Tags/TagChip";

interface ActivateVouchersModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: SteamAccountInfo[];
}

interface Log {
  id: number;
  accountName: string;
  timestamp: string;
  status: "pending" | "success" | "error";
  message: string;
  response?: any;
  voucherCode?: string;
}

interface QueueItem {
  accountName: string;
  voucherCode: string;
  processed: boolean;
  success: boolean;
}

export function ActivateVouchersModal({
  isOpen,
  onClose,
  accounts,
}: ActivateVouchersModalProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedAccounts, setSelectedAccounts] = useState<string[]>([]);
  const [vouchersPerAccount, setVouchersPerAccount] = useState<number>(1);
  const [voucherCodes, setVoucherCodes] = useState<string[]>([]);
  const [delaySeconds, setDelaySeconds] = useState<number>(3);
  const [processing, setProcessing] = useState(false);
  const [currentAccountIndex, setCurrentAccountIndex] = useState(0);
  const [currentVoucherIndex, setCurrentVoucherIndex] = useState(0);
  const [timeUntilNext, setTimeUntilNext] = useState(0);
  const [logs, setLogs] = useState<Log[]>([]);
  const [successCount, setSuccessCount] = useState(0);
  const [failedCount, setFailedCount] = useState(0);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const queueRef = useRef<QueueItem[]>([]);
  const currentQueueIndexRef = useRef<number>(0);
  const loggedInAccountsRef = useRef<Set<string>>(new Set());
  const stopRequestedRef = useRef(false);

  // --- Фильтры (кнопки-переключатели) ---
  const [filterLimited, setFilterLimited] = useState(true);
  const [filterNoWallet, setFilterNoWallet] = useState(true);
  const [filterNoBans, setFilterNoBans] = useState(true);

  // Вычисление списка аккаунтов, подходящих под фильтры (без учёта поиска)
  const eligibleAccounts = useMemo(() => {
    return accounts.filter((acc) => {
      if (!acc.steamid || acc.steamid === "") return false;
      if (filterLimited && acc.limited !== true) return false;
      if (filterNoWallet && acc.hasWallet !== false) return false;
      if (filterNoBans && (acc.bans.community || acc.bans.kt)) return false;
      return true;
    });
  }, [accounts, filterLimited, filterNoWallet, filterNoBans]);

  // Фильтр по поисковому запросу
  const filteredAccounts = eligibleAccounts.filter((acc) =>
    acc.accountName.toLowerCase().includes(searchTerm.toLowerCase()),
  );

  const someSelected = filteredAccounts.some((acc) =>
    selectedAccounts.includes(acc.accountName),
  );

  const totalVouchersNeeded = selectedAccounts.length * vouchersPerAccount;
  const hasEnoughVouchers = voucherCodes.length >= totalVouchersNeeded;

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  useEffect(() => {
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  const addLog = (
    accountName: string,
    status: Log["status"],
    message: string,
    response?: any,
    voucherCode?: string,
  ) => {
    setLogs((prev) => [
      ...prev,
      {
        id: Date.now() + Math.random(),
        accountName,
        timestamp: new Date().toLocaleTimeString(),
        status,
        message,
        response,
        voucherCode,
      },
    ]);
  };

  const removeVoucher = (index: number) => {
    setVoucherCodes(voucherCodes.filter((_, i) => i !== index));
  };

  const addMultipleVouchers = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter") {
      e.preventDefault();
      const value = e.currentTarget.value.trim();
      if (value) {
        const codes = value.split("\n").filter((code) => code.trim());
        setVoucherCodes([...voucherCodes, ...codes]);
        e.currentTarget.value = "";
      }
    }
  };

  const ensureLoggedIn = async (accountName: string): Promise<boolean> => {
    if (loggedInAccountsRef.current.has(accountName)) return true;

    const account = accounts.find((acc) => acc.accountName === accountName);
    if (!account) return false;

    if (account.status !== "offline") {
      loggedInAccountsRef.current.add(accountName);
      return true;
    }

    addLog(accountName, "pending", "Account offline, logging in...");

    try {
      const loginResponse = await accountApi.login([accountName]);
      if (loginResponse?.success) {
        addLog(accountName, "success", "Login successful");
        loggedInAccountsRef.current.add(accountName);
        return true;
      } else {
        addLog(
          accountName,
          "error",
          `Login failed: ${loginResponse?.error || "Unknown error"}`,
        );
        return false;
      }
    } catch (error) {
      addLog(
        accountName,
        "error",
        `Login error: ${error instanceof Error ? error.message : String(error)}`,
      );
      return false;
    }
  };

  const activateSingleVoucher = async (
    accountName: string,
    voucherCode: string,
  ): Promise<boolean> => {
    addLog(
      accountName,
      "pending",
      `Activating voucher: ${voucherCode}`,
      undefined,
      voucherCode,
    );

    try {
      const response = await accountApi.activateVoucher(
        accountName,
        voucherCode,
      );
      if (response.success) {
        addLog(
          accountName,
          "success",
          `✅ Voucher activated: ${voucherCode}`,
          response.data,
          voucherCode,
        );
        return true;
      } else {
        addLog(
          accountName,
          "error",
          `❌ Failed to activate ${voucherCode}: ${response.error}`,
          response,
          voucherCode,
        );
        return false;
      }
    } catch (error) {
      addLog(
        accountName,
        "error",
        `❌ Error activating ${voucherCode}: ${error instanceof Error ? error.message : "Unknown error"}`,
        undefined,
        voucherCode,
      );
      return false;
    }
  };

  const buildQueue = (): QueueItem[] => {
    const queue: QueueItem[] = [];
    let voucherIdx = 0;

    for (const accountName of selectedAccounts) {
      for (let i = 0; i < vouchersPerAccount; i++) {
        if (voucherIdx < voucherCodes.length) {
          queue.push({
            accountName,
            voucherCode: voucherCodes[voucherIdx],
            processed: false,
            success: false,
          });
          voucherIdx++;
        }
      }
    }
    return queue;
  };

  const processNext = async () => {
    if (stopRequestedRef.current) {
      addLog("System", "error", "⏹️ Activation process stopped by user");
      setProcessing(false);
      return;
    }

    const idx = currentQueueIndexRef.current;
    if (idx >= queueRef.current.length) {
      addLog(
        "System",
        "success",
        `✅ All activations completed. Success: ${successCount}, Failed: ${failedCount}`,
      );
      setProcessing(false);
      return;
    }

    const item = queueRef.current[idx];
    const { accountName, voucherCode } = item;

    const accountIdx = selectedAccounts.findIndex((a) => a === accountName);
    setCurrentAccountIndex(accountIdx);
    setCurrentVoucherIndex(idx);

    const loggedIn = await ensureLoggedIn(accountName);
    if (!loggedIn) {
      addLog(
        accountName,
        "error",
        `Skipping voucher ${voucherCode} due to login failure`,
        undefined,
        voucherCode,
      );
      item.processed = true;
      item.success = false;
      setFailedCount((prev) => prev + 1);
      currentQueueIndexRef.current++;
      setTimeUntilNext(delaySeconds);
      timerRef.current = setTimeout(() => {
        processNext();
      }, delaySeconds * 1000);
      return;
    }

    const isSuccess = await activateSingleVoucher(accountName, voucherCode);
    item.processed = true;
    item.success = isSuccess;
    if (isSuccess) {
      setSuccessCount((prev) => prev + 1);
      setVoucherCodes((prev) => prev.filter((code) => code !== voucherCode));
    } else {
      setFailedCount((prev) => prev + 1);
    }

    currentQueueIndexRef.current++;
    setTimeUntilNext(delaySeconds);
    timerRef.current = setTimeout(() => {
      const remaining = queueRef.current.filter((i) => !i.processed).length;
      if (remaining > 0) {
        processNext();
      } else {
        addLog(
          "System",
          "success",
          `✅ All activations completed. Success: ${successCount + (isSuccess ? 1 : 0)}, Failed: ${failedCount + (!isSuccess ? 1 : 0)}`,
        );
        setProcessing(false);
      }
    }, delaySeconds * 1000);
  };

  const startActivation = async () => {
    if (selectedAccounts.length === 0) {
      addLog("System", "error", "No accounts selected");
      return;
    }
    if (voucherCodes.length === 0) {
      addLog("System", "error", "No voucher codes entered");
      return;
    }
    if (!vouchersPerAccount || vouchersPerAccount < 1) {
      addLog("System", "error", "Vouchers per account must be at least 1");
      return;
    }
    if (!hasEnoughVouchers) {
      addLog(
        "System",
        "error",
        `Need ${totalVouchersNeeded} vouchers but only ${voucherCodes.length} available`,
      );
      return;
    }

    setProcessing(true);
    setLogs([]);
    setCurrentAccountIndex(0);
    setCurrentVoucherIndex(0);
    setSuccessCount(0);
    setFailedCount(0);
    setTimeUntilNext(0);
    stopRequestedRef.current = false;
    loggedInAccountsRef.current.clear();

    queueRef.current = buildQueue();
    currentQueueIndexRef.current = 0;

    processNext();
  };

  const stopActivation = () => {
    stopRequestedRef.current = true;
    if (timerRef.current) clearTimeout(timerRef.current);
    setProcessing(false);
    setTimeUntilNext(0);
  };

  const toggleAccount = (login: string) => {
    if (processing) return;
    setSelectedAccounts((prev) =>
      prev.includes(login) ? prev.filter((a) => a !== login) : [...prev, login],
    );
  };

  // Select All – выбирает только активные (online / farm) аккаунты из отфильтрованного списка
  const selectAllFiltered = () => {
    if (processing) return;
    const activeLogins = filteredAccounts
      .filter((acc) => acc.status === "online" || acc.status === "farm")
      .map((acc) => acc.accountName);
    setSelectedAccounts(activeLogins);
  };

  const clearAll = () => {
    if (processing) return;
    setSelectedAccounts([]);
  };

  const handleManualLogin = async (accountName: string) => {
    if (processing) return;
    addLog(accountName, "pending", "Manual login requested...");
    try {
      const result = await accountApi.login([accountName]);
      if (result?.success) {
        addLog(accountName, "success", "Manual login successful");
        loggedInAccountsRef.current.add(accountName);
      } else {
        addLog(
          accountName,
          "error",
          `Manual login failed: ${result?.error || "Unknown error"}`,
        );
      }
    } catch (err) {
      addLog(
        accountName,
        "error",
        `Manual login error: ${err instanceof Error ? err.message : String(err)}`,
      );
    }
  };

  const getStatusColor = (status: Log["status"]) => {
    switch (status) {
      case "success":
        return "text-green-400";
      case "error":
        return "text-red-400";
      case "pending":
        return "text-yellow-400";
      default:
        return "text-gray-400";
    }
  };

  const getStatusIcon = (status: Log["status"]) => {
    switch (status) {
      case "success":
        return "✅";
      case "error":
        return "❌";
      case "pending":
        return "⏳";
      default:
        return "📝";
    }
  };

  if (!isOpen) return null;

  const processedCount = queueRef.current.filter(
    (item) => item.processed,
  ).length;
  const totalQueueSize = queueRef.current.length;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
      onClick={(e) => e.target === e.currentTarget && !processing && onClose()}
    >
      <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-6xl max-h-[90vh] flex flex-col overflow-hidden border border-gray-700">
        {/* Header (без изменений) */}
        <div className="flex justify-between items-center p-5 border-b border-gray-700">
          <div>
            <h2 className="text-xl font-semibold text-white flex items-center gap-2">
              <Ticket className="w-5 h-5" />
              Activate Vouchers
            </h2>
            <p className="text-xs text-gray-400 mt-1">
              Activate Steam wallet vouchers one by one on eligible accounts
            </p>
            <p className="text-xs text-emerald-400 mt-1">
              The software automatically checks the account country and
              activates the key only in approved countries.
            </p>
            <p className="text-xs text-gray-300 mt-1">
              Countries can be found in settings.json
            </p>
          </div>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-white"
            disabled={processing}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-hidden flex flex-col lg:flex-row">
          {/* Левая колонка – аккаунты с фильтрами */}
          <div className="w-full lg:w-1/3 border-r border-gray-700 flex flex-col">
            <div className="p-4 border-b border-gray-700">
              <div className="relative mb-2">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search accounts..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-orange-500"
                  disabled={processing}
                />
              </div>

              {/* Панель фильтров-кнопок */}
              <div className="mt-3 p-3 bg-gray-800/50 rounded-lg space-y-2">
                <div className="text-xs text-gray-400 mb-1">Filters:</div>
                <div className="flex flex-wrap gap-2">
                  <button
                    onClick={() => setFilterLimited(!filterLimited)}
                    disabled={processing}
                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                      filterLimited
                        ? "bg-orange-600 text-white"
                        : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                    }`}
                  >
                    Limited
                  </button>
                  <button
                    onClick={() => setFilterNoWallet(!filterNoWallet)}
                    disabled={processing}
                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                      filterNoWallet
                        ? "bg-orange-600 text-white"
                        : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                    }`}
                  >
                    No wallet
                  </button>
                  <button
                    onClick={() => setFilterNoBans(!filterNoBans)}
                    disabled={processing}
                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                      filterNoBans
                        ? "bg-orange-600 text-white"
                        : "bg-gray-700 text-gray-300 hover:bg-gray-600"
                    }`}
                  >
                    No bans
                  </button>
                </div>
                <div className="text-xs text-gray-400 pt-1 border-t border-gray-700 mt-1">
                  Eligible accounts:{" "}
                  <span className="text-white font-medium">
                    {eligibleAccounts.length}
                  </span>
                </div>
              </div>

              <div className="flex gap-2 flex-wrap mt-3">
                <button
                  onClick={selectAllFiltered}
                  disabled={processing || filteredAccounts.length === 0}
                  className="flex items-center gap-1 px-3 py-1.5 bg-gray-700 hover:bg-gray-600 rounded-lg text-xs transition-colors disabled:opacity-50"
                >
                  <Square className="w-3.5 h-3.5" />
                  Select All (
                  {
                    filteredAccounts.filter(
                      (acc) => acc.status === "online" || acc.status === "farm",
                    ).length
                  }
                  )
                </button>
                {someSelected && (
                  <button
                    onClick={clearAll}
                    disabled={processing}
                    className="flex items-center gap-1 px-3 py-1.5 bg-gray-700 hover:bg-gray-600 rounded-lg text-xs transition-colors disabled:opacity-50"
                  >
                    <Square className="w-3.5 h-3.5" />
                    Clear All
                  </button>
                )}
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-3 space-y-2">
              <div className="mb-3 p-2 bg-orange-900/30 rounded-lg border border-orange-700/30">
                <div className="text-xs text-gray-300">
                  Selected:{" "}
                  <span className="text-orange-400 font-semibold">
                    {selectedAccounts.length}
                  </span>{" "}
                  of {eligibleAccounts.length} eligible accounts
                </div>
                <div className="text-xs text-gray-300 mt-1">
                  Total activations:{" "}
                  <span
                    className={`font-semibold ${hasEnoughVouchers ? "text-green-400" : "text-red-400"}`}
                  >
                    {totalVouchersNeeded}
                  </span>{" "}
                  / {voucherCodes.length} vouchers
                </div>
                {processing && (
                  <>
                    <div className="text-xs text-gray-400 mt-1">
                      Progress: {processedCount} / {totalQueueSize} activations
                    </div>
                    <div className="text-xs text-green-400 mt-1">
                      ✅ Success: {successCount}
                    </div>
                    <div className="text-xs text-red-400 mt-1">
                      ❌ Failed: {failedCount}
                    </div>
                    <div className="text-xs text-blue-400 mt-1">
                      ⏱️ Next request in: {timeUntilNext}s
                    </div>
                  </>
                )}
              </div>

              {filteredAccounts.length === 0 ? (
                <div className="text-center text-gray-400 py-8 text-sm">
                  {eligibleAccounts.length === 0
                    ? "No eligible accounts with current filters"
                    : "No accounts found"}
                </div>
              ) : (
                filteredAccounts.map((acc) => {
                  const accountIndex = selectedAccounts.indexOf(
                    acc.accountName,
                  );
                  const isProcessed =
                    accountIndex !== -1 && accountIndex < currentAccountIndex;
                  const isActive =
                    acc.status === "online" || acc.status === "farm";

                  return (
                    <div
                      key={acc.accountName}
                      className={`flex flex-col gap-1 p-2 rounded-lg transition ${
                        processing ? "opacity-60 cursor-not-allowed" : ""
                      } ${isProcessed ? "opacity-60 bg-gray-800/30" : ""}`}
                    >
                      {/* Верхняя строка: чекбокс + имя + дата + статус/кнопка */}
                      <div className="flex items-center gap-3">
                        <label
                          className={`flex items-center gap-3 flex-1 cursor-pointer ${!isActive ? "opacity-70" : ""}`}
                        >
                          <input
                            type="checkbox"
                            checked={selectedAccounts.includes(acc.accountName)}
                            onChange={() => toggleAccount(acc.accountName)}
                            disabled={processing || !isActive}
                            className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-orange-500 focus:ring-orange-500 disabled:opacity-50"
                          />
                          <span className="text-sm font-medium text-white">
                            {acc.accountName}
                          </span>
                          <span className="text-xs text-gray-400 ml-auto">
                            {acc.activity?.activate_vouchers &&
                              "last Use: " +
                                new Date(
                                  acc.activity?.activate_vouchers,
                                ).toLocaleDateString()}
                          </span>
                        </label>

                        {!isActive ? (
                          <button
                            onClick={() => handleManualLogin(acc.accountName)}
                            disabled={processing}
                            className="flex items-center gap-1 px-2 py-1 text-xs rounded-md bg-blue-600/80 hover:bg-blue-500 text-white transition-colors disabled:opacity-50"
                          >
                            <LogIn className="w-3 h-3" />
                            Login
                          </button>
                        ) : (
                          <span className="text-xs text-green-400 ml-auto">
                            {acc.status === "farm" ? "farming" : "online"}
                          </span>
                        )}
                        {isProcessed && processing && (
                          <span className="text-xs text-green-400 ml-1">✓</span>
                        )}
                      </div>

                      {/* Нижняя строка: теги */}
                      <div className="flex flex-wrap gap-1 ml-7">
                        {acc.tags?.map((tag: Tag) => (
                          <TagChip key={tag.id} tag={tag} small />
                        ))}
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>

          {/* Средняя колонка – настройки ваучеров (без изменений) */}
          <div className="w-full lg:w-1/3 border-r border-gray-700 flex flex-col">
            <div className="p-4 border-b border-gray-700">
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Vouchers per account
              </label>
              <input
                type="number"
                min={1}
                value={vouchersPerAccount}
                onChange={(e) => {
                  const value = e.target.value;
                  if (value === "") {
                    setVouchersPerAccount(0);
                  } else {
                    setVouchersPerAccount(Math.max(1, parseInt(value) || 1));
                  }
                }}
                className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white focus:outline-none focus:ring-2 focus:ring-orange-500"
                disabled={processing}
              />
              {(!vouchersPerAccount || vouchersPerAccount < 1) && (
                <p className="text-xs text-red-400 mt-1">Must be at least 1</p>
              )}
            </div>

            <div className="p-4 border-b border-gray-700">
              <div className="flex items-center gap-3">
                <Clock className="w-4 h-4 text-gray-400" />
                <label className="block text-sm font-medium text-gray-300">
                  Delay between requests (seconds):
                </label>
                <input
                  type="number"
                  min={0}
                  max={60}
                  step={1}
                  value={delaySeconds}
                  onChange={(e) => setDelaySeconds(Number(e.target.value) || 0)}
                  disabled={processing}
                  className="w-20 px-2 py-1 bg-gray-800 border border-gray-600 rounded text-white text-sm"
                />
              </div>
            </div>

            <div className="flex-1 p-4 overflow-hidden flex flex-col">
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Voucher Codes (one per line)
              </label>
              <textarea
                placeholder="Enter voucher codes (one per line)&#10;Example:&#10;STEAM-CODE-123&#10;STEAM-CODE-456"
                onKeyDown={addMultipleVouchers}
                className="w-full px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-orange-500 mb-4 resize-none"
                rows={4}
                disabled={processing}
              />

              <div className="border border-gray-700 rounded-lg overflow-hidden flex-1">
                <div className="bg-gray-800 px-3 py-2 text-xs text-gray-400 border-b border-gray-700">
                  Added Vouchers ({voucherCodes.length})
                </div>
                <div className="h-full overflow-y-auto">
                  {voucherCodes.length === 0 ? (
                    <div className="text-center text-gray-500 py-4 text-sm">
                      No vouchers added
                    </div>
                  ) : (
                    voucherCodes.map((code, idx) => (
                      <div
                        key={idx}
                        className="flex items-center justify-between px-3 py-2 border-b border-gray-700 last:border-0 hover:bg-gray-800"
                      >
                        <span className="text-sm text-white font-mono truncate flex-1">
                          {code}
                        </span>
                        <button
                          onClick={() => removeVoucher(idx)}
                          disabled={processing}
                          className="text-red-400 hover:text-red-300 ml-2 disabled:opacity-50"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* Правая колонка – логи (без изменений) */}
          <div className="w-full lg:w-1/3 flex flex-col">
            <div className="p-4 border-b border-gray-700 flex justify-between items-center">
              <div className="flex items-center gap-2">
                <Terminal className="w-4 h-4 text-gray-400" />
                <span className="text-sm font-medium text-white">Logs</span>
              </div>
              <button
                onClick={() => setLogs([])}
                disabled={processing}
                className="text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded transition-colors disabled:opacity-50"
              >
                Clear
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-2 font-mono text-xs">
              {logs.length === 0 ? (
                <div className="text-center text-gray-500 py-8">
                  Logs will appear here...
                </div>
              ) : (
                logs.map((log) => (
                  <div key={log.id} className="border-l-2 border-gray-700 pl-2">
                    <div className="flex items-start gap-2">
                      <span className="text-gray-500 shrink-0">
                        [{log.timestamp}]
                      </span>
                      <span
                        className={`${getStatusColor(log.status)} shrink-0`}
                      >
                        {getStatusIcon(log.status)}
                      </span>
                      <span className="text-gray-300 font-semibold shrink-0">
                        {log.accountName}:
                      </span>
                      <span className="text-gray-400 break-all">
                        {log.message}
                      </span>
                    </div>
                    {log.voucherCode && (
                      <div className="ml-16 mt-1 text-gray-500 text-[10px]">
                        Voucher: {log.voucherCode}
                      </div>
                    )}
                  </div>
                ))
              )}
              <div ref={logsEndRef} />
            </div>
          </div>
        </div>

        {/* Footer (без изменений) */}
        <div className="p-5 border-t border-gray-700 flex justify-end gap-3">
          <button
            onClick={onClose}
            disabled={processing}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm"
          >
            Close
          </button>
          {!processing ? (
            <button
              onClick={startActivation}
              disabled={
                selectedAccounts.length === 0 ||
                voucherCodes.length === 0 ||
                !vouchersPerAccount ||
                vouchersPerAccount < 1 ||
                !hasEnoughVouchers
              }
              className="px-6 py-2 bg-orange-600 hover:bg-orange-700 rounded-lg text-sm font-medium flex items-center gap-2 disabled:opacity-50"
            >
              <Ticket className="w-4 h-4" />
              Activate Vouchers
            </button>
          ) : (
            <button
              onClick={stopActivation}
              className="px-6 py-2 bg-red-600 hover:bg-red-700 rounded-lg text-sm font-medium flex items-center gap-2"
            >
              Stop
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
