// components/Market/MassSellItemsModal.tsx
import { useState, useRef, useEffect } from "react";
import {
  Search,
  Terminal,
  X,
  DollarSign,
  Play,
  Square,
  Clock,
  CheckSquare,
  Square as SquareIcon,
  Gamepad2,
  LogIn,
  CheckCircle,
  AlertTriangle,
  Loader2,
} from "lucide-react";
import { SteamAccountInfo, Confirmation, ConfirmationType } from "@/types";
import { accountApi } from "@/services/api";
import { Modal } from "@/components/Modal";
import { TagChip } from "../Tags/TagChip";

interface MassSellItemsModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: SteamAccountInfo[];
}

interface LogEntry {
  id: number;
  accountName: string;
  timestamp: string;
  status: "pending" | "success" | "error";
  message: string;
  response?: any;
  showConfirmButton?: boolean;
}

const GAME_PRESETS = [
  { label: "CS2", appId: "730", contextId: "2" },
  { label: "Dota 2", appId: "570", contextId: "2" },
  { label: "Team Fortress 2", appId: "440", contextId: "2" },
];

const getConfirmationTypeName = (type: number): string => {
  switch (type) {
    case ConfirmationType.Test:
      return "Test Confirmation";
    case ConfirmationType.Trade:
      return "Trade Offer";
    case ConfirmationType.MarketSell:
      return "Market Sell Listing";
    case ConfirmationType.MarketBuy:
      return "Market Buy Confirmation";
    default:
      return "Confirmation";
  }
};

const formatDate = (isoString: string) => {
  const date = new Date(isoString);
  return date.toLocaleString();
};

export function MassSellItemsModal({
  isOpen,
  onClose,
  accounts,
}: MassSellItemsModalProps) {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedAccounts, setSelectedAccounts] = useState<Set<string>>(
    new Set(),
  );
  const [selectedGame, setSelectedGame] = useState(GAME_PRESETS[0]);
  const [delaySeconds, setDelaySeconds] = useState(2);
  const [isProcessing, setIsProcessing] = useState(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const stopRequestedRef = useRef(false);
  const [loggingInAccounts, setLoggingInAccounts] = useState<Set<string>>(
    new Set(),
  );
  const [confirmationsModal, setConfirmationsModal] = useState<{
    isOpen: boolean;
    accountName: string | null;
    confirmations: Confirmation[];
    loading: boolean;
  }>({
    isOpen: false,
    accountName: null,
    confirmations: [],
    loading: false,
  });
  const [processingConfirmations, setProcessingConfirmations] = useState<
    Set<string>
  >(new Set());
  const [bulkModal, setBulkModal] = useState<{
    type: "accept" | "decline" | null;
    open: boolean;
  }>({ type: null, open: false });
  const [bulkLoading, setBulkLoading] = useState<{
    accept: boolean;
    decline: boolean;
  }>({ accept: false, decline: false });

  const filteredAccounts = accounts
    .filter((acc) =>
      acc.accountName.toLowerCase().includes(searchTerm.toLowerCase()),
    )
    .sort((a, b) => {
      if (a.cookies && !b.cookies) return -1;
      if (!a.cookies && b.cookies) return 1;
      return 0;
    });

  const selectableAccounts = filteredAccounts.filter(
    (acc) => acc.cookies === true,
  );

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  const addLog = (
    accountName: string,
    status: LogEntry["status"],
    message: string,
    response?: any,
    showConfirmButton?: boolean,
  ) => {
    setLogs((prev) => [
      ...prev,
      {
        id: Date.now() + Math.random(),
        accountName,
        timestamp: new Date().toLocaleTimeString(),
        status,
        message,
        response,
        showConfirmButton,
      },
    ]);
  };

  const toggleAccount = (accountName: string) => {
    if (isProcessing) return;
    const account = accounts.find((a) => a.accountName === accountName);
    if (account && account.cookies !== true) return;
    const newSet = new Set(selectedAccounts);
    if (newSet.has(accountName)) newSet.delete(accountName);
    else newSet.add(accountName);
    setSelectedAccounts(newSet);
  };

  const selectAllFiltered = () => {
    if (isProcessing) return;
    const newSet = new Set(selectedAccounts);
    selectableAccounts.forEach((acc) => newSet.add(acc.accountName));
    setSelectedAccounts(newSet);
  };

  const deselectAllFiltered = () => {
    if (isProcessing) return;
    const newSet = new Set(selectedAccounts);
    filteredAccounts.forEach((acc) => newSet.delete(acc.accountName));
    setSelectedAccounts(newSet);
  };

  const fetchConfirmations = async (accountName: string) => {
    setConfirmationsModal((prev) => ({ ...prev, loading: true }));
    try {
      const result = await accountApi.getConfirmations(accountName);
      if (result.data && result.data?.length > 0) {
        //@ts-ignore
        setConfirmationsModal((prev) => ({
          ...prev,
          confirmations: result.data,
          loading: false,
        }));
      } else {
        setConfirmationsModal((prev) => ({
          ...prev,
          confirmations: [],
          loading: false,
        }));
      }
    } catch (error) {
      console.error("Failed to fetch confirmations:", error);
      setConfirmationsModal((prev) => ({ ...prev, loading: false }));
    }
  };

  const openConfirmationsModal = async (accountName: string) => {
    setConfirmationsModal({
      isOpen: true,
      accountName,
      confirmations: [],
      loading: false,
    });
    await fetchConfirmations(accountName);
  };

  const closeConfirmationsModal = () => {
    setConfirmationsModal({
      isOpen: false,
      accountName: null,
      confirmations: [],
      loading: false,
    });
    setBulkModal({ type: null, open: false });
  };

  const handleAcceptConfirmation = async (confirmationId: string) => {
    const { accountName } = confirmationsModal;
    if (!accountName || processingConfirmations.has(confirmationId)) return;

    setProcessingConfirmations((prev) => new Set(prev).add(confirmationId));
    const result = await accountApi.acceptConfirmation(
      accountName,
      confirmationId,
    );

    if (result.success) {
      setConfirmationsModal((prev) => ({
        ...prev,
        confirmations: prev.confirmations.filter(
          (c) => c.id !== confirmationId,
        ),
      }));
      addLog(
        accountName,
        "success",
        `✅ Confirmation ${confirmationId} accepted`,
        undefined,
        false,
      );
    } else {
      addLog(
        accountName,
        "error",
        `❌ Failed to accept confirmation: ${result.error}`,
        undefined,
        false,
      );
    }

    setProcessingConfirmations((prev) => {
      const newSet = new Set(prev);
      newSet.delete(confirmationId);
      return newSet;
    });
  };

  const handleDeclineConfirmation = async (confirmationId: string) => {
    const { accountName } = confirmationsModal;
    if (!accountName || processingConfirmations.has(confirmationId)) return;

    setProcessingConfirmations((prev) => new Set(prev).add(confirmationId));
    const result = await accountApi.declineConfirmation(
      accountName,
      confirmationId,
    );

    if (result.success) {
      setConfirmationsModal((prev) => ({
        ...prev,
        confirmations: prev.confirmations.filter(
          (c) => c.id !== confirmationId,
        ),
      }));
      addLog(
        accountName,
        "success",
        `✅ Confirmation ${confirmationId} declined`,
        undefined,
        false,
      );
    } else {
      addLog(
        accountName,
        "error",
        `❌ Failed to decline confirmation: ${result.error}`,
        undefined,
        false,
      );
    }

    setProcessingConfirmations((prev) => {
      const newSet = new Set(prev);
      newSet.delete(confirmationId);
      return newSet;
    });
  };

  const handleAcceptAll = async () => {
    const { accountName, confirmations } = confirmationsModal;
    if (!accountName || confirmations.length === 0) return;

    setBulkLoading((prev) => ({ ...prev, accept: true }));
    const result = await accountApi.acceptAllConfirmations(accountName);

    if (result.success) {
      setConfirmationsModal((prev) => ({ ...prev, confirmations: [] }));
      addLog(
        accountName,
        "success",
        `✅ All ${confirmations.length} confirmations accepted successfully`,
        undefined,
        false,
      );
    } else {
      addLog(
        accountName,
        "error",
        `❌ Failed to accept all confirmations: ${result.error}`,
        undefined,
        false,
      );
    }

    setBulkLoading((prev) => ({ ...prev, accept: false }));
    setBulkModal({ type: null, open: false });
  };

  const handleDeclineAll = async () => {
    const { accountName, confirmations } = confirmationsModal;
    if (!accountName || confirmations.length === 0) return;

    setBulkLoading((prev) => ({ ...prev, decline: true }));
    const result = await accountApi.declineAllConfirmations(accountName);

    if (result.success) {
      setConfirmationsModal((prev) => ({ ...prev, confirmations: [] }));
      addLog(
        accountName,
        "success",
        `✅ All ${confirmations.length} confirmations declined successfully`,
        undefined,
        false,
      );
    } else {
      addLog(
        accountName,
        "error",
        `❌ Failed to decline all confirmations: ${result.error}`,
        undefined,
        false,
      );
    }

    setBulkLoading((prev) => ({ ...prev, decline: false }));
    setBulkModal({ type: null, open: false });
  };

  const openBulkConfirmModal = (type: "accept" | "decline") => {
    setBulkModal({ type, open: true });
  };

  const handleManualLogin = async (accountName: string) => {
    if (isProcessing || loggingInAccounts.has(accountName)) return;
    setLoggingInAccounts((prev) => new Set(prev).add(accountName));
    addLog(accountName, "pending", "Manual login requested...");
    try {
      const result = await accountApi.login([accountName]);
      if (result?.success) {
        addLog(accountName, "success", "Manual login successful");
        addLog(
          accountName,
          "success",
          "You may need to refresh the modal to see changes.",
        );
      } else {
        addLog(
          accountName,
          "error",
          `Manual login failed: ${result?.error || "Unknown error"}`,
        );
      }
    } catch (err) {
      addLog(
        accountName,
        "error",
        `Manual login error: ${err instanceof Error ? err.message : String(err)}`,
      );
    } finally {
      setLoggingInAccounts((prev) => {
        const newSet = new Set(prev);
        newSet.delete(accountName);
        return newSet;
      });
    }
  };

  const runSellAll = async () => {
    if (selectedAccounts.size === 0) {
      addLog("System", "error", "No accounts selected");
      return;
    }
    if (isProcessing) return;

    stopRequestedRef.current = false;
    setIsProcessing(true);
    setLogs([]);

    const accountsList = Array.from(selectedAccounts);
    let successCount = 0;
    let errorCount = 0;

    for (let i = 0; i < accountsList.length; i++) {
      if (stopRequestedRef.current) {
        addLog("System", "error", "Process interrupted by user");
        break;
      }
      const accountName = accountsList[i];
      const account = accounts.find((a) => a.accountName === accountName);
      if (!account || account.cookies !== true) {
        addLog(
          accountName,
          "error",
          "Skipped: no valid session (cookies missing)",
        );
        errorCount++;
        continue;
      }

      addLog(
        accountName,
        "pending",
        `Selling all items from ${selectedGame.label}...`,
      );
      try {
        const response = await accountApi.sellAllItems(
          accountName,
          selectedGame.appId,
          selectedGame.contextId,
        );
        if (stopRequestedRef.current) {
          addLog("System", "error", "Process stopped after this account");
          break;
        }
        if (response.success) {
          addLog(
            accountName,
            "success",
            `✅ All items listed! Check confirmations and confirm sales.`,
            response.data,
            true, // show confirm button
          );
          successCount++;
        } else {
          addLog(accountName, "error", `❌ Error: ${response.error}`, response);
          errorCount++;
        }
      } catch (err: any) {
        addLog(
          accountName,
          "error",
          `❌ Exception: ${err.message || "Unknown error"}`,
        );
        errorCount++;
      }

      if (stopRequestedRef.current) break;
      if (i < accountsList.length - 1 && !stopRequestedRef.current) {
        await new Promise((resolve) =>
          setTimeout(resolve, delaySeconds * 1000),
        );
      }
    }

    addLog(
      "System",
      successCount > 0 && errorCount === 0 ? "success" : "error",
      `Finished. Success: ${successCount}, Errors: ${errorCount}`,
    );
    setIsProcessing(false);
    stopRequestedRef.current = false;
  };

  const stopProcess = () => {
    if (isProcessing && !stopRequestedRef.current) {
      stopRequestedRef.current = true;
      addLog(
        "System",
        "pending",
        "⏹️ Stop requested — waiting for current account to finish...",
      );
    }
  };

  const handleClose = () => {
    if (isProcessing) {
      if (confirm("Process is running. Are you sure you want to close?")) {
        stopProcess();
        onClose();
      }
    } else {
      onClose();
    }
  };

  const getStatusColor = (status: LogEntry["status"]) => {
    switch (status) {
      case "success":
        return "text-green-400";
      case "error":
        return "text-red-400";
      case "pending":
        return "text-yellow-400";
      default:
        return "text-gray-400";
    }
  };

  const getStatusIcon = (status: LogEntry["status"]) => {
    switch (status) {
      case "success":
        return "✅";
      case "error":
        return "❌";
      case "pending":
        return "⏳";
      default:
        return "📝";
    }
  };

  // Рендер модального окна подтверждений
  const renderConfirmationsModal = () => (
    <Modal
      isOpen={confirmationsModal.isOpen}
      onClose={closeConfirmationsModal}
      title={`Confirmations for ${confirmationsModal.accountName || ""}`}
      icon={<CheckCircle className="w-5 h-5 text-amber-400" />}
      maxWidth="2xl"
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={closeConfirmationsModal}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors cursor-pointer"
          >
            Close
          </button>
        </div>
      }
    >
      <div className="p-4">
        {/* Кнопки Accept All и Decline All */}
        <div className="flex justify-end gap-3 mb-4">
          <button
            onClick={() => openBulkConfirmModal("accept")}
            disabled={
              bulkLoading.accept ||
              bulkLoading.decline ||
              confirmationsModal.confirmations.length === 0 ||
              confirmationsModal.loading
            }
            className="px-3 py-1.5 bg-green-600 hover:bg-green-700 rounded-md text-sm font-medium transition-colors disabled:opacity-50 cursor-pointer flex items-center gap-2"
          >
            {bulkLoading.accept ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <CheckCircle className="w-4 h-4" />
            )}
            Accept All
          </button>
          <button
            onClick={() => openBulkConfirmModal("decline")}
            disabled={
              bulkLoading.accept ||
              bulkLoading.decline ||
              confirmationsModal.confirmations.length === 0 ||
              confirmationsModal.loading
            }
            className="px-3 py-1.5 bg-red-600 hover:bg-red-700 rounded-md text-sm font-medium transition-colors disabled:opacity-50 cursor-pointer flex items-center gap-2"
          >
            {bulkLoading.decline ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <AlertTriangle className="w-4 h-4" />
            )}
            Decline All
          </button>
        </div>

        {confirmationsModal.loading ? (
          <div className="flex flex-col items-center justify-center py-12">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-amber-500 mb-4"></div>
            <div className="text-gray-300">Loading confirmations...</div>
          </div>
        ) : confirmationsModal.confirmations.length === 0 ? (
          <div className="text-center text-gray-400 py-12">
            No pending confirmations found
          </div>
        ) : (
          <div className="space-y-3 max-h-96 overflow-y-auto">
            {confirmationsModal.confirmations.map((conf) => {
              const isProcessing = processingConfirmations.has(conf.id);
              return (
                <div
                  key={conf.id}
                  className="flex items-start gap-3 p-3 bg-gray-800 rounded-lg border border-gray-700 transition-opacity duration-200"
                >
                  {conf.icon && (
                    <img
                      src={conf.icon}
                      alt=""
                      className="w-12 h-12 rounded object-cover flex-shrink-0"
                      onError={(e) => (e.currentTarget.style.display = "none")}
                    />
                  )}
                  <div className="flex-1">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="font-medium text-white">
                        {conf.title || getConfirmationTypeName(conf.type)}
                      </span>
                      <span className="text-xs text-gray-400">
                        {formatDate(conf.time || conf.timestamp)}
                      </span>
                    </div>
                    {conf.sending && conf.sending !== "null" && (
                      <div className="text-sm text-red-300 mt-1">
                        💰 Selling:{" "}
                        <span className="font-mono">{conf.sending}</span>
                      </div>
                    )}
                    {conf.receiving && conf.receiving !== "null" && (
                      <div className="text-sm text-green-300 mt-1">
                        📥 Receiving:{" "}
                        <span className="font-mono">{conf.receiving}</span>
                      </div>
                    )}
                    {conf.type === ConfirmationType.MarketSell && (
                      <div className="text-xs text-amber-400 mt-1">
                        🏷️ Market listing confirmation
                      </div>
                    )}
                    {conf.type === ConfirmationType.MarketBuy && (
                      <div className="text-xs text-yellow-300 mt-1">
                        🛡️ Purchase verification required
                      </div>
                    )}
                    <div className="text-xs text-gray-400 mt-1">
                      ID: {conf.id}
                    </div>
                  </div>
                  <div className="flex gap-2 flex-shrink-0">
                    <button
                      onClick={() => handleAcceptConfirmation(conf.id)}
                      disabled={isProcessing}
                      className="px-3 py-1 bg-green-600 hover:bg-green-700 rounded text-sm transition-colors disabled:opacity-50 cursor-pointer flex items-center gap-1 min-w-[70px] justify-center"
                    >
                      {isProcessing ? (
                        <>
                          <Loader2 className="w-3 h-3 animate-spin" />
                          <span>...</span>
                        </>
                      ) : (
                        "Accept"
                      )}
                    </button>
                    <button
                      onClick={() => handleDeclineConfirmation(conf.id)}
                      disabled={isProcessing}
                      className="px-3 py-1 bg-red-600 hover:bg-red-700 rounded text-sm transition-colors disabled:opacity-50 cursor-pointer flex items-center gap-1 min-w-[70px] justify-center"
                    >
                      {isProcessing ? (
                        <>
                          <Loader2 className="w-3 h-3 animate-spin" />
                          <span>...</span>
                        </>
                      ) : (
                        "Decline"
                      )}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Модальное окно подтверждения для массовых действий */}
      <Modal
        isOpen={bulkModal.open}
        onClose={() => setBulkModal({ type: null, open: false })}
        title={
          bulkModal.type === "accept"
            ? "Confirm Accept All"
            : "Confirm Decline All"
        }
        icon={<AlertTriangle className="w-5 h-5 text-red-400" />}
        footer={
          <div className="flex justify-end gap-3">
            <button
              onClick={() => setBulkModal({ type: null, open: false })}
              className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-md text-sm font-medium transition-colors cursor-pointer"
            >
              Cancel
            </button>
            <button
              onClick={
                bulkModal.type === "accept" ? handleAcceptAll : handleDeclineAll
              }
              disabled={bulkLoading.accept || bulkLoading.decline}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors cursor-pointer flex items-center gap-2 ${
                bulkModal.type === "accept"
                  ? "bg-green-600 hover:bg-green-700"
                  : "bg-red-600 hover:bg-red-700"
              } disabled:opacity-50`}
            >
              {(bulkLoading.accept || bulkLoading.decline) && (
                <Loader2 className="w-4 h-4 animate-spin" />
              )}
              {bulkModal.type === "accept"
                ? "Yes, accept all"
                : "Yes, decline all"}
            </button>
          </div>
        }
        maxWidth="md"
      >
        <div className="p-4">
          <p className="text-gray-300">
            Are you sure you want to{" "}
            {bulkModal.type === "accept" ? "accept" : "decline"}{" "}
            <strong>
              all {confirmationsModal.confirmations.length} pending
              confirmations
            </strong>
            ?
          </p>
          <p className="text-red-400 text-sm mt-2">
            This action cannot be undone.
          </p>
        </div>
      </Modal>
    </Modal>
  );

  if (!isOpen) return null;

  return (
    <>
      <div
        className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
        onClick={(e) =>
          e.target === e.currentTarget && !isProcessing && handleClose()
        }
      >
        <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-5xl max-h-[90vh] flex flex-col overflow-hidden border border-gray-700">
          {/* Header */}
          <div className="flex justify-between items-center p-5 border-b border-gray-700">
            <div>
              <h2 className="text-xl font-semibold text-white flex items-center gap-2">
                <DollarSign className="w-5 h-5 text-amber-400" />
                Mass Sell Items
              </h2>
              <p className="text-xs text-gray-400 mt-1">
                Sell all marketable items from selected accounts – sequential
                with delay
              </p>
            </div>
            <button
              onClick={handleClose}
              disabled={isProcessing}
              className="text-gray-400 hover:text-white disabled:opacity-50"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
            {/* LEFT – accounts */}
            <div className="w-full md:w-2/5 border-r border-gray-700 flex flex-col">
              <div className="p-4 border-b border-gray-700 space-y-3">
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
                  <input
                    type="text"
                    placeholder="Search accounts..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-amber-500"
                    disabled={isProcessing}
                  />
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={selectAllFiltered}
                    disabled={isProcessing || selectableAccounts.length === 0}
                    className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50 cursor-pointer"
                  >
                    <CheckSquare className="w-3 h-3" /> Select all
                  </button>
                  <button
                    onClick={deselectAllFiltered}
                    disabled={isProcessing || filteredAccounts.length === 0}
                    className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50 cursor-pointer"
                  >
                    <SquareIcon className="w-3 h-3" /> Deselect all
                  </button>
                </div>
                <div className="mb-3 p-2 bg-amber-900/20 rounded-lg border border-amber-500/30">
                  <div className="text-xs text-gray-300">
                    Selected:{" "}
                    <span className="text-amber-400 font-semibold">
                      {selectedAccounts.size}
                    </span>{" "}
                    account(s)
                  </div>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto p-3 space-y-2">
                {filteredAccounts.length === 0 ? (
                  <div className="text-center text-gray-400 py-8 text-sm">
                    No accounts found
                  </div>
                ) : (
                  filteredAccounts.map((acc) => {
                    const isActive = acc.cookies === true;
                    const isChecked = selectedAccounts.has(acc.accountName);
                    const isLoggingIn = loggingInAccounts.has(acc.accountName);
                    return (
                      <div
                        key={acc.accountName}
                        className="flex flex-col gap-1 p-2 rounded-lg transition"
                      >
                        <div className="flex items-center gap-3">
                          <label
                            className={`flex items-center gap-3 flex-1 cursor-pointer ${!isActive ? "opacity-70" : ""}`}
                          >
                            <input
                              type="checkbox"
                              checked={isChecked}
                              onChange={() => toggleAccount(acc.accountName)}
                              disabled={isProcessing || !isActive}
                              className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-amber-500 focus:ring-amber-500 disabled:opacity-50 cursor-pointer"
                            />
                            <span className="text-sm font-medium text-white">
                              {acc.accountName}
                            </span>
                            <span className="text-xs text-gray-400 ml-auto">
                              {acc.activity?.mass_sell_items &&
                                "last Use: " +
                                  new Date(
                                    acc.activity.mass_sell_items,
                                  ).toLocaleDateString()}
                            </span>
                          </label>
                          {!isActive ? (
                            <button
                              onClick={() => handleManualLogin(acc.accountName)}
                              disabled={isProcessing || isLoggingIn}
                              className="flex items-center gap-1 px-2 py-1 text-xs rounded-md bg-amber-600/80 hover:bg-amber-500 text-white transition-colors disabled:opacity-50 cursor-pointer"
                            >
                              {isLoggingIn ? (
                                <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
                              ) : (
                                <LogIn className="w-3 h-3" />
                              )}
                              {isLoggingIn ? "Logging..." : "Login"}
                            </button>
                          ) : (
                            <span className="text-xs text-green-400 ml-auto">
                              online
                            </span>
                          )}
                        </div>
                        {/* Теги */}
                        <div className="flex flex-wrap gap-1 ml-7">
                          {acc.tags?.map((tag) => (
                            <TagChip key={tag.id} tag={tag} small />
                          ))}
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </div>

            {/* RIGHT – settings */}
            <div className="w-full md:w-3/5 flex flex-col">
              <div className="p-4 border-b border-gray-700 flex flex-wrap items-center gap-4">
                <div className="flex items-center gap-2">
                  <Gamepad2 className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-white">Game:</span>
                </div>
                <select
                  value={selectedGame.appId}
                  onChange={(e) => {
                    const preset = GAME_PRESETS.find(
                      (p) => p.appId === e.target.value,
                    );
                    if (preset) setSelectedGame(preset);
                  }}
                  disabled={isProcessing}
                  className="px-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white cursor-pointer"
                >
                  {GAME_PRESETS.map((preset) => (
                    <option key={preset.appId} value={preset.appId}>
                      {preset.label} ({preset.appId}/{preset.contextId})
                    </option>
                  ))}
                </select>
                <div className="flex items-center gap-2 ml-auto">
                  <Clock className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-white">Delay:</span>
                </div>
                <input
                  type="number"
                  min="0"
                  max="60"
                  step="0.5"
                  value={delaySeconds}
                  onChange={(e) =>
                    setDelaySeconds(parseFloat(e.target.value) || 0)
                  }
                  disabled={isProcessing}
                  className="w-20 px-2 py-1 bg-gray-800 border border-gray-600 rounded text-white text-sm"
                />
                <span className="text-xs text-gray-400">sec</span>
              </div>

              <div className="flex-1 overflow-y-auto p-3 space-y-2 font-mono text-xs">
                <div className="flex justify-between items-center mb-2">
                  <div className="flex items-center gap-2">
                    <Terminal className="w-4 h-4 text-gray-400" />
                    <span className="text-sm font-medium text-white">Logs</span>
                  </div>
                  <button
                    onClick={() => setLogs([])}
                    disabled={isProcessing}
                    className="text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded transition-colors disabled:opacity-50 cursor-pointer"
                  >
                    Clear
                  </button>
                </div>
                {logs.length === 0 ? (
                  <div className="text-center text-gray-500 py-8">
                    Logs will appear here...
                  </div>
                ) : (
                  logs.map((log) => (
                    <div
                      key={log.id}
                      className="border-l-2 border-gray-700 pl-2"
                    >
                      <div className="flex items-start gap-2 flex-wrap">
                        <span className="text-gray-500 shrink-0">
                          [{log.timestamp}]
                        </span>
                        <span
                          className={`${getStatusColor(log.status)} shrink-0`}
                        >
                          {getStatusIcon(log.status)}
                        </span>
                        <span className="text-gray-300 font-semibold shrink-0">
                          {log.accountName}:
                        </span>
                        <span className="text-gray-400 break-all">
                          {log.message}
                        </span>
                        {log.showConfirmButton && (
                          <button
                            onClick={() =>
                              openConfirmationsModal(log.accountName)
                            }
                            className="ml-auto px-2 py-0.5 bg-amber-600/80 hover:bg-amber-500 rounded text-xs text-white transition-colors flex items-center gap-1 cursor-pointer"
                          >
                            <CheckCircle className="w-3 h-3" />
                            Confirm
                          </button>
                        )}
                      </div>
                    </div>
                  ))
                )}
                <div ref={logsEndRef} />
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="p-5 border-t border-gray-700 flex justify-between gap-3">
            <button
              onClick={handleClose}
              disabled={isProcessing}
              className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm cursor-pointer"
            >
              Close
            </button>
            <div className="flex gap-3">
              {isProcessing && (
                <button
                  onClick={stopProcess}
                  disabled={stopRequestedRef.current}
                  className={`px-6 py-2 rounded-lg text-sm font-medium flex items-center gap-2 cursor-pointer ${
                    stopRequestedRef.current
                      ? "bg-gray-600 cursor-not-allowed opacity-70"
                      : "bg-red-600 hover:bg-red-700"
                  }`}
                >
                  <Square className="w-4 h-4" />
                  {stopRequestedRef.current ? "Stopping..." : "Stop"}
                </button>
              )}
              <button
                onClick={runSellAll}
                disabled={isProcessing || selectedAccounts.size === 0}
                className="px-6 py-2 bg-amber-600 hover:bg-amber-700 rounded-lg text-sm font-medium flex items-center gap-2 disabled:opacity-50 cursor-pointer"
              >
                <Play className="w-4 h-4" /> Sell All
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Модальное окно подтверждений */}
      {renderConfirmationsModal()}
    </>
  );
}
