// components/Market/SellItemModal.tsx
import { useState, useEffect } from "react";
import { Package, Tag, DollarSign } from "lucide-react";
import { Modal } from "../Modal";
import { SteamAccountInfo, SteamInventoryItem } from "../../types";
import { accountApi } from "../../services/api";

interface SellItemModalProps {
  isOpen: boolean;
  account: SteamAccountInfo | null;
  onClose: () => void;
  onSuccess: () => void;
}

export function SellItemModal({
  isOpen,
  account,
  onClose,
  onSuccess,
}: SellItemModalProps) {
  const [inventoryItems, setInventoryItems] = useState<SteamInventoryItem[]>(
    [],
  );
  const [loadingInventory, setLoadingInventory] = useState(false);
  const [selectedItems, setSelectedItems] = useState<
    Map<string, SteamInventoryItem>
  >(new Map());
  const [sellPrice, setSellPrice] = useState("");
  const [sellingItems, setSellingItems] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fetchingPrice, setFetchingPrice] = useState(false);

  // Состояния для прогресс-бара загрузки цен
  const [totalPriceItems, setTotalPriceItems] = useState(0);
  const [loadedPriceItems, setLoadedPriceItems] = useState(0);
  console.log(totalPriceItems, loadedPriceItems);
  const fetchInventory = async () => {
    if (!account?.cookies) return;
    setLoadingInventory(true);
    setError(null);
    try {
      const result = await accountApi.getInventory(
        account.accountName,
        "730",
        "2",
      );
      if (result.success && result.data) {
        const marketableItems = result.data.filter(
          (item: SteamInventoryItem) => item.marketable === true,
        );
        setInventoryItems(marketableItems);
      } else {
        setError(result.error || "Failed to load inventory");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setLoadingInventory(false);
    }
  };

  // Функция получения рекомендуемой цены для уникальных (appId, marketHashName) с прогрессом
  const fetchRecommendedPrice = async () => {
    if (!account || selectedItems.size === 0) return;

    // Собираем уникальные пары (appId, marketHashName)
    const uniqueKeys = new Map<
      string,
      { appId: string; marketHashName: string }
    >();
    for (const item of selectedItems.values()) {
      if (item.market_hash_name && item.appid) {
        const key = `${item.appid}_${item.market_hash_name}`;
        if (!uniqueKeys.has(key)) {
          uniqueKeys.set(key, {
            appId: item.appid.toString(),
            marketHashName: item.market_hash_name,
          });
        }
      }
    }
    if (uniqueKeys.size === 0) return;

    setFetchingPrice(true);
    setTotalPriceItems(uniqueKeys.size);
    setLoadedPriceItems(0);
    setError(null);

    const priceMap = new Map<string, number>();
    const promises = Array.from(uniqueKeys.values()).map(
      async ({ appId, marketHashName }) => {
        try {
          const result = await accountApi.getItemPrice(
            account.accountName,
            appId,
            marketHashName,
          );
          const price = result.data?.price ?? result.data;
          if (result.success && typeof price === "number") {
            priceMap.set(`${appId}_${marketHashName}`, price);
          }
          setLoadedPriceItems((prev) => prev + 1);
        } catch (err) {
          console.error(`Failed to fetch price for ${marketHashName}`, err);
        } finally {
        }
      },
    );

    await Promise.all(promises);

    // Находим минимальную цену среди всех загруженных
    let minPrice = Infinity;
    for (const price of priceMap.values()) {
      minPrice = Math.min(minPrice, price);
    }
    if (isFinite(minPrice)) {
      setSellPrice(minPrice.toFixed(2));
    } else {
      setError("Could not fetch recommended prices for selected items.");
    }
    setFetchingPrice(false);
  };

  const handleSellItems = async () => {
    if (!account || selectedItems.size === 0 || !sellPrice) return;

    setSellingItems(true);
    setError(null);

    const itemsToSell = Array.from(selectedItems.values()).map((item) => ({
      appId: item.appid.toString(),
      contextId: item.contextid,
      assetId: item.assetid,
      price: sellPrice,
    }));

    try {
      const result = await accountApi.createMarketListing(
        account.accountName,
        itemsToSell,
      );
      if (result.success) {
        onClose();
        setSelectedItems(new Map());
        setSellPrice("");
        onSuccess();
      } else {
        setError(result.error || "Failed to create listings");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setSellingItems(false);
    }
  };

  const toggleItemSelection = (item: SteamInventoryItem) => {
    setSelectedItems((prev) => {
      const newMap = new Map(prev);
      if (newMap.has(item.assetid)) {
        newMap.delete(item.assetid);
      } else {
        newMap.set(item.assetid, item);
      }
      return newMap;
    });
  };

  // Сброс при открытии/закрытии
  useEffect(() => {
    if (isOpen) {
      fetchInventory();
    } else {
      setSelectedItems(new Map());
      setSellPrice("");
      setError(null);
      setTotalPriceItems(0);
      setLoadedPriceItems(0);
    }
  }, [isOpen, account]);

  const resetModal = () => {
    setSelectedItems(new Map());
    setSellPrice("");
    setError(null);
    setTotalPriceItems(0);
    setLoadedPriceItems(0);
  };

  // Вычисляем процент загрузки
  const progressPercent =
    totalPriceItems > 0 ? (loadedPriceItems / totalPriceItems) * 100 : 0;

  return (
    <Modal
      isOpen={isOpen}
      onClose={() => {
        onClose();
        resetModal();
      }}
      title="Sell Items"
      icon={<Tag className="w-5 h-5 text-emerald-400" />}
      footer={
        <div className="flex justify-end gap-3">
          <button
            onClick={() => {
              onClose();
              resetModal();
            }}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm font-medium transition-colors"
          >
            Cancel
          </button>
          <button
            onClick={handleSellItems}
            disabled={
              selectedItems.size === 0 ||
              !sellPrice ||
              sellingItems ||
              fetchingPrice
            }
            className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
          >
            {sellingItems
              ? "Creating listings..."
              : `Sell (${selectedItems.size})`}
          </button>
        </div>
      }
      maxWidth="lg"
    >
      <div className="p-4 space-y-4">
        {/* Прогресс-бар загрузки цен */}
        {fetchingPrice && totalPriceItems > 0 && (
          <div className="bg-gray-800/50 rounded-lg p-3">
            <div className="flex justify-between text-sm text-gray-400 mb-2">
              <span>Loading recommended prices...</span>
              <span>
                {loadedPriceItems} / {totalPriceItems}
              </span>
            </div>
            <div className="w-full bg-gray-700 rounded-full h-2">
              <div
                className="bg-emerald-500 h-2 rounded-full transition-all duration-300"
                style={{ width: `${progressPercent}%` }}
              />
            </div>
          </div>
        )}

        {/* Поле ввода цены */}
        <div>
          <label className="block text-sm font-medium text-gray-300 mb-2">
            Price per item (in account currency)
          </label>
          <div className="relative">
            <DollarSign className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="number"
              step="0.01"
              value={sellPrice}
              onChange={(e) => setSellPrice(e.target.value)}
              placeholder="Enter price..."
              className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-emerald-500"
            />
          </div>
          {selectedItems.size > 0 && (
            <button
              onClick={fetchRecommendedPrice}
              disabled={fetchingPrice}
              className="mt-2 text-xs text-indigo-400 hover:text-indigo-300 transition-colors disabled:opacity-50"
            >
              {fetchingPrice
                ? "Fetching recommended price..."
                : "Get recommended price"}
            </button>
          )}
        </div>

        {/* Сетка предметов */}
        <div className="mt-4">
          <h3 className="text-sm font-medium text-gray-300 mb-3">
            Select items to sell ({inventoryItems.length} marketable items)
          </h3>

          {loadingInventory ? (
            <div className="flex flex-col items-center justify-center py-8">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-500 mx-auto mb-2"></div>
              <div className="text-gray-400 text-sm">Loading inventory...</div>
            </div>
          ) : inventoryItems.length === 0 ? (
            <div className="text-center py-8 text-gray-400">
              <Package size={32} className="mx-auto mb-2 opacity-50" />
              <p className="text-sm">No marketable items found in inventory</p>
            </div>
          ) : (
            <div className="grid grid-cols-2 gap-3 max-h-96 overflow-y-auto">
              {inventoryItems.map((item) => (
                <div
                  key={item.assetid}
                  onClick={() => toggleItemSelection(item)}
                  className={`flex items-center gap-3 p-3 rounded-lg cursor-pointer transition-colors ${
                    selectedItems.has(item.assetid)
                      ? "bg-emerald-500/20 border-2 border-emerald-500"
                      : "bg-gray-800/50 border-2 border-transparent hover:bg-gray-800"
                  }`}
                >
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-white truncate">
                      {item.market_hash_name || item.name}
                    </p>
                    <p className="text-xs text-gray-400">{item.type}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Информация о выбранных предметах */}
        {selectedItems.size > 0 && (
          <div className="p-3 bg-gray-800/60 rounded-lg">
            <p className="text-sm text-gray-300">
              Selected:{" "}
              <span className="text-emerald-400 font-medium">
                {selectedItems.size}
              </span>{" "}
              items
            </p>
            <p className="text-sm text-gray-300">
              Total price:{" "}
              <span className="text-emerald-400 font-medium">
                $
                {(parseFloat(sellPrice || "0") * selectedItems.size).toFixed(2)}
              </span>
            </p>
          </div>
        )}

        {error && (
          <div className="p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
            {error}
          </div>
        )}
      </div>
    </Modal>
  );
}
