import { AlertCircle, BanIcon, Plus } from "lucide-react";
import { SteamAccountInfo } from "../types";
import { SortHeader } from "./SortHeader";
import { BansSortField } from "../types/index";

interface BansTableProps {
  accounts: SteamAccountInfo[];
  sortField: BansSortField;
  sortOrder: "asc" | "desc";
  onSort: (field: BansSortField) => void;
}

export function BansTable({
  accounts,
  sortField,
  sortOrder,
  onSort,
}: BansTableProps) {
  return (
    <table className="w-full">
      <thead className="bg-secondary/50">
        <tr>
          <SortHeader
            label="Login"
            field="login"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="VAC Bans"
            field="vac"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Game Bans"
            field="game"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Community Bans"
            field="community"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Banned games"
            field="game_ids"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
          <SortHeader
            label="Total"
            field="total"
            sortField={sortField}
            sortOrder={sortOrder}
            onSort={onSort}
          />
        </tr>
      </thead>
      <tbody>
        {accounts.length > 0 ? (
          accounts.map((account) => {
            const totalBans =
              (account.bans.vac ? 1 : 0) +
              (account.bans.game ? 1 : 0) +
              (account.bans.community ? 1 : 0);
            return (
              <tr
                key={account.accountName}
                className="border-t border-border hover:bg-secondary/20 transition-colors"
              >
                <td className="p-3 text-sm font-medium">
                  {account.accountName}
                </td>
                <td className="p-3 text-sm ">
                  {account.bans.vac ? (
                    <Plus className="h-4 w-4 text-red-400" />
                  ) : (
                    "-"
                  )}
                </td>
                <td className="p-3 text-sm ">
                  {account.bans.game ? (
                    <Plus className="h-4 w-4 text-red-400" />
                  ) : (
                    "-"
                  )}
                </td>
                <td className="p-3 text-sm ">
                  {account.bans.community ? (
                    <Plus className="h-4 w-4 text-red-400" />
                  ) : (
                    "-"
                  )}
                </td>
                <td className="p-3 text-sm text-red-400">
                  {account.bans.appids.length > 0
                    ? account.bans.appids.join(", ")
                    : "-"}
                </td>
                <td className="p-3 text-sm font-bold text-red-400">
                  {totalBans}
                </td>
              </tr>
            );
          })
        ) : (
          <tr>
            <td colSpan={5} className="p-8 text-center text-muted-foreground">
              <AlertCircle className="h-8 w-8 mx-auto mb-2 opacity-30" />
              <p className="text-sm">No banned accounts found</p>
            </td>
          </tr>
        )}
      </tbody>
    </table>
  );
}
