// components/LoadingInitialization.tsx
import { useState, useEffect } from "react";

interface LoadingInitializationProps {
  isWsConnected?: boolean;
  isLoadingData?: boolean;
  proxyProgress?: {
    stage: string;
    current: number;
    total: number;
    working: number;
  } | null;
  accountsCount?: number; // сколько аккаунтов уже загружено
}

export function LoadingInitialization({
  isWsConnected = false,
  isLoadingData = false,
  proxyProgress = null,
  accountsCount = 0,
}: LoadingInitializationProps) {
  const isProxyCheckDone = proxyProgress?.stage === "done";
  const isProxyCheckStarted = proxyProgress && proxyProgress.total > 0;
  const proxyCheckedCount = proxyProgress?.current ?? 0;
  const proxyTotalCount = proxyProgress?.total ?? 0;
  const proxyWorkingCount = proxyProgress?.working ?? 0;
  const proxyProgressPercent =
    proxyTotalCount > 0 ? (proxyCheckedCount / proxyTotalCount) * 100 : 0;

  // Активный шаг (для точек)
  let activeStep = 0;
  if (isWsConnected) activeStep = 1;
  if (!isLoadingData && accountsCount > 0) activeStep = 2;
  if (isProxyCheckDone) activeStep = 3;

  return (
    <div className="fixed inset-0 z-50 bg-black/95 backdrop-blur-sm flex items-center justify-center">
      <div className="max-w-md w-full mx-4">
        <div className="bg-gray-900/80 rounded-2xl border border-gray-700 shadow-2xl p-8">
          {/* Логотип */}
          <div className="flex justify-center mb-6">
            <div className="relative">
              <div className="w-20 h-20 bg-gradient-to-br from-blue-600 to-purple-600 rounded-2xl flex items-center justify-center shadow-lg">
                <svg
                  className="w-10 h-10 text-white"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M13 10V3L4 14h7v7l9-11h-7z"
                  />
                </svg>
              </div>
              <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl blur opacity-30 animate-pulse"></div>
            </div>
          </div>

          <h2 className="text-2xl font-bold text-center text-white mb-2">
            Initializing Steam Farm
          </h2>
          <p className="text-center text-gray-400 text-sm mb-8">
            Please wait while we prepare your environment
          </p>

          {/* Индикатор прогресса (точки) */}
          <div className="flex justify-center gap-2 mb-8">
            {[0, 1, 2, 3].map((idx) => (
              <div
                key={idx}
                className={`h-2 rounded-full transition-all duration-500 ${
                  idx <= activeStep
                    ? "w-8 bg-gradient-to-r from-blue-500 to-purple-500"
                    : "w-2 bg-gray-600"
                }`}
              />
            ))}
          </div>

          {/* Список шагов */}
          <div className="space-y-4">
            {/* 1. WebSocket */}
            <div className="flex items-center gap-3">
              <div className="flex-shrink-0">
                {isWsConnected ? (
                  <div className="w-6 h-6 rounded-full bg-green-500/20 flex items-center justify-center">
                    <div className="w-2 h-2 rounded-full bg-green-500" />
                  </div>
                ) : (
                  <div className="w-6 h-6 rounded-full border-2 border-gray-500 border-t-blue-500 animate-spin" />
                )}
              </div>
              <div className="flex-1">
                <p className="text-gray-200 font-medium">
                  Connecting to the license server
                </p>
                <p className="text-gray-500 text-xs">
                  {isWsConnected ? "Connected successfully" : "Establishing..."}
                </p>
              </div>
              {isWsConnected && (
                <span className="text-green-400 text-xs">✓</span>
              )}
            </div>

            {/* 2. Загрузка аккаунтов */}
            <div className="flex items-center gap-3">
              <div className="flex-shrink-0">
                {accountsCount > 0 ? (
                  <div className="w-6 h-6 rounded-full bg-green-500/20 flex items-center justify-center">
                    <div className="w-2 h-2 rounded-full bg-green-500" />
                  </div>
                ) : isWsConnected ? (
                  <div className="w-6 h-6 rounded-full border-2 border-gray-500 border-t-blue-500 animate-spin" />
                ) : (
                  <div className="w-6 h-6 rounded-full bg-gray-800 border border-gray-600" />
                )}
              </div>
              <div className="flex-1">
                <p className="text-gray-200 font-medium">Loading accounts</p>
                <p className="text-gray-500 text-xs">
                  {accountsCount === 0
                    ? "Waiting for account data..."
                    : `Loaded ${accountsCount} account${accountsCount !== 1 ? "s" : ""}`}
                </p>
              </div>
              {accountsCount > 0 && (
                <span className="text-green-400 text-xs">✓</span>
              )}
            </div>

            {/* 3. Проверка прокси */}
            <div className="flex items-start gap-3">
              <div className="flex-shrink-0 mt-0.5">
                {isProxyCheckDone ? (
                  <div className="w-6 h-6 rounded-full bg-green-500/20 flex items-center justify-center">
                    <div className="w-2 h-2 rounded-full bg-green-500" />
                  </div>
                ) : isProxyCheckStarted ? (
                  <div className="w-6 h-6 rounded-full border-2 border-gray-500 border-t-blue-500 animate-spin" />
                ) : (
                  <div className="w-6 h-6 rounded-full bg-gray-800 border border-gray-600" />
                )}
              </div>
              <div className="flex-1">
                <p className="text-gray-200 font-medium">Proxy verification</p>
                <div className="text-gray-500 text-xs space-y-1">
                  {!isProxyCheckStarted && accountsCount === 0 && (
                    <p>Waiting for accounts...</p>
                  )}
                  {!isProxyCheckStarted &&
                    accountsCount > 0 &&
                    !proxyProgress && <p>Initializing proxy checker...</p>}
                  {isProxyCheckStarted && !isProxyCheckDone && (
                    <>
                      <p>
                        Checking: {proxyCheckedCount} / {proxyTotalCount}
                      </p>
                      <p className="text-green-400">
                        Working: {proxyWorkingCount}
                      </p>
                      <div className="w-full bg-gray-700 rounded-full h-1.5 mt-2">
                        <div
                          className="bg-gradient-to-r from-blue-500 to-purple-500 h-1.5 rounded-full transition-all duration-300"
                          style={{ width: `${proxyProgressPercent}%` }}
                        />
                      </div>
                    </>
                  )}
                  {isProxyCheckDone && (
                    <p className="text-green-400">
                      ✅ Completed: {proxyWorkingCount} of {proxyTotalCount}{" "}
                      proxies working
                    </p>
                  )}
                  {proxyTotalCount === 0 && isProxyCheckDone && (
                    <p className="text-yellow-400">⚠️ No proxies configured</p>
                  )}
                </div>
              </div>
              {isProxyCheckDone && (
                <span className="text-green-400 text-xs">✓</span>
              )}
            </div>
          </div>

          <div className="mt-8 text-center">
            <p className="text-gray-400 text-xs flex items-center justify-center gap-1">
              <span>Initialization in progress</span>
              <span className="animate-pulse">.</span>
              <span className="animate-pulse delay-150">.</span>
              <span className="animate-pulse delay-300">.</span>
            </p>
          </div>
        </div>
        <div className="text-center mt-4 text-gray-600 text-xs">
          Steam Farm Tool v2.0
        </div>
      </div>
    </div>
  );
}
