// components/Market/ListingsTab.tsx
import { useMemo } from "react";
import { Package, XCircle } from "lucide-react";
import { MarketListing } from "../../types";
import { LoadingSpinner } from "../LoadingSpinner";

interface ListingsTabProps {
  listings: MarketListing[];
  loading: boolean;
  searchQuery: string;
  processingId: string | null;
  setActivePage: (page: string) => void;
  onCancelListing: (listing: MarketListing) => void;
}

const formatPrice = (price: string | null) => {
  if (!price) return "N/A";
  return price;
};

export function ListingsTab({
  listings,
  loading,
  setActivePage,
  searchQuery,
  processingId,
  onCancelListing,
}: ListingsTabProps) {
  const filteredListings = useMemo(() => {
    if (!searchQuery.trim()) return listings;
    const query = searchQuery.toLowerCase();
    return listings.filter((listing) =>
      listing.title.toLowerCase().includes(query),
    );
  }, [listings, searchQuery]);

  if (loading) {
    return <LoadingSpinner message="Loading active listings..." />;
  }

  return (
    <div className="bg-gray-800/40 rounded-lg p-6">
      <h2 className="text-xl font-semibold mb-4">
        Active Sell Listings
        {searchQuery && (
          <span className="text-sm text-gray-400 ml-2">
            (filtered from {listings.length})
          </span>
        )}
      </h2>

      {filteredListings.length === 0 ? (
        <div className="text-center py-12 text-gray-400">
          <Package size={48} className="mx-auto mb-4 opacity-50" />
          <p>
            {searchQuery
              ? `No listings found matching "${searchQuery}"`
              : "No active listings"}
          </p>
          <p className="text-sm mt-2">
            {searchQuery
              ? "Try a different search term"
              : "Items you put up for sale will appear here"}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {filteredListings.map((listing) => (
            <div
              key={listing.listingid}
              className="flex items-center justify-between p-4 bg-gray-700/30 rounded-lg hover:bg-gray-700/50 transition-colors"
            >
              <div className="flex items-center gap-4 flex-1 min-w-0">
                {listing.image && (
                  <img
                    src={listing.image}
                    alt={listing.title}
                    className="w-12 h-12 rounded object-cover flex-shrink-0"
                    onError={(e) => (e.currentTarget.style.display = "none")}
                  />
                )}
                <div className="flex-1 min-w-0">
                  <h3 className="font-medium text-white truncate">
                    {listing.title}
                  </h3>
                  <div className="flex items-center gap-4 mt-1 text-xs text-gray-400 flex-wrap">
                    <span>{listing.game}</span>
                    <span>Listed: {listing.listed_date}</span>
                    <span
                      onClick={() =>
                        listing.status === "pending"
                          ? setActivePage("confirmations")
                          : null
                      }
                      className={`px-2 py-0.5 rounded ${
                        listing.status === "active"
                          ? "bg-green-500/20 text-green-400"
                          : "bg-yellow-500/20 text-yellow-400 hover:text-yellow-300 hover:bg-yellow-500/30 cursor-pointer"
                      }`}
                    >
                      {listing.status}
                    </span>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-4 flex-shrink-0">
                <div className="text-right">
                  <div className="text-lg font-semibold text-emerald-400">
                    {formatPrice(listing.sale_price)}
                  </div>
                  <div className="text-xs text-gray-400">
                    Receive: {formatPrice(listing.receive_amount)}
                  </div>
                </div>
                <button
                  onClick={() => onCancelListing(listing)}
                  disabled={processingId === listing.listingid}
                  className="p-2 rounded-lg bg-red-500/20 text-red-400 hover:bg-red-500/30 transition-colors disabled:opacity-50"
                  title="Cancel listing"
                >
                  {processingId === listing.listingid ? (
                    <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <XCircle size={18} />
                  )}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
