// components/AccountControlModal.tsx
import { useState, useMemo } from "react";
import {
  Search,
  Power,
  PowerOff,
  StopCircle,
  Globe,
  CheckSquare,
  Square,
  Users,
  RefreshCw,
  ChevronDown,
} from "lucide-react";
import { cn } from "../lib/utils";
import { SteamAccountInfo } from "../types";
import { accountApi } from "../services/api";
import { Modal } from "./Modal";

interface AccountControlModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: SteamAccountInfo[];
  onAccountStateChange?: (accountName: string, enabled: boolean) => void;
}

type AccountStatus = "online" | "offline" | "farm" | "logining";

const statusConfig: Record<
  AccountStatus,
  { label: string; color: string; bgColor: string; borderColor: string }
> = {
  online: {
    label: "Online",
    color: "text-emerald-400",
    bgColor: "bg-emerald-500/10",
    borderColor: "border-emerald-500/30",
  },
  offline: {
    label: "Offline",
    color: "text-gray-400",
    bgColor: "bg-gray-500/10",
    borderColor: "border-gray-500/30",
  },
  farm: {
    label: "Farming",
    color: "text-indigo-400",
    bgColor: "bg-indigo-500/10",
    borderColor: "border-indigo-500/30",
  },
  logining: {
    label: "Logging in...",
    color: "text-yellow-400",
    bgColor: "bg-yellow-500/10",
    borderColor: "border-yellow-500/30",
  },
};

const PAGE_SIZE = 10;

interface AccountCardProps {
  account: SteamAccountInfo;
  isSelected: boolean;
  isBatchLoading?: boolean;
  onToggleSelect: () => void;
  onTogglePower: () => void;
  onOpenBrowser: () => void;
  onStopFarming: () => void;
  isPowerLoading: boolean;
  isBrowserLoading: boolean;
}

const AccountCard = ({
  account,
  isSelected,
  isBatchLoading,
  onToggleSelect,
  onTogglePower,
  onOpenBrowser,
  onStopFarming,
  isPowerLoading,
  isBrowserLoading,
}: AccountCardProps) => {
  const isOnline = account.status === "online" || account.status === "farm";
  const isFarming = account.status === "farm";
  const hasCookie = account.cookies === true;
  const isLogining = account.status === "logining";

  return (
    <div
      className={cn(
        "group bg-gray-800/40 rounded-xl border transition-all duration-200",
        isSelected
          ? "border-emerald-500/60 ring-1 ring-emerald-500/30 bg-gray-800/60"
          : "border-gray-700 hover:border-gray-600",
        (isPowerLoading || isBatchLoading) && "opacity-70",
      )}
    >
      <div className="p-3 flex items-center gap-3">
        <button
          onClick={onToggleSelect}
          disabled={isBatchLoading || isLogining}
          className="text-gray-400 hover:text-emerald-400 transition-colors disabled:opacity-50"
        >
          {isSelected ? (
            <CheckSquare className="w-5 h-5 text-emerald-400" />
          ) : (
            <Square className="w-5 h-5" />
          )}
        </button>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <div
              className={cn(
                "w-2 h-2 rounded-full",
                statusConfig[account.status as AccountStatus]?.color ||
                  "text-gray-400",
              )}
            />
            <p className="text-sm font-medium text-white truncate">
              {account.accountName}
            </p>
          </div>
          {account.ipAddress && (
            <p className="text-xs text-gray-500 font-mono mt-0.5">
              {account.ipAddress}
            </p>
          )}
        </div>

        <div className="flex items-center gap-1.5">
          {hasCookie && (
            <button
              onClick={onOpenBrowser}
              disabled={isBrowserLoading || isLogining || isBatchLoading}
              className="p-1.5 rounded-lg bg-blue-500/10 text-blue-400 hover:bg-blue-500/20 disabled:opacity-50"
              title="Open browser"
            >
              {isBrowserLoading ? (
                <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
              ) : (
                <Globe size={16} />
              )}
            </button>
          )}

          <button
            onClick={onTogglePower}
            disabled={isPowerLoading || isLogining || isBatchLoading}
            className={cn(
              "p-1.5 rounded-lg transition-all",
              isOnline
                ? "bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20"
                : "bg-gray-700/50 text-gray-400 hover:bg-gray-700",
            )}
            title={isOnline ? "Disable account" : "Enable account"}
          >
            {isPowerLoading ? (
              <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
            ) : isOnline ? (
              <Power size={16} />
            ) : (
              <PowerOff size={16} />
            )}
          </button>

          {isFarming && (
            <button
              onClick={onStopFarming}
              disabled={isPowerLoading || isBatchLoading}
              className="p-1.5 rounded-lg bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-all"
              title="Stop farming"
            >
              <StopCircle size={16} />
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

interface PaginatedColumnProps {
  title: string;
  icon: React.ReactNode;
  accounts: SteamAccountInfo[];
  selectedAccounts: Set<string>;
  onToggleSelect: (accountName: string) => void;
  onTogglePower: (accountName: string) => void;
  onOpenBrowser: (accountName: string) => void;
  onStopFarming: (accountName: string) => void;
  loadingStates: Record<string, boolean>;
  browserLoadingStates: Record<string, boolean>;
  batchLoading?: boolean;
  colorClass: string;
  onSelectAll: () => void;
}

const PaginatedColumn = ({
  title,
  icon,
  accounts,
  selectedAccounts,
  onToggleSelect,
  onTogglePower,
  onOpenBrowser,
  onStopFarming,
  loadingStates,
  browserLoadingStates,
  batchLoading,
  colorClass,
  onSelectAll,
}: PaginatedColumnProps) => {
  const [visibleCount, setVisibleCount] = useState(PAGE_SIZE);
  const total = accounts.length;
  const hasMore = visibleCount < total;
  const visibleAccounts = accounts.slice(0, visibleCount);

  const loadMore = () => {
    setVisibleCount((prev) => Math.min(prev + PAGE_SIZE, total));
  };

  if (total === 0) return null;

  return (
    <div className="flex flex-col h-full bg-gray-900/50 rounded-xl border border-gray-800 overflow-hidden">
      <div
        className={cn(
          "px-4 py-3 border-b flex items-center justify-between",
          colorClass,
        )}
      >
        <div className="flex items-center gap-2">
          {icon}
          <h3 className="font-semibold text-sm">{title}</h3>
          <span className="text-xs bg-white/10 px-2 py-0.5 rounded-full">
            {total}
          </span>
        </div>
        <button
          onClick={onSelectAll}
          className="text-xs text-gray-400 hover:text-white transition-colors"
        >
          Select all
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-3 space-y-2 max-h-[70vh]">
        {visibleAccounts.map((account) => (
          <AccountCard
            key={account.accountName}
            account={account}
            isSelected={selectedAccounts.has(account.accountName)}
            isBatchLoading={batchLoading}
            onToggleSelect={() => onToggleSelect(account.accountName)}
            onTogglePower={() => onTogglePower(account.accountName)}
            onOpenBrowser={() => onOpenBrowser(account.accountName)}
            onStopFarming={() => onStopFarming(account.accountName)}
            isPowerLoading={!!loadingStates[account.accountName]}
            isBrowserLoading={!!browserLoadingStates[account.accountName]}
          />
        ))}

        {hasMore && (
          <button
            onClick={loadMore}
            className="w-full mt-2 py-2 text-center text-sm text-gray-400 hover:text-white bg-gray-800/50 rounded-lg transition-colors flex items-center justify-center gap-1"
          >
            <ChevronDown className="w-4 h-4" />
            Show {Math.min(PAGE_SIZE, total - visibleCount)} more
          </button>
        )}
      </div>
    </div>
  );
};

export function AccountControlModal({
  isOpen,
  onClose,
  accounts,
}: AccountControlModalProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedAccounts, setSelectedAccounts] = useState<Set<string>>(
    new Set(),
  );
  const [loadingStates, setLoadingStates] = useState<Record<string, boolean>>(
    {},
  );
  const [browserLoadingStates, setBrowserLoadingStates] = useState<
    Record<string, boolean>
  >({});
  const [batchActionLoading, setBatchActionLoading] = useState(false);
  const [batchProgress, setBatchProgress] = useState<{
    total: number;
    completed: number;
  } | null>(null);

  const groupedAccounts = useMemo(() => {
    const filtered = accounts.filter((acc) =>
      acc.accountName.toLowerCase().includes(searchQuery.toLowerCase()),
    );

    const needInit: SteamAccountInfo[] = [];
    const online: SteamAccountInfo[] = [];
    const offline: SteamAccountInfo[] = [];
    const farm: SteamAccountInfo[] = [];

    filtered.forEach((acc) => {
      if (!acc.steamid || acc.steamid === "") {
        needInit.push(acc);
      } else {
        switch (acc.status) {
          case "online":
            online.push(acc);
            break;
          case "offline":
            offline.push(acc);
            break;
          case "farm":
            farm.push(acc);
            break;
          default:
            offline.push(acc);
            break;
        }
      }
    });

    const sortByName = (arr: SteamAccountInfo[]) =>
      [...arr].sort((a, b) => a.accountName.localeCompare(b.accountName));
    return {
      needInit: sortByName(needInit),
      online: sortByName(online),
      offline: sortByName(offline),
      farm: sortByName(farm),
    };
  }, [accounts, searchQuery]);

  const totalFilteredCount =
    groupedAccounts.online.length +
    groupedAccounts.offline.length +
    groupedAccounts.farm.length +
    groupedAccounts.needInit.length;

  const getSelectedList = () => Array.from(selectedAccounts);

  // Функция для массовых операций с прогрессом (тип action изменён на Promise<any>)
  const executeBatch = async (
    action: (accounts: string[]) => Promise<any>,
    accountsList: string[],
    _actionName: string,
  ) => {
    if (accountsList.length === 0) return;
    setBatchActionLoading(true);
    setBatchProgress({ total: accountsList.length, completed: 0 });
    const chunkSize = 5;
    for (let i = 0; i < accountsList.length; i += chunkSize) {
      const chunk = accountsList.slice(i, i + chunkSize);
      await action(chunk);
      setBatchProgress((prev) =>
        prev ? { ...prev, completed: i + chunk.length } : null,
      );
    }
    setBatchActionLoading(false);
    setBatchProgress(null);
  };

  const handleBatchLogin = async () => {
    const toLogin = getSelectedList().filter((name) => {
      const acc = accounts.find((a) => a.accountName === name);
      return acc && (acc.status === "offline" || !acc.steamid);
    });
    if (toLogin.length === 0) return;
    await executeBatch(accountApi.login, toLogin, "login");
  };

  const handleBatchLogout = async () => {
    const toLogout = getSelectedList().filter((name) => {
      const acc = accounts.find((a) => a.accountName === name);
      return acc && (acc.status === "online" || acc.status === "farm");
    });
    if (toLogout.length === 0) return;
    await executeBatch(accountApi.logout, toLogout, "logout");
  };

  const handleBatchInitialize = async () => {
    const toInit = getSelectedList().filter((name) => {
      const acc = accounts.find((a) => a.accountName === name);
      return acc && (!acc.steamid || acc.steamid === "");
    });
    if (toInit.length === 0) return;
    await executeBatch(accountApi.login, toInit, "init");
  };

  const setLoading = (name: string, isLoading: boolean) =>
    setLoadingStates((prev) => ({ ...prev, [name]: isLoading }));
  const setBrowserLoading = (name: string, isLoading: boolean) =>
    setBrowserLoadingStates((prev) => ({ ...prev, [name]: isLoading }));

  const handleTogglePower = async (accountName: string) => {
    const account = accounts.find((a) => a.accountName === accountName);
    if (!account) return;
    const isOnline = account.status === "online" || account.status === "farm";
    setLoading(accountName, true);
    if (isOnline) {
      await accountApi.logout([accountName]);
    } else {
      await accountApi.login([accountName]);
    }
    setLoading(accountName, false);
  };

  const handleOpenBrowser = async (accountName: string) => {
    setBrowserLoading(accountName, true);
    await accountApi.openBrowser(accountName);
    setBrowserLoading(accountName, false);
  };

  const handleStopFarming = async (accountName: string) => {
    setLoading(accountName, true);
    await accountApi.stopFarming(accountName);
    setLoading(accountName, false);
  };

  const toggleSelectAccount = (accountName: string) => {
    setSelectedAccounts((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(accountName)) newSet.delete(accountName);
      else newSet.add(accountName);
      return newSet;
    });
  };

  const selectAllInColumn = (accs: SteamAccountInfo[]) => {
    setSelectedAccounts((prev) => {
      const newSet = new Set(prev);
      accs.forEach((a) => newSet.add(a.accountName));
      return newSet;
    });
  };

  const clearSelection = () => setSelectedAccounts(new Set());

  const footer = (
    <div className="flex justify-between items-center">
      <div className="flex gap-2">
        <button
          onClick={handleBatchLogin}
          disabled={selectedAccounts.size === 0 || batchActionLoading}
          className="px-3 py-1.5 bg-emerald-500/20 text-emerald-400 rounded-lg text-xs font-medium hover:bg-emerald-500/30 transition-colors disabled:opacity-50 flex items-center gap-1"
        >
          <Power size={14} />
          Enable selected
        </button>
        <button
          onClick={handleBatchLogout}
          disabled={selectedAccounts.size === 0 || batchActionLoading}
          className="px-3 py-1.5 bg-red-500/20 text-red-400 rounded-lg text-xs font-medium hover:bg-red-500/30 transition-colors disabled:opacity-50 flex items-center gap-1"
        >
          <PowerOff size={14} />
          Disable selected
        </button>
        <button
          onClick={clearSelection}
          disabled={selectedAccounts.size === 0 || batchActionLoading}
          className="px-3 py-1.5 bg-gray-700/50 text-gray-300 rounded-lg text-xs hover:bg-gray-700 transition-colors disabled:opacity-50"
        >
          Clear selection
        </button>
      </div>
      <div className="text-xs text-gray-400 flex items-center gap-2">
        {batchProgress && (
          <span className="text-emerald-400">
            {batchProgress.completed}/{batchProgress.total}
          </span>
        )}
        <span>Selected: {selectedAccounts.size}</span>
      </div>
    </div>
  );

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Account Control"
      icon={<Users className="w-5 h-5 text-emerald-400" />}
      footer={footer}
      maxWidth="6xl"
    >
      <div className="p-4 border-b border-gray-700">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            placeholder="Search by login..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-emerald-500"
          />
        </div>
        <div className="text-xs text-gray-400 mt-2">
          Found {totalFilteredCount} accounts
        </div>
      </div>

      <div className="p-4">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <PaginatedColumn
            title="Need Init"
            icon={<RefreshCw className="w-4 h-4 text-yellow-400" />}
            accounts={groupedAccounts.needInit}
            selectedAccounts={selectedAccounts}
            onToggleSelect={toggleSelectAccount}
            onTogglePower={handleTogglePower}
            onOpenBrowser={handleOpenBrowser}
            onStopFarming={handleStopFarming}
            loadingStates={loadingStates}
            browserLoadingStates={browserLoadingStates}
            batchLoading={batchActionLoading}
            colorClass="border-yellow-500/30 bg-yellow-500/5"
            onSelectAll={() => selectAllInColumn(groupedAccounts.needInit)}
          />
          <PaginatedColumn
            title="Offline"
            icon={<PowerOff className="w-4 h-4 text-gray-400" />}
            accounts={groupedAccounts.offline}
            selectedAccounts={selectedAccounts}
            onToggleSelect={toggleSelectAccount}
            onTogglePower={handleTogglePower}
            onOpenBrowser={handleOpenBrowser}
            onStopFarming={handleStopFarming}
            loadingStates={loadingStates}
            browserLoadingStates={browserLoadingStates}
            batchLoading={batchActionLoading}
            colorClass="border-gray-500/30 bg-gray-500/5"
            onSelectAll={() => selectAllInColumn(groupedAccounts.offline)}
          />
          <PaginatedColumn
            title="Online"
            icon={<Power className="w-4 h-4 text-emerald-400" />}
            accounts={groupedAccounts.online}
            selectedAccounts={selectedAccounts}
            onToggleSelect={toggleSelectAccount}
            onTogglePower={handleTogglePower}
            onOpenBrowser={handleOpenBrowser}
            onStopFarming={handleStopFarming}
            loadingStates={loadingStates}
            browserLoadingStates={browserLoadingStates}
            batchLoading={batchActionLoading}
            colorClass="border-emerald-500/30 bg-emerald-500/5"
            onSelectAll={() => selectAllInColumn(groupedAccounts.online)}
          />
          <PaginatedColumn
            title="Farming"
            icon={<StopCircle className="w-4 h-4 text-indigo-400" />}
            accounts={groupedAccounts.farm}
            selectedAccounts={selectedAccounts}
            onToggleSelect={toggleSelectAccount}
            onTogglePower={handleTogglePower}
            onOpenBrowser={handleOpenBrowser}
            onStopFarming={handleStopFarming}
            loadingStates={loadingStates}
            browserLoadingStates={browserLoadingStates}
            batchLoading={batchActionLoading}
            colorClass="border-indigo-500/30 bg-indigo-500/5"
            onSelectAll={() => selectAllInColumn(groupedAccounts.farm)}
          />
        </div>
        {totalFilteredCount === 0 && (
          <div className="text-center py-12 text-gray-400">
            No accounts match the search
          </div>
        )}
      </div>
    </Modal>
  );
}
