interface AuthenticationRequiredProps {
  text: string;
  handleLogin: () => Promise<void>;
  loggingIn: boolean;
  loginError: string | null;
}
export const AuthenticationRequired = ({
  text,
  handleLogin,
  loggingIn,
  loginError,
}: AuthenticationRequiredProps) => {
  return (
    <div className="flex items-center justify-center h-full">
      <div className="bg-gray-800/60 rounded-xl p-8 max-w-md text-center border border-gray-700 shadow-xl">
        <div className="text-amber-400 text-5xl mb-4">🔒</div>
        <h2 className="text-xl font-bold mb-2">Authentication Required</h2>
        <p className="text-gray-300 mb-6">{text}</p>
        <button
          onClick={handleLogin}
          disabled={loggingIn}
          className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-md font-medium transition-colors disabled:opacity-50 cursor-pointer"
        >
          {loggingIn ? "Logging in..." : "Login to Account"}
        </button>
        {loginError && (
          <div className="mt-4 p-2 bg-red-500/20 border border-red-500 rounded text-red-400 text-sm">
            {loginError}
          </div>
        )}
      </div>
    </div>
  );
};
