// pages/LogsPage.tsx
import { useState, useEffect, useRef } from "react";
import {
  Terminal,
  Search,
  Info,
  AlertTriangle,
  AlertCircle,
  CheckCircle,
  Play,
  Pause,
} from "lucide-react";

export interface LogEntry {
  id: string;
  timestamp: string;
  message: string;
  status: "ok" | "error" | "warning" | "info";
}

interface LogsPageProps {
  logs: LogEntry[];
}

export function LogsPage({ logs }: LogsPageProps) {
  const [filterStatus, setFilterStatus] = useState<string>("all");
  const [searchQuery, setSearchQuery] = useState("");
  const [autoScroll, setAutoScroll] = useState(true);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [userScrolled, setUserScrolled] = useState(false);

  // Автопрокрутка
  useEffect(() => {
    if (autoScroll && !userScrolled && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [logs, autoScroll, userScrolled]);

  const handleScroll = () => {
    if (!containerRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
    const isAtBottom = scrollHeight - scrollTop <= clientHeight + 50;
    setUserScrolled(!isAtBottom);
    if (isAtBottom) setAutoScroll(true);
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "ok":
        return <CheckCircle className="w-4 h-4 text-green-400" />;
      case "error":
        return <AlertCircle className="w-4 h-4 text-red-400" />;
      case "warning":
        return <AlertTriangle className="w-4 h-4 text-yellow-400" />;
      default:
        return <Info className="w-4 h-4 text-blue-400" />;
    }
  };

  const getStatusBg = (status: string) => {
    switch (status) {
      case "ok":
        return "bg-green-500/10 border-l-green-500";
      case "error":
        return "bg-red-500/10 border-l-red-500";
      case "warning":
        return "bg-yellow-500/10 border-l-yellow-500";
      default:
        return "bg-blue-500/10 border-l-blue-500";
    }
  };

  const filteredLogs = logs.filter((log) => {
    if (filterStatus !== "all" && log.status !== filterStatus) return false;
    if (
      searchQuery &&
      !log.message.toLowerCase().includes(searchQuery.toLowerCase())
    )
      return false;
    return true;
  });

  const stats = {
    total: logs.length,
    ok: logs.filter((l) => l.status === "ok").length,
    error: logs.filter((l) => l.status === "error").length,
    warning: logs.filter((l) => l.status === "warning").length,
    info: logs.filter((l) => l.status === "info").length,
  };

  return (
    <div className="h-full flex flex-col">
      {/* Заголовок + статистика в стиле градиентной карточки */}
      <div className="bg-gradient-to-r from-indigo-900/20 to-purple-900/20 rounded-2xl p-6 mb-6 backdrop-blur-sm border border-indigo-700/30">
        <div className="flex items-start justify-between flex-wrap gap-4">
          <div className="flex-1">
            <div className="flex items-center gap-2 mb-2">
              <Terminal className="w-5 h-5 text-indigo-400" />
              <h2 className="text-lg font-semibold text-white">System Logs</h2>
              <div className="ml-2 inline-flex items-center gap-1.5 px-2 py-0.5 rounded-full text-xs font-medium bg-gray-700/50 text-gray-300">
                <div className="w-1.5 h-1.5 rounded-full bg-indigo-400" />
                Live
              </div>
            </div>
            <p className="text-sm text-gray-300">
              Real‑time events from accounts and Steam operations
            </p>
          </div>
          <div className="flex items-center gap-3 text-xs">
            <div className="flex gap-2 bg-black/30 rounded-full px-3 py-1.5">
              <span className="text-gray-400">Total: {stats.total}</span>
              <span className="text-green-400">✓ {stats.ok}</span>
              <span className="text-yellow-400">⚠ {stats.warning}</span>
              <span className="text-red-400">✗ {stats.error}</span>
              <span className="text-blue-400">ℹ {stats.info}</span>
            </div>
          </div>
        </div>
      </div>

      {/* Панель фильтров и поиска — отдельный блок */}
      <div className="bg-gradient-to-r from-gray-900/60 to-gray-800/40 rounded-2xl p-4 mb-6 backdrop-blur-sm border border-gray-700">
        <div className="flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-1 bg-gray-800/60 rounded-lg p-1">
            {["all", "info", "ok", "warning", "error"].map((status) => (
              <button
                key={status}
                onClick={() => setFilterStatus(status)}
                className={`px-3 py-1.5 rounded-md text-sm font-medium transition-all ${
                  filterStatus === status
                    ? "bg-indigo-600 text-white shadow-md"
                    : "text-gray-300 hover:bg-gray-700"
                }`}
              >
                {status === "all"
                  ? "All"
                  : status === "ok"
                    ? "Success"
                    : status.charAt(0).toUpperCase() + status.slice(1)}
              </button>
            ))}
          </div>
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Search in logs..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-9 pr-3 py-2 bg-gray-800/60 border border-gray-600 rounded-xl text-sm text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
            />
          </div>
          <button
            onClick={() => setAutoScroll(!autoScroll)}
            className={`flex items-center gap-2 px-3 py-2 rounded-xl text-sm font-medium transition-all ${
              autoScroll
                ? "bg-indigo-600 text-white shadow-md"
                : "bg-gray-800/60 text-gray-300 hover:bg-gray-700"
            }`}
            title={autoScroll ? "Auto-scroll enabled" : "Auto-scroll disabled"}
          >
            {autoScroll ? (
              <Play className="w-4 h-4" />
            ) : (
              <Pause className="w-4 h-4" />
            )}
            <span className="hidden sm:inline">Auto-scroll</span>
          </button>
        </div>
      </div>

      {/* Контейнер с логами */}
      <div
        ref={containerRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto space-y-2 font-mono text-xs bg-gray-900/30 rounded-2xl p-4 border border-gray-700/50 backdrop-blur-sm"
      >
        {filteredLogs.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-500">
            <Terminal className="w-12 h-12 mb-2 opacity-30" />
            <p className="text-sm">No logs to display</p>
            <p className="text-xs">System events will appear here</p>
          </div>
        ) : (
          filteredLogs.map((log) => (
            <div
              key={log.id}
              className={`border-l-4 pl-3 py-2 rounded-r-xl transition-all hover:bg-gray-800/40 ${getStatusBg(log.status)}`}
            >
              <div className="flex items-start gap-3 flex-wrap">
                <span className="text-gray-400 shrink-0 text-[11px]">
                  [{log.timestamp}]
                </span>
                <div className="flex items-center gap-1 shrink-0">
                  {getStatusIcon(log.status)}
                </div>
                <span className="text-gray-200 break-all leading-relaxed">
                  {log.message}
                </span>
              </div>
            </div>
          ))
        )}
        <div ref={logsEndRef} />
      </div>
    </div>
  );
}
