/**
 * Форматирует дату обновления в человекочитаемый формат на английском
 * @param date - дата для форматирования
 * @returns строка вида "just now", "5 minutes ago", "2 hours ago", "3 days ago" и т.д.
 */
export function formatTimeAgo(date: Date | string | null | undefined): string {
  if (!date) return "never";

  const now = new Date();
  const updateTime = new Date(date);

  // Проверка на валидность даты
  if (isNaN(updateTime.getTime())) return "never";

  const diffMs = now.getTime() - updateTime.getTime();
  const diffSecs = Math.floor(diffMs / 1000);
  const diffMins = Math.floor(diffSecs / 60);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);
  const diffWeeks = Math.floor(diffDays / 7);
  const diffMonths = Math.floor(diffDays / 30);
  const diffYears = Math.floor(diffDays / 365);

  // Меньше минуты
  if (diffSecs < 10) return "just now";
  if (diffSecs < 60) return `${diffSecs} seconds ago`;

  // Минуты
  if (diffMins === 1) return "1 minute ago";
  if (diffMins < 60) return `${diffMins} minutes ago`;

  // Часы
  if (diffHours === 1) return "1 hour ago";
  if (diffHours < 24) return `${diffHours} hours ago`;

  // Дни
  if (diffDays === 1) return "1 day ago";
  if (diffDays < 7) return `${diffDays} days ago`;

  // Недели
  if (diffWeeks === 1) return "1 week ago";
  if (diffWeeks < 4) return `${diffWeeks} weeks ago`;

  // Месяцы
  if (diffMonths === 1) return "1 month ago";
  if (diffMonths < 12) return `${diffMonths} months ago`;

  // Годы
  if (diffYears === 1) return "1 year ago";
  return `${diffYears} years ago`;
}

/**
 * Альтернативная функция с более коротким форматом
 */
export function formatTimeAgoShort(
  date: Date | string | null | undefined,
): string {
  if (!date) return "never";

  const now = new Date();
  const updateTime = new Date(date);

  if (isNaN(updateTime.getTime())) return "never";

  const diffMs = now.getTime() - updateTime.getTime();
  const diffSecs = Math.floor(diffMs / 1000);
  const diffMins = Math.floor(diffSecs / 60);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);

  if (diffSecs < 60) return `${diffSecs}s ago`;
  if (diffMins < 60) return `${diffMins}m ago`;
  if (diffHours < 24) return `${diffHours}h ago`;
  if (diffDays < 7) return `${diffDays}d ago`;
  if (diffDays < 30) return `${Math.floor(diffDays / 7)}w ago`;
  if (diffDays < 365) return `${Math.floor(diffDays / 30)}mo ago`;
  return `${Math.floor(diffDays / 365)}y ago`;
}

/**
 * Функция для получения точного времени обновления
 */
export function getLastUpdatedTime(date: Date | string | null | undefined): {
  raw: Date | null;
  formatted: string;
  formattedShort: string;
  timestamp: number;
  isValid: boolean;
} {
  if (!date) {
    return {
      raw: null,
      formatted: "never",
      formattedShort: "never",
      timestamp: 0,
      isValid: false,
    };
  }

  const updateTime = new Date(date);
  const isValid = !isNaN(updateTime.getTime());

  return {
    raw: isValid ? updateTime : null,
    formatted: isValid ? formatTimeAgo(updateTime) : "never",
    formattedShort: isValid ? formatTimeAgoShort(updateTime) : "never",
    timestamp: isValid ? updateTime.getTime() : 0,
    isValid,
  };
}
