// components/AccountList/TOTPProgress.tsx
import { cn } from "../../lib/utils";

interface TOTPProgressProps {
  timeLeft: number;
  size?: number;
}

export function TOTPProgress({ timeLeft, size = 24 }: TOTPProgressProps) {
  const radius = size / 2;
  const circumference = 2 * Math.PI * radius;
  const progress = ((30 - timeLeft) / 30) * circumference;
  const strokeDashoffset = circumference - progress;

  return (
    <div className="relative inline-flex items-center justify-center">
      <svg width={size} height={size} className="transform -rotate-90">
        <circle
          cx={radius}
          cy={radius}
          r={radius - 1.5}
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
          className="text-indigo-400"
        />
        <circle
          cx={radius}
          cy={radius}
          r={radius - 1.5}
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeDasharray={circumference}
          strokeDashoffset={strokeDashoffset}
          className="text-emerald-400 transition-all duration-1000 ease-linear"
          strokeLinecap="round"
        />
      </svg>
      <span className="absolute text-[8px] font-mono font-bold text-emerald-400">
        {timeLeft}
      </span>
    </div>
  );
}
