// components/Activity/CollectItemsFromBotsModal.tsx
import { useState, useRef, useEffect } from "react";
import {
  Package,
  Link2,
  Terminal,
  X,
  Play,
  Square,
  Search,
  CheckSquare,
  Square as SquareIcon,
  LogIn,
  Clock,
} from "lucide-react";
import { SteamAccountInfo } from "@/types";
import { accountApi } from "@/services/api";

interface BotInfo {
  accountName: string;
  last_trade: string | null;
  trade_url?: string | null;
}

interface CollectItemsFromBotsModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: SteamAccountInfo[];
}

interface LogEntry {
  id: number;
  botName: string;
  timestamp: string;
  status: "pending" | "success" | "error";
  message: string;
  response?: any;
}

export function CollectItemsFromBotsModal({
  isOpen,
  onClose,
  accounts,
}: CollectItemsFromBotsModalProps) {
  const [bots, setBots] = useState<BotInfo[]>([]);
  const [loadingBots, setLoadingBots] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedBots, setSelectedBots] = useState<Set<string>>(new Set());
  const [targetAccountName, setTargetAccountName] = useState<string>("");
  const [tradeUrl, setTradeUrl] = useState("");
  const [delaySeconds, setDelaySeconds] = useState(2);
  const [isProcessing, setIsProcessing] = useState(false);
  const [shouldStop, setShouldStop] = useState(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const [loggingInAccounts, setLoggingInAccounts] = useState<Set<string>>(
    new Set(),
  );

  useEffect(() => {
    if (isOpen) {
      const fetchBots = async () => {
        setLoadingBots(true);
        try {
          const result = await accountApi.getBots();
          if (result.success && Array.isArray(result.data)) {
            setBots(result.data);
          } else {
            setBots([]);
          }
        } catch (err) {
          console.error(err);
          setBots([]);
        } finally {
          setLoadingBots(false);
        }
      };
      fetchBots();
    } else {
      setBots([]);
      setSelectedBots(new Set());
      setTargetAccountName("");
      setTradeUrl("");
      setLogs([]);
      setShouldStop(false);
    }
  }, [isOpen]);

  useEffect(() => {
    logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  const addLog = (
    botName: string,
    status: LogEntry["status"],
    message: string,
    response?: any,
  ) => {
    setLogs((prev) => [
      ...prev,
      {
        id: Date.now() + Math.random(),
        botName,
        timestamp: new Date().toLocaleTimeString(),
        status,
        message,
        response,
      },
    ]);
  };

  const filteredBots = bots.filter((bot) =>
    bot.accountName.toLowerCase().includes(searchTerm.toLowerCase()),
  );

  const toggleBot = (botName: string) => {
    if (isProcessing) return;
    const newSet = new Set(selectedBots);
    if (newSet.has(botName)) newSet.delete(botName);
    else newSet.add(botName);
    setSelectedBots(newSet);
  };

  const selectAll = () => {
    if (isProcessing) return;
    const newSet = new Set(selectedBots);
    filteredBots.forEach((bot) => newSet.add(bot.accountName));
    setSelectedBots(newSet);
  };

  const deselectAll = () => {
    if (isProcessing) return;
    const newSet = new Set(selectedBots);
    filteredBots.forEach((bot) => newSet.delete(bot.accountName));
    setSelectedBots(newSet);
  };

  const handleTargetAccountChange = (accName: string) => {
    setTargetAccountName(accName);
    const acc = accounts.find((a) => a.accountName === accName);
    if (acc?.profileData?.tradelink) {
      setTradeUrl(acc.profileData.tradelink);
    } else {
      setTradeUrl("");
    }
  };

  const handleManualLogin = async (accountName: string) => {
    if (isProcessing || loggingInAccounts.has(accountName)) return;
    setLoggingInAccounts((prev) => new Set(prev).add(accountName));
    addLog(accountName, "pending", "Manual login requested...");
    try {
      const result = await accountApi.login([accountName]);
      if (result?.success) {
        addLog(accountName, "success", "Manual login successful");
        addLog(
          accountName,
          "success",
          "You may need to refresh the modal to see changes.",
        );
      } else {
        addLog(
          accountName,
          "error",
          `Manual login failed: ${result?.error || "Unknown error"}`,
        );
      }
    } catch (err) {
      addLog(
        accountName,
        "error",
        `Manual login error: ${err instanceof Error ? err.message : String(err)}`,
      );
    } finally {
      setLoggingInAccounts((prev) => {
        const newSet = new Set(prev);
        newSet.delete(accountName);
        return newSet;
      });
    }
  };

  const handleCollect = async () => {
    if (selectedBots.size === 0) {
      addLog("System", "error", "No bots selected");
      return;
    }
    if (!targetAccountName) {
      addLog("System", "error", "Please select a target account");
      return;
    }
    if (!tradeUrl.trim()) {
      addLog("System", "error", "Please provide a valid trade URL");
      return;
    }

    setIsProcessing(true);
    setShouldStop(false);
    setLogs([]);

    const botsArray = Array.from(selectedBots);
    let successCount = 0;
    let errorCount = 0;

    for (let i = 0; i < botsArray.length; i++) {
      if (shouldStop) {
        addLog("System", "error", "Process interrupted by user");
        break;
      }

      const botName = botsArray[i];
      addLog(botName, "pending", `Sending items to ${targetAccountName}...`);

      try {
        const response = await accountApi.collectItemsFromBots({
          accountName: botName,
          tradeUrl: tradeUrl,
        });
        if (response.success) {
          addLog(
            botName,
            "success",
            `✅ Items sent successfully`,
            response.data,
          );
          successCount++;
        } else {
          addLog(botName, "error", `❌ Error: ${response.error}`, response);
          errorCount++;
        }
      } catch (err) {
        addLog(
          botName,
          "error",
          `❌ Exception: ${err instanceof Error ? err.message : "Unknown error"}`,
        );
        errorCount++;
      }

      if (i < botsArray.length - 1 && !shouldStop) {
        await new Promise((resolve) =>
          setTimeout(resolve, delaySeconds * 1000),
        );
      }
    }

    addLog(
      "System",
      successCount > 0 && errorCount === 0 ? "success" : "error",
      `Finished. Success: ${successCount}, Errors: ${errorCount}`,
    );
    setIsProcessing(false);
  };

  const stopProcess = () => {
    if (isProcessing) setShouldStop(true);
  };

  const handleClose = () => {
    if (isProcessing) {
      if (confirm("Process is running. Are you sure you want to close?")) {
        setShouldStop(true);
        onClose();
      }
    } else {
      onClose();
    }
  };

  const getStatusColor = (status: LogEntry["status"]) => {
    switch (status) {
      case "success":
        return "text-green-400";
      case "error":
        return "text-red-400";
      case "pending":
        return "text-yellow-400";
      default:
        return "text-gray-400";
    }
  };

  const getStatusIcon = (status: LogEntry["status"]) => {
    switch (status) {
      case "success":
        return "✅";
      case "error":
        return "❌";
      case "pending":
        return "⏳";
      default:
        return "📝";
    }
  };

  const formatLastTrade = (dateStr: string | null) => {
    if (!dateStr) return "Never";
    try {
      return new Date(dateStr).toLocaleString();
    } catch {
      return "Invalid date";
    }
  };

  if (!isOpen) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm"
      onClick={(e) =>
        e.target === e.currentTarget && !isProcessing && handleClose()
      }
    >
      <div className="bg-gray-900 rounded-2xl shadow-2xl w-full max-w-6xl max-h-[90vh] flex flex-col overflow-hidden border border-gray-700">
        {/* Header */}
        <div className="flex justify-between items-center p-5 border-b border-gray-700">
          <div>
            <h2 className="text-xl font-semibold text-white flex items-center gap-2">
              <Package className="w-5 h-5 text-emerald-400" />
              Collect Items from Bots
            </h2>
            <p className="text-xs text-gray-400 mt-1">
              Send entire inventory from selected bots to a target account
            </p>
          </div>
          <button
            onClick={handleClose}
            disabled={isProcessing}
            className="text-gray-400 hover:text-white disabled:opacity-50"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row">
          {/* LEFT COLUMN – bots list */}
          <div className="w-full md:w-2/5 border-r border-gray-700 flex flex-col">
            <div className="p-4 border-b border-gray-700 space-y-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search bots..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-600 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-emerald-500"
                  disabled={isProcessing}
                />
              </div>
              <div className="flex gap-2">
                <button
                  onClick={selectAll}
                  disabled={isProcessing || filteredBots.length === 0}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50"
                >
                  <CheckSquare className="w-3 h-3" /> Select all
                </button>
                <button
                  onClick={deselectAll}
                  disabled={isProcessing || filteredBots.length === 0}
                  className="flex items-center gap-1 text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded disabled:opacity-50"
                >
                  <SquareIcon className="w-3 h-3" /> Deselect all
                </button>
              </div>
              <div className="mb-3 p-2 bg-emerald-900/20 rounded-lg border border-emerald-500/30">
                <div className="text-xs text-gray-300">
                  Selected bots:{" "}
                  <span className="text-emerald-400 font-semibold">
                    {selectedBots.size}
                  </span>
                </div>
              </div>
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-2">
              {loadingBots ? (
                <div className="text-center text-gray-400 py-8 text-sm">
                  Loading bots...
                </div>
              ) : filteredBots.length === 0 ? (
                <div className="text-center text-gray-400 py-8 text-sm">
                  No bots found
                </div>
              ) : (
                filteredBots.map((bot) => {
                  const isChecked = selectedBots.has(bot.accountName);

                  const isActive = true;
                  return (
                    <div
                      key={bot.accountName}
                      className="flex items-center gap-3 p-2 rounded-lg transition"
                    >
                      <label className="flex items-center gap-3 flex-1 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={isChecked}
                          onChange={() => toggleBot(bot.accountName)}
                          disabled={isProcessing}
                          className="w-4 h-4 rounded bg-gray-700 border-gray-600 text-emerald-500 focus:ring-emerald-500 disabled:opacity-50"
                        />
                        <span className="text-sm font-medium text-white">
                          {bot.accountName}
                        </span>
                      </label>
                    </div>
                  );
                })
              )}
            </div>
          </div>

          {/* RIGHT COLUMN – settings & logs */}
          <div className="w-full md:w-3/5 flex flex-col">
            <div className="flex-1 overflow-y-auto p-5 space-y-5">
              {/* Target account */}
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Target Account (receiver)
                </label>
                <select
                  value={targetAccountName}
                  onChange={(e) => handleTargetAccountChange(e.target.value)}
                  disabled={isProcessing}
                  className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
                >
                  <option value="">-- Select an account --</option>
                  {accounts.map((acc) => (
                    <option key={acc.accountName} value={acc.accountName}>
                      {acc.accountName}
                    </option>
                  ))}
                </select>
              </div>

              {/* Trade URL */}
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Trade Offer URL
                </label>
                <div className="relative">
                  <Link2 className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" />
                  <input
                    type="text"
                    value={tradeUrl}
                    onChange={(e) => setTradeUrl(e.target.value)}
                    placeholder="https://steamcommunity.com/tradeoffer/new/?partner=..."
                    className="w-full pl-9 pr-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-sm text-white placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-emerald-500"
                    disabled={isProcessing}
                  />
                </div>
              </div>

              {/* Delay */}
              <div className="flex items-center gap-4 flex-wrap">
                <div className="flex items-center gap-2">
                  <Clock className="w-4 h-4 text-gray-400" />
                  <span className="text-sm text-white">
                    Delay between accounts:
                  </span>
                </div>
                <input
                  type="number"
                  min="0"
                  max="60"
                  step="0.5"
                  value={delaySeconds}
                  onChange={(e) =>
                    setDelaySeconds(parseFloat(e.target.value) || 0)
                  }
                  disabled={isProcessing}
                  className="w-20 px-2 py-1 bg-gray-800 border border-gray-600 rounded text-white text-sm"
                />
                <span className="text-xs text-gray-400">sec</span>
              </div>

              {/* Logs */}
              <div className="bg-gray-800/40 rounded-lg p-3">
                <div className="flex items-center gap-2 mb-2">
                  <Terminal className="w-4 h-4 text-gray-400" />
                  <span className="text-sm font-medium text-white">Logs</span>
                  <button
                    onClick={() => setLogs([])}
                    disabled={isProcessing}
                    className="ml-auto text-xs px-2 py-1 bg-gray-700 hover:bg-gray-600 rounded transition-colors disabled:opacity-50"
                  >
                    Clear
                  </button>
                </div>
                <div className="space-y-1 font-mono text-xs max-h-64 overflow-y-auto">
                  {logs.length === 0 ? (
                    <div className="text-center text-gray-500 py-4">
                      Logs will appear here...
                    </div>
                  ) : (
                    logs.map((log) => (
                      <div
                        key={log.id}
                        className="border-l-2 border-gray-700 pl-2"
                      >
                        <div className="flex items-start gap-2 flex-wrap">
                          <span className="text-gray-500 shrink-0">
                            [{log.timestamp}]
                          </span>
                          <span
                            className={`${getStatusColor(log.status)} shrink-0`}
                          >
                            {getStatusIcon(log.status)}
                          </span>
                          <span className="text-gray-300 font-semibold shrink-0">
                            {log.botName}:
                          </span>
                          <span className="text-gray-400 break-all">
                            {log.message}
                          </span>
                        </div>
                      </div>
                    ))
                  )}
                  <div ref={logsEndRef} />
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-5 border-t border-gray-700 flex justify-between gap-3">
          <button
            onClick={handleClose}
            disabled={isProcessing}
            className="px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded-lg text-sm transition-colors disabled:opacity-50"
          >
            Close
          </button>
          <div className="flex gap-3">
            {isProcessing && (
              <button
                onClick={stopProcess}
                className="px-6 py-2 bg-red-600 hover:bg-red-700 rounded-lg text-sm font-medium flex items-center gap-2"
              >
                <Square className="w-4 h-4" /> Stop
              </button>
            )}
            <button
              onClick={handleCollect}
              disabled={
                isProcessing ||
                selectedBots.size === 0 ||
                !targetAccountName ||
                !tradeUrl.trim()
              }
              className="px-6 py-2 bg-emerald-600 hover:bg-emerald-700 rounded-lg text-sm font-medium flex items-center gap-2 disabled:opacity-50"
            >
              <Package className="w-4 h-4" /> Collect Items
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
