// Layout.tsx
import { useState, useEffect, useRef, useCallback } from "react";
import { Sidebar } from "./Sidebar";
import { AccountSearch } from "./AccountSearch";
import { AccountList } from "./AccountList/AccountList.tsx";
import {
  MainPage,
  ActivityPage,
  MarketPage,
  InventoryPage,
  TradePage,
  ConfirmationsPage,
} from "../pages";
import { ProxyProgress, SteamAccountInfo, WebSocketMessage } from "../types.ts";
import { ProfilePage } from "@/pages/ProfilePage.tsx";
import { LoadingInitialization } from "./LoadingInitialization.tsx";
import { LogEntry, LogsPage } from "@/pages/LogsPage.tsx";

export function Layout() {
  const [activePage, setActivePage] = useState("main");
  const [searchQuery, setSearchQuery] = useState("");
  const [accounts, setAccounts] = useState<SteamAccountInfo[]>([]);
  const [selectedAccount, setSelectedAccount] =
    useState<SteamAccountInfo | null>(null);
  const [isWsConnected, setIsWsConnected] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(true);
  const [proxyProgress, setProxyProgress] = useState<ProxyProgress | null>(
    null,
  );
  const [logs, setLogs] = useState<LogEntry[]>([]);
  // Refs для предотвращения переподключения
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(
    null,
  );
  const selectedAccountRef = useRef(selectedAccount);

  // Обновляем ref при изменении selectedAccount
  useEffect(() => {
    selectedAccountRef.current = selectedAccount;
  }, [selectedAccount]);

  const openConfirmations = (account: SteamAccountInfo) => {
    setSelectedAccount(account);
    setActivePage("confirmations");
  };

  const normalizeAccountData = (account: any): SteamAccountInfo => {
    // Нормализуем profileData
    const profileData = {
      name: account.profileData?.name ?? "",
      avatar: account.avatar ?? account.profileData?.avatar ?? "",
      state: account.state ?? account.profileData?.state ?? null,
      city:
        account.city !== undefined
          ? account.city
          : (account.profileData?.city ?? null),
      level: account.level ?? account.profileData?.level ?? 0,
      profileUrl: account.profileUrl ?? account.profileData?.profileUrl ?? null,
      country: account.country ?? account.profileData?.country ?? null,
      realName: account.realName ?? account.profileData?.realName ?? null,
      summary: account.summary ?? account.profileData?.summary ?? null,
      tradelink: account.tradelink ?? account.profileData?.tradelink ?? null,
      memberSince: account.memberSince
        ? new Date(account.memberSince)
        : account.profileData?.memberSince
          ? new Date(account.profileData.memberSince)
          : new Date(),
      playingAppIds:
        account.playingAppIds ?? account.profileData?.playingAppIds ?? null,
      privacyState:
        account.privacyState ?? account.profileData?.privacyState ?? "",
      groups: account.groups ?? account.profileData?.groups ?? 0,
      visibilityState:
        account.visibilityState ?? account.profileData?.visibilityState ?? null,
    };

    // Баланс (может быть null)
    let balance = null;
    if (account.balance) {
      balance = {
        value: account.balance.value ?? 0,
        currency: account.balance.currency ?? 0,
        formattedBalance: account.balance.formattedBalance ?? "0",
        usdbalance: parseFloat(account.balance.usdbalance) ?? 0,
        lastUpdated: account.balance.lastUpdated
          ? new Date(account.balance.lastUpdated)
          : new Date(),
      };
    } else if (!account.hasWallet) {
      // Если hasWallet true, но баланс отсутствует, создаём пустой
      balance = {
        value: 0,
        currency: 0,
        formattedBalance: "0",
        usdbalance: 0,
        lastUpdated: new Date(),
      };
    }
    const market = {
      open: account.market?.open ?? false,
      canOpenByPurchase: account.market?.canOpenByPurchase ?? null,
      willOpen: account.market?.willOpen ?? null,
    };
    // Баны (поле gameids преобразуем в appids)
    const bans = {
      vac: account.bans?.vac ?? false,
      game: account.bans?.game ?? false,
      appids: account.bans?.appids ?? account.bans?.gameids ?? [],
      community: account.bans?.community ?? false,
      kt: account.bans?.kt ?? false,
      lastUpdated: account.bans?.lastUpdated
        ? new Date(account.bans.lastUpdated)
        : new Date(),
    };

    // Подтверждения
    const confirmations = {
      trade: account.confirmations?.trade ?? false,
      market: account.confirmations?.market ?? false,
      system: account.confirmations?.system ?? false,
      acceptGiftTrade: account.confirmations?.acceptGiftTrade ?? false,
    };
    const activity = {
      farming_activity: account?.activity?.farming_activity ?? null,
      add_free_games: account?.activity?.add_free_games ?? null,
      create_badge: account?.activity?.create_badge ?? null,
      profile_background: account?.activity?.profile_background ?? null,
      activate_vouchers: account?.activity?.activate_vouchers ?? null,
      send_random_trades: account?.activity?.send_random_trades ?? null,
      collect_items: account?.activity?.collect_items ?? null,
      mass_sell_items: account?.activity?.mass_sell_items ?? null,
      buy_cs2: account?.activity?.buy_cs2 ?? null,
      marketplace_unlock: account?.activity?.marketplace_unlock ?? null,
    };
    const refreshToken = account?.refreshToken ?? false;
    return {
      tags: account.tags,
      steamid: account.steamid ?? "",
      accountName: account.accountName ?? "",
      market,
      activity,
      password: account.password ?? "",
      sharedSecret: account.sharedSecret ?? account.shared_secret ?? "",
      accountid: account.accountid ?? 0,
      status: account.status ?? "offline",
      email: account.email ?? "",
      profileData,
      refreshToken: refreshToken ?? false,
      emailValidated: account.emailValidated ?? false,
      ipAddress: account.ipAddress ?? "",
      limited: Boolean(account.limited) ?? false,
      hasWallet: Boolean(account.hasWallet) ?? false,
      balance,
      bans,
      activeOrders: account.activeOrders ?? null,
      activeListings: account.activeListings ?? null,
      ownedGames: Array.isArray(account.ownedGames) ? account.ownedGames : [],
      cookies: account.cookies ?? false,
      identity_secret: account.identity_secret ?? false,
      confirmations,
    };
  };

  // Функция подключения — теперь без зависимостей (стабильна)
  const connectWebSocket = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      return;
    }

    const ws = new WebSocket("ws://127.0.0.1:4200/ws");

    ws.onopen = () => {
      console.log("WebSocket connected");
      setIsWsConnected(true);
      setIsLoadingData(true);

      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
        reconnectTimeoutRef.current = null;
      }
    };

    ws.onmessage = (event) => {
      try {
        let data: WebSocketMessage;
        if (typeof event.data === "string") {
          data = JSON.parse(event.data);
        } else {
          data = event.data;
        }
        if (data.type === "log" && data.data) {
          const logData = data.data as unknown as LogEntry;
          const newLog: LogEntry = {
            id: `${logData.timestamp}-${Math.random()}`,
            timestamp: logData.timestamp,
            message: logData.message,
            status: logData.status,
          };
          setLogs((prev) => [...prev, newLog]);
        }
        if (data.type === "proxy_progress") {
          const progress = data as unknown as {
            stage: string;
            current: number;
            total: number;
            working: number;
          };

          setProxyProgress({
            stage: progress.stage,
            current: progress.current,
            total: progress.total,
            working: progress.working,
          });
          return;
        }
        if (data.type === "accounts" && Array.isArray(data.data)) {
          const validAccounts = data.data
            .filter((account) => account && account.accountName)
            .sort((a, b) => {
              const statusOrder = {
                logining: 1,
                online: 2,
                farm: 3,
                offline: 4,
              };

              return (
                (statusOrder[a.status] || 4) - (statusOrder[b.status] || 4)
              );
            })
            .map((account) => normalizeAccountData(account));

          setAccounts(validAccounts);

          setSelectedAccount((prev) => {
            if (validAccounts.length > 0 && !prev) {
              return validAccounts[0];
            }
            return prev;
          });

          setIsLoadingData(false);
        } else if (
          data.type === "accountUpdate" &&
          data.data &&
          data.accountName
        ) {
          const updatedAccount = normalizeAccountData(data.data);

          setAccounts((prev) =>
            prev
              .map((acc) =>
                acc.accountName === data.accountName ? updatedAccount : acc,
              )
              .sort((a, b) => {
                const statusOrder = {
                  logining: 1,
                  online: 2,
                  farm: 3,
                  offline: 4,
                };

                return (
                  (statusOrder[a.status] || 4) - (statusOrder[b.status] || 4)
                );
              }),
          );

          // Используем ref для получения текущего selectedAccount
          if (selectedAccountRef.current?.accountName === data.accountName) {
            setSelectedAccount(updatedAccount);
          }
        }
      } catch (err) {
        console.error("Error parsing WebSocket message:", err);
        setIsLoadingData(false);
      }
    };

    ws.onclose = () => {
      console.log("WebSocket disconnected");
      setIsWsConnected(false);
      setIsLoadingData(true);

      reconnectTimeoutRef.current = setTimeout(() => {
        console.log("Attempting to reconnect...");
        connectWebSocket();
      }, 3000);
    };

    ws.onerror = (error) => {
      console.error("WebSocket error:", error);
    };

    wsRef.current = ws;
  }, []);

  // Эффект для подключения при монтировании
  useEffect(() => {
    connectWebSocket();

    return () => {
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
      if (wsRef.current) {
        wsRef.current.close();
        wsRef.current = null;
      }
    };
  }, [connectWebSocket]);

  const filteredAccounts = accounts
    .filter((account) => {
      if (!account || !account.accountName) return false;
      return account.accountName
        .toLowerCase()
        .includes(searchQuery.toLowerCase());
    })
    .sort((a, b) => {
      if (a.cookies && !b.cookies) return -1;
      if (!a.cookies && b.cookies) return 1;
      return 0;
    });
  const openProfile = (account: SteamAccountInfo) => {
    setSelectedAccount(account);
    setActivePage("profile");
  };
  const handleUpdateAccount = (updatedAccount: SteamAccountInfo) => {
    setAccounts((prev) =>
      prev.map((acc) =>
        acc.accountName === updatedAccount.accountName ? updatedAccount : acc,
      ),
    );
    if (selectedAccount?.accountName === updatedAccount.accountName) {
      setSelectedAccount(updatedAccount);
    }
  };

  const renderPage = () => {
    switch (activePage) {
      case "main":
        return <MainPage accounts={accounts} />;
      case "activity":
        return <ActivityPage accounts={accounts} />;
      case "logs":
        return <LogsPage logs={logs} />;
      case "market":
        return (
          <MarketPage
            account={selectedAccount as any}
            onUpdateAccount={handleUpdateAccount}
            setActivePage={setActivePage}
          />
        );
      case "inventory":
        return (
          <InventoryPage
            account={selectedAccount as any}
            accounts={accounts}
            onUpdateAccount={handleUpdateAccount}
          />
        );
      case "trade":
        return <TradePage account={selectedAccount as any} />;
      case "confirmations":
        return (
          <ConfirmationsPage
            account={selectedAccount}
            onUpdateAccount={handleUpdateAccount}
          />
        );
      case "profile":
        return (
          <ProfilePage
            account={selectedAccount}
            onUpdateAccount={handleUpdateAccount}
          />
        );
      default:
        return <MainPage accounts={accounts} />;
    }
  };

  const isProxyCheckDone = proxyProgress?.stage === "done";
  // Показываем загрузку, если нет аккаунтов ИЛИ проверка прокси не завершена
  const showLoading = accounts.length === 0 || !isProxyCheckDone;

  if (showLoading) {
    return (
      <LoadingInitialization
        isWsConnected={isWsConnected}
        isLoadingData={isLoadingData}
        proxyProgress={proxyProgress}
        accountsCount={accounts.length}
      />
    );
  }

  return (
    <div className="flex h-screen bg-gradient-to-br text-gray-200 from-gray-900 via-gray-900 to-gray-900">
      <Sidebar
        activePage={activePage}
        onPageChange={setActivePage}
        accounts={accounts}
      />

      <div className="flex-1 flex overflow-hidden">
        {activePage !== "activity" && activePage !== "logs" && (
          <div className="w-90 bg-gray-800/40 backdrop-blur-sm border-r border-gray-700 flex flex-col">
            <div className="p-[9px] border-b border-gray-700">
              <AccountSearch value={searchQuery} onChange={setSearchQuery} />
            </div>

            <AccountList
              activePage={activePage}
              accounts={filteredAccounts}
              selectedAccount={selectedAccount}
              onSelectAccount={setSelectedAccount}
              onOpenConfirmations={openConfirmations}
              onOpenProfile={openProfile}
              onUpdateAccount={handleUpdateAccount}
            />
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-6">
          {isLoadingData && accounts.length > 0 ? (
            <div className="flex items-center justify-center h-full">
              <div className="text-center">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-purple-500 mx-auto mb-4"></div>
                <div className="text-gray-400">Loading account details...</div>
              </div>
            </div>
          ) : (
            renderPage()
          )}
        </div>
      </div>

      <div className="fixed bottom-4 right-4 flex items-center gap-2">
        <div
          className={`w-2 h-2 rounded-full ${isWsConnected ? "bg-green-500" : "bg-red-500"}`}
        />
        <span className="text-xs text-gray-400">
          {isWsConnected
            ? isLoadingData
              ? "Loading..."
              : "Connected"
            : "Disconnected"}
        </span>
      </div>
    </div>
  );
}
